-- Poems batch 234
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('06fc33d1-369d-4bc7-949b-007b96a307be','橫翠亭書懷','釋紹嵩','宋','宋诗','song-poetry','','[]','小葺茅茨紫翠間，門當宮道不曾關。',64,'全唐诗/poet.song.213000.json','["小葺茅茨紫翠間，門當宮道不曾關。", "剪裁風月聊堪醉，奔走塵寰出老顔。", "半局殘棋消白晝，十年歸夢滿青山。", "江城今可徘徊處，莫怪頻頻此往還。"]'),
('29979414-7aff-4bbd-862c-afcbc76ef0ed','安吉道中','釋紹嵩','宋','宋诗','song-poetry','','[]','六尺枯藤了此生，青春作伴日同行。',64,'全唐诗/poet.song.213000.json','["六尺枯藤了此生，青春作伴日同行。", "牆頭花吐舊枝出，原上人侵落照耕。", "芳草似袍連徑合，亂山如畫带溪平。", "杜鵑知我歸心急，啼了千聲更萬聲。"]'),
('33e05432-b4af-418c-8b80-2c55461a75c2','和自然','釋紹嵩','宋','宋诗','song-poetry','','[]','南北三年一解携，曾書蕉葉寄新題。',64,'全唐诗/poet.song.213000.json','["南北三年一解携，曾書蕉葉寄新題。", "知渠已富江山句，英譽自成桃李蹊。", "坡底詩人梅底醉，雲間秋鴈水間棲。", "千巖萬壑時相憶，迢遞尋君夢不迷。"]'),
('2d115874-bc14-4eab-878d-f1e8a6807a88','題印上人關外山水圖','釋紹嵩','宋','宋诗','song-poetry','','[]','一源淳朴鄮山川，一簇人家起暮煙。',64,'全唐诗/poet.song.213000.json','["一源淳朴鄮山川，一簇人家起暮煙。", "世亂不妨松偃蹇，客程依舊水潺湲。", "雲橫新塞遮秦甸，樹蔭澄江入野船。", "聞說函殽猶險在，爲師懷想幾凄然。"]'),
('7bf6c2df-b716-4da3-bdc8-76a44d1e599f','和自然','釋紹嵩','宋','宋诗','song-poetry','','[]','客裏唯君數往還，笑談終日盡君歡。',64,'全唐诗/poet.song.213000.json','["客裏唯君數往還，笑談終日盡君歡。", "敢將古道爲吾事，已作歸心即自寬。", "露草欲隨霜草盡，泉聲長带珮聲寒。", "月生更愛欄干影，未厭慇懃達曙看。"]'),
('66eeec85-700f-4d3d-a734-136cfbbac1e7','寓龍峰遣興','釋紹嵩','宋','宋诗','song-poetry','','[]','可要棲身向薜蘿，閑門空掩半庭莎。',64,'全唐诗/poet.song.213000.json','["可要棲身向薜蘿，閑門空掩半庭莎。", "天寒日暮遊人少，花落僧禪覆地多。", "六尺屏風遮宴坐，數椽月屋愛巖阿。", "我今客氣渾消盡，無奈千莖鬢雪何。"]'),
('dec294db-71db-4bff-9ce1-30c6e713bd42','陪趙知府登桃嶺山亭','釋紹嵩','宋','宋诗','song-poetry','','[]','誰向雲端著此亭，簷前樹木映窗櫺。',64,'全唐诗/poet.song.213000.json','["誰向雲端著此亭，簷前樹木映窗櫺。", "野田流水濺濺白，芳草隨人段段青。", "春服照塵連草色，雲蘿幽信寄茶經。", "史君領客週遭看，鍾送遥帆落晚汀。"]'),
('63e2e611-c250-4b8c-9a84-8a55c21dbf4e','贈何知錄','釋紹嵩','宋','宋诗','song-poetry','','[]','青雲直上路初通，白鳳新詞入聖聰。',64,'全唐诗/poet.song.213000.json','["青雲直上路初通，白鳳新詞入聖聰。", "抵掌劇談吾浪語，連城增價子何窮。", "共登小閣春風裏，又解征帆落照中。", "此去優游益吟詠，公餘無惜寄詩筒。"]'),
('d044d177-ba32-469c-aab8-45dcd53da72f','客邸晝寢起而追程','釋紹嵩','宋','宋诗','song-poetry','','[]','客裏無聊久合并，夢回南北昧平生。',64,'全唐诗/poet.song.213000.json','["客裏無聊久合并，夢回南北昧平生。", "苦吟風月唯添病，獨冒煙嵐促去程。", "城外諸峰迎落照，花邊白犬吠流鶯。", "阮途未用嗟漂泊，自有孤雲識此情。"]'),
('7dba7777-c763-4ff6-a671-84bb812bb37e','和曾俊臣','釋紹嵩','宋','宋诗','song-poetry','','[]','沉醉無期即是鄉，暫偷閑卧老僧床。',64,'全唐诗/poet.song.213000.json','["沉醉無期即是鄉，暫偷閑卧老僧床。", "縱遊籍草花垂酒，陳跡題詩蝸篆梁。", "故國山川皆夢寐，天涯形貌各昂藏。", "芭蕉葉上三更雨，一陣疎來一陣狂。"]'),
('b27749e5-bebf-4616-8878-3150dd0202e7','憩顔子予海山別業','釋紹嵩','宋','宋诗','song-poetry','','[]','群峰當戶曉嵐晴，楊柳風和日聽鶯。',64,'全唐诗/poet.song.213000.json','["群峰當戶曉嵐晴，楊柳風和日聽鶯。", "郭外春山明錦綉，門前弱水即蓬瀛。", "期登野閣閑應甚，來慣幽禽近不驚。", "獨凭欄干意難寫，綠桑疎處哺牛鳴。"]'),
('1ce6d6a2-4437-45d4-9e2b-2bef63d8240c','鄮山道中答印上人遊乳竇','釋紹嵩','宋','宋诗','song-poetry','','[]','鴉啼古木亂雲深，地带河聲足水禽。',64,'全唐诗/poet.song.213000.json','["鴉啼古木亂雲深，地带河聲足水禽。", "簷雨滴秋殘旅夢，夜堂疎磬發禪心。", "五年乳竇峰前路，十里塵媒溪上林。", "滿目雲山俱是樂，故人携客作幽尋。"]'),
('a6f1dc93-6c3f-4c95-86cc-864e153bb710','春夜書懷','釋紹嵩','宋','宋诗','song-poetry','','[]','海內艱難各飽更，鬢毛寧與化工爭。',64,'全唐诗/poet.song.213000.json','["海內艱難各飽更，鬢毛寧與化工爭。", "春宵思極蘭燈暗，曉角初吹客夢驚。", "壯思不逢韓吏部，絕交益媿孔方兄。", "到頭詩卷須藏却，薄飯粗繒老此生。"]'),
('b5aad412-efe1-401f-ba9f-4d9242369876','送黎主簿','釋紹嵩','宋','宋诗','song-poetry','','[]','及瓜一笑上浮艎，孤淡無君得趣長。',64,'全唐诗/poet.song.213000.json','["及瓜一笑上浮艎，孤淡無君得趣長。", "秋月春花入牙頰，錦機綉段出肝腸。", "詩題寺壁雲根潤，江送蓬婆雪汁香。", "丞相舊知爲學苦，回軒應問石渠郎。"]'),
('478c33ae-4a92-45ac-b4c6-45da7ee32d91','酬王主簿示道中所作','釋紹嵩','宋','宋诗','song-poetry','','[]','蓼花紅淡葦條黄，洛岸秋晴夕照長。',67,'全唐诗/poet.song.213000.json','["蓼花紅淡葦條黄，洛岸秋晴夕照長。", "雪羽{礻離}褷立倒影，酒旗摇曳出疎篁。", "雲邊鴈斷湖邊月，圩上人牽水上航。", "輸與能詩王主簿，每行吟得好篇章。"]'),
('24121044-382e-4f44-bd2f-63a81187296d','貽康兼善','釋紹嵩','宋','宋诗','song-poetry','','[]','遍繞籬邊日漸斜，盡無鷄犬有鳴鴉。',64,'全唐诗/poet.song.213000.json','["遍繞籬邊日漸斜，盡無鷄犬有鳴鴉。", "風凋古木秋陰薄，煙瑣西山暝色賒。", "題柱未期歸蜀國，繫船長得傍蘆花。", "雲林好處欲留脚，要趁新詩挽物華。"]'),
('8f09a5cf-02e9-49b1-bb82-dfe225dc5753','途次走筆送張明府之都城','釋紹嵩','宋','宋诗','song-poetry','','[]','原下相逢便別離，故人特地爲嗟咨。',64,'全唐诗/poet.song.213000.json','["原下相逢便別離，故人特地爲嗟咨。", "高灘落日光零亂，春水涵波綠渺瀰。", "四壁一身長客夢，三年兩作送君詩。", "紫垣名士推揚切，會向天庭振羽儀。"]'),
('73b73775-6f6e-4f0a-a51e-df1d5bf0a59e','途次遇雨和丘德高','釋紹嵩','宋','宋诗','song-poetry','','[]','白葦黄茅路四通，芙蓉憔悴菊垂叢。',64,'全唐诗/poet.song.213000.json','["白葦黄茅路四通，芙蓉憔悴菊垂叢。", "川原繚繞浮雲外，樓閣朦朧細雨中。", "蔽野吞村飄不住，重山複水去無窮。", "丘郎蠟屐能從我，一任此身同轉蓬。"]'),
('43adc8e5-077f-4d4f-814f-6c323ca34ce1','題劉唐臣新葺池亭','釋紹嵩','宋','宋诗','song-poetry','','[]','劉郎瀟洒水爲居，水碧山青畫不如。',64,'全唐诗/poet.song.213000.json','["劉郎瀟洒水爲居，水碧山青畫不如。", "綠竹可供公子釣，紫鱗時掣季膺魚。", "幽尋勝事鳥窺牖，閑卧臨窗燕拂書。", "觸目韶華總詩本，放懷端與世情疎。"]'),
('21e1cf82-ab79-4b8a-b702-2ffb97534d72','夜題','釋紹嵩','宋','宋诗','song-poetry','','[]','滿庭松桂雨餘天，病眼開時月正圓。',64,'全唐诗/poet.song.213000.json','["滿庭松桂雨餘天，病眼開時月正圓。", "羅列衆星依木末，安排流水落簷前。", "倚松長嘯宜疎拙，隨處何妨且信緣。", "白髮青燈兩無語，瓣香深炷夜堂禪。"]'),
('cd4fb3b2-1456-46bd-9f95-9b77343e0cfc','次韻楊判院晚春','釋紹嵩','宋','宋诗','song-poetry','','[]','杏褪殘花點碧輕，殘花含恨脫紅英。',64,'全唐诗/poet.song.213000.json','["杏褪殘花點碧輕，殘花含恨脫紅英。", "樹連翠篠圍春晝，風入青山送雨聲。", "不辦扁舟訪安道，何妨蓮社醉淵明。", "如公自是鑾坡具，盍與吾君致太平。"]'),
('b7d6c2b9-2484-4002-9c43-212e04e33e90','答朋上人','釋紹嵩','宋','宋诗','song-poetry','','[]','爭渡行人簇晚沙，歸舟天際暮雲遮。',64,'全唐诗/poet.song.213000.json','["爭渡行人簇晚沙，歸舟天際暮雲遮。", "波生野水鴈初下，竹映寒原日已斜。", "剩欲出門追笑語，可堪垂白各天涯。", "知公頗有奇章病，戲墨貽嘲棲暝鴉。"]'),
('59d0f000-770a-4020-9715-82d8bffcd440','次韻朱國器秋夜之什','釋紹嵩','宋','宋诗','song-poetry','','[]','二水奔奔鳴屋除，山川澄浄九秋餘。',64,'全唐诗/poet.song.213000.json','["二水奔奔鳴屋除，山川澄浄九秋餘。", "故人相見自青眼，病叟中間已白鬚。", "風射破窗燈易滅，鶴歸喬木月難呼。", "政須送與王摩詰，畫我憑欄覓句圖。"]'),
('87175857-cf9c-4f26-814a-f2b7766c9ed0','次韻曾俊臣即事','釋紹嵩','宋','宋诗','song-poetry','','[]','柳暗人家水拍堤，人家隨處有柴扉。',64,'全唐诗/poet.song.213000.json','["柳暗人家水拍堤，人家隨處有柴扉。", "草中白道穿村去，門外黄塵撲面飛。", "返照未沉僧獨往，暮山時見鳥雙歸。", "風從北戶來披拂，暗遞花香入客衣。"]'),
('26d97656-156e-4bd9-8420-58a409599d32','憩竇園因題池亭','釋紹嵩','宋','宋诗','song-poetry','','[]','午枕藜床夢忽驚，竇家園裏有鶯聲。',64,'全唐诗/poet.song.213000.json','["午枕藜床夢忽驚，竇家園裏有鶯聲。", "半生客路逢佳節，萬瓦脚跟開化城。", "鸂鶒刷毛花蕩漾，蒲萄上架月縱橫。", "誰教併向此中見，清殺詩翁老不勝。"]'),
('711eebca-dd88-4d42-a7ba-a5efe9cd6f30','和陳堯臣','釋紹嵩','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','羨君瀟灑有餘清，霜翮摩霄萬里情。',64,'全唐诗/poet.song.213000.json','["羨君瀟灑有餘清，霜翮摩霄萬里情。", "冰雪照人徐孺子，篇章高體謝宣城。", "摇窗竹色留僧語，步野風寒散酒酲。", "明日岳陽樓上去，不妨談笑又詩成。"]'),
('70426eef-a3e2-467f-973d-a2b40f6a8a0f','贈聞人必大  其一','釋紹嵩','宋','宋诗','song-poetry','','[]','未遂青雲一挂科，科名成後竟如何。',64,'全唐诗/poet.song.213000.json','["未遂青雲一挂科，科名成後竟如何。", "貧疑陋巷春偏少，學辦癡龍藝最多。", "剩把文章鳴聖代，却思猿鳥共煙蘿。", "高吟大醉三千首，他日陽春白雪歌。"]'),
('071e1640-8007-41a6-9e8a-29dec158b2aa','贈聞人必大  其二','釋紹嵩','宋','宋诗','song-poetry','','[]','長日林臯獨醉吟，久貧如得顧家金。',64,'全唐诗/poet.song.213000.json','["長日林臯獨醉吟，久貧如得顧家金。", "屬文想見翻新樣，執卷猶聞惜寸陰。", "世上紛紛蠻與觸，胸中歷歷古兼今。", "有時出縱風煙步，多謝携筇數訪尋。"]'),
('d2e33a5c-8aa1-41cb-acee-4ededf5e877c','曲江野眺','釋紹嵩','宋','宋诗','song-poetry','','[]','偶來清賞曲江頭，人自無言水自流。',32,'全唐诗/poet.song.213000.json','["偶來清賞曲江頭，人自無言水自流。", "欲作新詩圖畫取，亂峰寒木更孤舟。"]'),
('470a8a2d-9396-47f3-9bab-8f0f7bd00d04','舟中書事','釋紹嵩','宋','宋诗','song-poetry','','[]','南昌城郭枕江煙，一葦鳴桹下渺然。',32,'全唐诗/poet.song.213000.json','["南昌城郭枕江煙，一葦鳴桹下渺然。", "驚起暮天沙上鴈，背人飛過北山前。"]'),
('8593df98-3d37-4785-a0e7-abe5cdf24356','宿山居','釋紹嵩','宋','宋诗','song-poetry','','[]','中庭淡月照三更，環堵翛然表裏清。',32,'全唐诗/poet.song.213000.json','["中庭淡月照三更，環堵翛然表裏清。", "深夜欲眠眠未得，一溪秋水枕邊聲。"]'),
('755fed88-12b4-4e62-a718-b00663cd46ba','仙嵓江口','釋紹嵩','宋','宋诗','song-poetry','','[]','淅淅寒流漲淺沙，小橋通去路橫斜。',32,'全唐诗/poet.song.213000.json','["淅淅寒流漲淺沙，小橋通去路橫斜。", "因尋野渡逢漁舍，夾路松開黄玉花。"]'),
('898ec547-3c68-41d3-8b72-c5cbeb53f1b2','題謝公橋','釋紹嵩','宋','宋诗','song-poetry','','[]','白雲深處小橋橫，流水涓涓古意生。',32,'全唐诗/poet.song.213000.json','["白雲深處小橋橫，流水涓涓古意生。", "多少升沉都不見，至今留得謝公名。"]'),
('7e193d3e-dd96-4a20-850e-d63e652b7cb2','宿疎山','釋紹嵩','宋','宋诗','song-poetry','','[]','竹輿穿雨上疎山，寒涕垂頤獨掩關。',32,'全唐诗/poet.song.213000.json','["竹輿穿雨上疎山，寒涕垂頤獨掩關。", "病客欲眠渾不寐，白猿啼在白雲間。"]'),
('7d2cc474-0f09-44fd-99c9-43b2aa548874','雨後登吸江亭','釋紹嵩','宋','宋诗','song-poetry','','[]','吸江亭下雨初晴，中有樵夫跣足行。',32,'全唐诗/poet.song.213000.json','["吸江亭下雨初晴，中有樵夫跣足行。", "時作微吟清徹骨，茲游無乃太清生。"]'),
('660f6b09-ee1f-4911-99db-213e901c00ff','次韻吳伯庸竹間梅花十絕  其一','釋紹嵩','宋','宋诗','song-poetry','','[]','竹間初拆半斜枝，正是周王二月時。',32,'全唐诗/poet.song.213000.json','["竹間初拆半斜枝，正是周王二月時。", "竹映梅花花映竹，主人不剪要題詩。"]'),
('6bceb4ba-7906-444f-a921-c5e040f0d159','次韻吳伯庸竹間梅花十絕  其二','釋紹嵩','宋','宋诗','song-poetry','','[]','孤芳高節共亭亭，子細相看似有情。',32,'全唐诗/poet.song.213000.json','["孤芳高節共亭亭，子細相看似有情。", "春色惱人眠不得，移床換枕到天明。"]'),
