('1b58af80-0a19-452c-96f7-ae3205fdfe28','知府黄寺簿生日  其五','釋紹嵩','宋','宋诗','song-poetry','','[]','邦伯由來有令名，修持清苦振佳聲。',32,'全唐诗/poet.song.213000.json','["邦伯由來有令名，修持清苦振佳聲。", "至尊仄席思耆舊，即看徵黄侍紫清。"]'),
('f3a55b53-e32d-4856-bcc2-ef441e9ae9e2','知府黄寺簿生日  其六','釋紹嵩','宋','宋诗','song-poetry','','[]','筆端風雨發天慳，應有清名動九關。',32,'全唐诗/poet.song.213000.json','["筆端風雨發天慳，應有清名動九關。", "正直早年聞苦節，只今文翰許誰攀。"]'),
('29d0d102-42c7-4d44-88dc-dc90bcad3df9','知府黄寺簿生日  其七','釋紹嵩','宋','宋诗','song-poetry','','[]','惠愛如春威似霜，家傳活國有良方。',32,'全唐诗/poet.song.213000.json','["惠愛如春威似霜，家傳活國有良方。", "平章風物詩無敵，玉唾銀鈎十萬行。"]'),
('e6d64125-276f-4733-a636-92bd45f42c71','知府黄寺簿生日  其八','釋紹嵩','宋','宋诗','song-poetry','','[]','從容此日見清規，玉珮瓊琚杜拾遺。',32,'全唐诗/poet.song.213000.json','["從容此日見清規，玉珮瓊琚杜拾遺。", "槜李轉聞風教好，蒼生從此得伸眉。"]'),
('4a77977d-5fe1-4cff-b316-8a0128d52556','知府黄寺簿生日  其九','釋紹嵩','宋','宋诗','song-poetry','','[]','文星漸見射台星，仙籍高標第一名。',32,'全唐诗/poet.song.213000.json','["文星漸見射台星，仙籍高標第一名。", "爲語邦人休眷戀，北門卧護要耆英。"]'),
('ef7e6454-4fb4-4e67-b16c-675ec832e696','知府黄寺簿生日  其一○','釋紹嵩','宋','宋诗','song-poetry','','[]','自笑無機觸事真，衰遲猶許望光塵。',32,'全唐诗/poet.song.213000.json','["自笑無機觸事真，衰遲猶許望光塵。", "此邦若有誅茆地，乞借風波起涸鱗。"]'),
('8eebc186-0ab5-4477-8b9b-095cea5c1e2a','口占','釋紹嵩','宋','宋诗','song-poetry','','[]','谷口殘春黄鳥稀，野梅山杏暗芳菲。',32,'全唐诗/poet.song.213000.json','["谷口殘春黄鳥稀，野梅山杏暗芳菲。", "百千幽勝無人見，紅白路花相雜飛。"]'),
('693e7794-1e0d-417a-8ba8-6b8121390f79','城西野行  其一','釋紹嵩','宋','宋诗','song-poetry','','[]','三月西城淑景多，曉煙清露暗相和。',32,'全唐诗/poet.song.213000.json','["三月西城淑景多，曉煙清露暗相和。", "晚鍾未用催歸客，聞道新亭更可過。"]'),
('0d1abeb7-3f60-4540-9dcf-8936c2947133','城西野行  其二','釋紹嵩','宋','宋诗','song-poetry','','[]','細草疎花自在春，悠悠煙水似天津。',32,'全唐诗/poet.song.213000.json','["細草疎花自在春，悠悠煙水似天津。", "垂楊一徑深深去，白鳥雙飛不避人。"]'),
('b3357e67-29ee-4800-b660-bea45f173283','江上嬉行和永上人','釋紹嵩','宋','宋诗','song-poetry','','[]','飛花滿眼句縱橫，江上閑吟立又行。',32,'全唐诗/poet.song.213000.json','["飛花滿眼句縱橫，江上閑吟立又行。", "正是如今江上好，薰風盡日語流鶯。"]'),
('e4b62904-5ffe-45f3-8f3f-2679e7714823','解嘲十絕呈浩西堂  其一','釋紹嵩','宋','宋诗','song-poetry','','[]','殘骸已廢自知休，少不愁窮老豈愁。',32,'全唐诗/poet.song.213000.json','["殘骸已廢自知休，少不愁窮老豈愁。", "坎止流行聊爾耳，一身隨世作虛舟。"]'),
('635c31e1-892f-4096-9667-b076c6cd16f8','解嘲十絕呈浩西堂  其二','釋紹嵩','宋','宋诗','song-poetry','','[]','世緣自覺逐時輕，可要王侯知姓名。',32,'全唐诗/poet.song.213000.json','["世緣自覺逐時輕，可要王侯知姓名。", "未合白頭今已白，知渠何事太忙生。"]'),
('503d8abe-9564-4b9e-88ac-5fec0222a078','解嘲十絕呈浩西堂  其三','釋紹嵩','宋','宋诗','song-poetry','','[]','江湖放浪未寧居，處世真同逐隊魚。',32,'全唐诗/poet.song.213000.json','["江湖放浪未寧居，處世真同逐隊魚。", "但願一生長若此，時清不問命何如。"]'),
('164dcc3e-4cb8-40ae-92d4-acbf3ab298ea','解嘲十絕呈浩西堂  其四','釋紹嵩','宋','宋诗','song-poetry','','[]','可堪時序苦侵尋，留滯誰知此日心。',32,'全唐诗/poet.song.213000.json','["可堪時序苦侵尋，留滯誰知此日心。", "萬事轉頭如墮甑，忘懷未得是微吟。"]'),
('e8e6f982-dcc3-4275-a5dd-b48771d34a1a','解嘲十絕呈浩西堂  其五','釋紹嵩','宋','宋诗','song-poetry','','[]','中年養病只吟詩，心跡懸知兩崛奇。',32,'全唐诗/poet.song.213000.json','["中年養病只吟詩，心跡懸知兩崛奇。", "莫笑吾儂躭此癖，鏡中贏得鬢成絲。"]'),
('1c2afa9f-9c38-417b-b3b7-2e9a1a030899','解嘲十絕呈浩西堂  其六','釋紹嵩','宋','宋诗','song-poetry','','[]','浩然南北與西東，自笑今爲白髮翁。',32,'全唐诗/poet.song.213000.json','["浩然南北與西東，自笑今爲白髮翁。", "畢竟浮生謾勞役，一場大夢到頭空。"]'),
('f20249cf-4610-4d70-bfe7-70186fb0d096','解嘲十絕呈浩西堂  其七','釋紹嵩','宋','宋诗','song-poetry','','[]','𡼭巇世路九回腸，兩鬢年深一鏡霜。',32,'全唐诗/poet.song.213000.json','["𡼭巇世路九回腸，兩鬢年深一鏡霜。", "身事龍鍾應是分，誰知貧樂異尋常。"]'),
('d6f9bab0-2b34-426d-a1c2-50f4a58a7588','解嘲十絕呈浩西堂  其八','釋紹嵩','宋','宋诗','song-poetry','','[]','不知經世竟如何，轉看人情敗意多。',32,'全唐诗/poet.song.213000.json','["不知經世竟如何，轉看人情敗意多。", "頼有好山供客眼，此生吾亦未蹉跎。"]'),
('453ace27-44ff-4c7a-a89e-74b728f0bd30','解嘲十絕呈浩西堂  其九','釋紹嵩','宋','宋诗','song-poetry','','[]','杜門芳草與蒼苔，况是囊無挑藥財。',32,'全唐诗/poet.song.213000.json','["杜門芳草與蒼苔，况是囊無挑藥財。", "莫漢勞生三十九，人間萬事要寒灰。"]'),
('aeebc862-9ae4-43aa-9d2a-6759199ad0ee','解嘲十絕呈浩西堂  其一○','釋紹嵩','宋','宋诗','song-poetry','','[]','平居懶與慢相親，養拙藏愚春復春。',32,'全唐诗/poet.song.214000.json','["平居懶與慢相親，養拙藏愚春復春。", "已信此心安此命，世情奈值不容真。"]'),
('cdf20298-091f-4dab-9e94-e08f327818f4','浩西堂見和因再用韻  其一','釋紹嵩','宋','宋诗','song-poetry','','["\u897f\u6e56"]','無錢使鬼故宜休，已失裝懷萬斛愁。',32,'全唐诗/poet.song.214000.json','["無錢使鬼故宜休，已失裝懷萬斛愁。", "况有西湖好山水，一帆還自上歸舟。"]'),
('306230a7-69f5-407a-8317-5e85a9e0f175','浩西堂見和因再用韻  其二','釋紹嵩','宋','宋诗','song-poetry','','[]','老景人情一羽輕，絆身何用尚浮名。',32,'全唐诗/poet.song.214000.json','["老景人情一羽輕，絆身何用尚浮名。", "備嘗世事灰心久，更問儂當作麽生。"]'),
('aead81ab-ff10-49d3-875c-6d8d09664ccb','浩西堂見和因再用韻  其三','釋紹嵩','宋','宋诗','song-poetry','','[]','蕭條四壁是閑居，老子而今非故魚。',32,'全唐诗/poet.song.214000.json','["蕭條四壁是閑居，老子而今非故魚。", "大抵人生只如此，只消如此看何如。"]'),
('3a4c134a-18ef-472d-9bde-f1dd84ae476e','浩西堂見和因再用韻  其四','釋紹嵩','宋','宋诗','song-poetry','','[]','鏡中老色日侵尋，更有江湖萬里心。',32,'全唐诗/poet.song.214000.json','["鏡中老色日侵尋，更有江湖萬里心。", "心許故人知此意，爲吾因掉白頭吟。"]'),
('cc2da7c9-2129-4640-a49e-fa42da19afc2','浩西堂見和因再用韻  其五','釋紹嵩','宋','宋诗','song-poetry','','[]','每慚疎散爲吟詩，說破當知未大奇。',32,'全唐诗/poet.song.214000.json','["每慚疎散爲吟詩，說破當知未大奇。", "似此誤人多少事，如何兩鬢不成絲。"]'),
('ee3d2f44-45f4-474d-82b7-b56e53b221c2','浩西堂見和因再用韻  其六','釋紹嵩','宋','宋诗','song-poetry','','[]','行盡天涯西復東，大家閑作卧雲翁。',32,'全唐诗/poet.song.214000.json','["行盡天涯西復東，大家閑作卧雲翁。", "紛紛燕雀休相羨，得喪悲歡盡是空。"]'),
('c4e0696d-227b-45bc-9c88-788f0e99dc42','浩西堂見和因再用韻  其七','釋紹嵩','宋','宋诗','song-poetry','','[]','笑殺人來斷殺腸，可憐贏得鬢成霜。',32,'全唐诗/poet.song.214000.json','["笑殺人來斷殺腸，可憐贏得鬢成霜。", "人情易變乃如此，祇有江山不改常。"]'),
('65957d68-07e4-4518-973d-98bb0414b36a','浩西堂見和因再用韻  其八','釋紹嵩','宋','宋诗','song-poetry','','[]','道方時險擬如何，今古疎愚似我多。',32,'全唐诗/poet.song.214000.json','["道方時險擬如何，今古疎愚似我多。", "否去泰來終可待，尚須客裏訪蹉跎。"]'),
('8ad7e441-a803-4506-88d0-e81463347ae5','浩西堂見和因再用韻  其九','釋紹嵩','宋','宋诗','song-poetry','','[]','小園和雨掃莓苔，箇箇圓如濟世財。',32,'全唐诗/poet.song.214000.json','["小園和雨掃莓苔，箇箇圓如濟世財。", "丘壑同盟從已定，莫談休咎動寒灰。"]'),
('4a4d88ff-ffc1-4123-914f-0138e065f617','浩西堂見和因再用韻  其一○','釋紹嵩','宋','宋诗','song-poetry','','[]','沙邊鷗鷺日相親，老去光陰非我春。',32,'全唐诗/poet.song.214000.json','["沙邊鷗鷺日相親，老去光陰非我春。", "百巧從來知是妄，獨援詩筆得天真。"]'),
('344aeb69-8d87-441c-b685-7df8d378d0c5','示德圓','釋紹嵩','宋','宋诗','song-poetry','','[]','莫因居此與名疎，未可唐捐肘後書。',32,'全唐诗/poet.song.214000.json','["莫因居此與名疎，未可唐捐肘後書。", "晝短夜長須强學，青春不再汝知乎。"]'),
('211868cf-d92d-437b-aa49-68ed79ca0529','遊西湖','釋紹嵩','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖招提三百六，佳處如春有眉目。',128,'全唐诗/poet.song.214000.json','["西湖招提三百六，佳處如春有眉目。", "一番雨過吞青空，萬頃無波鴨頭綠。", "望湖樓閣獨自登，煙霏向背攢寒玉。", "想見襄陽孟浩然，此中有句不容續。", "道人長坐西山河，骨清氣明韻出俗。", "久居京闕厭塵土，一夕歸心俊如鵠。", "明窗爲君研破硯，落筆轉頭風雨速。", "龍山深處如定居，就彼結鄰容我卜。"]'),
('5563b6d2-8bcf-4bb2-b310-6b564133b1d7','句','蔡凝','宋','宋诗','song-poetry','','[]','春色徧空明。',6,'全唐诗/poet.song.214000.json','["春色徧空明。"]'),
('6ca64e1f-02dd-4f2d-8347-22628ad05d4a','上習庵陳先生','趙孟堅','宋','宋诗','song-poetry','','[]','厥聞忠孝者，所出同一源。',288,'全唐诗/poet.song.214000.json','["厥聞忠孝者，所出同一源。", "子於所親孝，移忠理必然。", "親賢亦子訓，忠節貴兩全。", "殺身能成仁，揚名斯永延。", "是亦孝所在，豈但知色難。", "嘻其叔世風，本末嗟倒懸。", "若曰能養耳，食美衣華鮮。", "苟求胡弗至，側媚諂笑肩。", "彼其良自多，喟歎達者觀。", "向來歐陽公，拓落夷陵年。", "夫人告之公，淡泊吾所安。", "慎毋爲險變，守節當彌堅。", "卓哉名母訓，紀歷伊誰傳。", "恭惟奉常君，矢心直似弦。", "立朝幾抗論，凜凜高回天。", "力甦憒憒徒，若障狂瀾川。", "人知君守固，當識君母賢。", "想其勉勵時，諄勤誨膝邊。", "怡愉一領解，心注靡變遷。", "升而高爲天，下而沉爲淵。", "但知慈訓在，此外浮雲焉。", "茲來從吏隠，斲屋新數椽。", "曲檻花葳蕤，虛窗月嬋娟。", "雅意寓一賦，懦立貪以廉。"]'),
('aa31b68c-ae9d-43dd-b7dd-e6d0a34fc24f','仲弟借書持要不謹護有損爲之覆背葺還','趙孟堅','宋','宋诗','song-poetry','','[]','昔聞勤讀者，三度絕韋編。',288,'全唐诗/poet.song.214000.json','["昔聞勤讀者，三度絕韋編。", "讀書書已破，書則在肺肝。", "摘實咀其華，發揮事業間。", "伊惟事精研，整束懸牙籤。", "縹囊手未觸，慨是龍泉言。", "虎子畜溪魚，汝懵未鑿顓。", "胡策追元方，紛紛探簡編。", "抱書手不龜，面壁縛枯禪。", "靴化例隨水，竟負一瓻還。", "季也怒生癭，我慚家訓顔。", "願季無銜怒，鳳樓修則完。", "嗟嗟仁義諫，束濕何由痊。", "顛倒幸爾存，柿葉風掀掀。", "糊老飽九炊，紙搗翼擬蟬。", "翻翻事兼兩，滑膩好且堅。", "手鑒具在茲，秋露無重妍。", "舊書百回讀，訓佩坡老僊。", "請季事斯語，慎勿高閣懸。", "因憐數匱藏，徒疥小印存。", "浮雲忽白衣，世事無不然。", "眼底不自快，封閉何取焉。", "所貴得之心，亦可忘蹄筌。", "又憐囿大塊，華好竟飽鮮。", "一飽羶聚蠅，曷與千古傳。"]'),
('89771c4f-cc5b-4ad8-82b0-35b12575d18e','贈筆工吳昇','趙孟堅','宋','宋诗','song-poetry','','[]','蘭臺上狸毛，山谷愛雞距。',228,'全唐诗/poet.song.214000.json','["蘭臺上狸毛，山谷愛雞距。", "物勝因人成，雅製傳自古。", "風流渡江初，筆翰猶朴魯。", "曾窺上方製，遺範典刑具。", "寸簪束萬穎，贍足飽霜兔。", "豐融沛行墨，充實自妍富。", "行間得茂密，夫豈窘尺度。", "澆浮自趨薄，羸劣醜畢露。", "清快誇鈎心，節括號釵股。", "纖纖銛甚錐，祇便庸書伍。", "殺鋒出光芒，苗枯旱無雨。", "齷齪癡凍蠅，安能劂石怒。", "爾來邈東嘉，法則自誰祖。", "宛見昔製作，齊力萬毫努。", "吾欲標諸人，示茲明取與。", "斲雕還反樸，淳風招已去。", "春苗異蘆筍，廣袖謬織組。", "誰能一羽力，回彼滔滔注。", "百爾今已然，豈但於筆故。"]'),
('7ccabe50-8347-4f8e-888e-44fdfdca4aaa','題黄巖夏氏曉山亭詩卷','趙孟堅','宋','宋诗','song-poetry','','[]','玄暉工畫山，最識山之趣。',204,'全唐诗/poet.song.214000.json','["玄暉工畫山，最識山之趣。", "每言籠朝雲，乃是奇絕處。", "君家結幽亭，兩峯正當戶。", "窣堵冠其巔，雲中雙筆露。", "宗老爲扁名，得自昌黎句。", "相當卷書坐，塤箎遞吟賦。", "是時神宇泰，白雲未飛去。", "滃然截山腰，素練初橫布。", "須臾朝陽升，景象幾更互。", "盤旋宛遊龍，披離擘輕絮。", "春澌苒而泮，青烟惟一縷。", "霏微辨岡巒，歷落分島嶼。", "露晞如膏沐，蒼翠盡還故。", "松針與篁叢，貫穿珠無數。", "應接良不暇，詩料亦既冨。", "只憂紅塵生，分我淡思慮。", "更須清夜來，四更看月吐。"]'),
('4df4dda1-039b-4e15-913b-d6dbeec1a8f7','詩談','趙孟堅','宋','宋诗','song-poetry','','[]','吾嗤彼云士，努力事詩妍。',168,'全唐诗/poet.song.214000.json','["吾嗤彼云士，努力事詩妍。", "竟日搜枯腸，抽黄對白間。", "爾何無達觀，跼促自縛纏。", "不見淵明陶，有詩累百篇。", "要以寫吾心，出語如流泉。", "採菊見南山，得句於悠然。", "少陵動感慨，忠義膽所宣。", "有時心境夷，亦復輕翩翩。", "纖纖白雲閑，無心遊日邊。", "風石激而奇，奔迸生雲煙。", "詎以天然態，而事斧鑿鎸。", "陶爾一觴酒，警爾心地偏。", "少焉明月上，高掛西山巔。", "聽我曳杖歌，金石聲撼天。"]'),
('9601cee2-7708-4608-9bae-920ec64380ee','萬壽寺避暑讀書','趙孟堅','宋','宋诗','song-poetry','','[]','梵寺齋殿深，屋古洞陰冷。',132,'全唐诗/poet.song.214000.json','["梵寺齋殿深，屋古洞陰冷。", "火雲自空飛，此地暑盡屏。", "乍至心已清，坐久體如冰。", "官清務乃簡，居易事亦省。", "是爲臭味同，玉碎金無礦。", "蕭閑日追隨，論辯當脩省。", "展書相對讀，佳處擊節猛。", "輿皁謂前茲，文會無許盛。", "觴詠直寄耳，沈湎夫豈肯。", "過從奚厭密，交道久彌敬。", "無令數斯疎，此語共知警。"]'),
('6c9a3742-8b74-477e-a18c-74d17e47cfce','爲倉使吳荆溪先生壽','趙孟堅','宋','宋诗','song-poetry','','[]','人祝先生壽，勳名而福祿。',216,'全唐诗/poet.song.214000.json','["人祝先生壽，勳名而福祿。", "伊惟小門生，而迺異斯祝。", "所祝在斯文，其壽非已獨。", "嘗聞侍席言，檃括因以復。", "孔孟至皇朝，文與道相屬。", "溯自熙豐後，專門始分目。", "歐蘇以文雄，周程理義熟。", "從此判而二，流派各異躅。", "偉哉水心葉，同軌混列輻。", "粲粲雲錦章，理義仍炳燭。", "筠窗一傳後，人已沾膏馥。", "正統的屬任，非公紹者孰。", "鯫生耳聞此，驚詫歎不足。", "因捧介壽巵，譜在歌詩軸。", "願言清節高，歲寒等修竹。", "長以文鳴道，聲金而振玉。", "上而軋漢周，俯命騷以僕。", "門生嚴楷法，剩將從紀錄。"]'),
('abffbc04-40ad-4c99-95b7-bff57fd84fc8','漕使李寶文先生除宣城守','趙孟堅','宋','宋诗','song-poetry','','[]','幕客崇酒觴，渠渠餞行舟。',252,'全唐诗/poet.song.214000.json','["幕客崇酒觴，渠渠餞行舟。", "先生蘸甲飲，不使涓滴留。", "持盞顧謂言，汝復能吟不。", "爾不歌吾行，而俟吾言求。", "沃爾滿鍾酒，畀爾筆力遒。", "扶輿懵懵醉，夢化蝴蝶遊。", "夜分起展燭，落筆蓴絲柔。", "請歌先生行，真與人不侔。", "前者亦云歸，金帛囷載收。", "今惟明月耳，舴艋輕浮浮。", "視彼掊歛徒，推剝藂怨尤。", "逮其去國日，競欲瓦礫投。", "此乃戀寬恩，說著涕泗流。", "國用既云裕，民瘉亦云瘳。", "而令分左符，遠從牧山州。", "投鼠戒忌器，矧我無是謀。", "彈烏或驚鸞，盍亦謹厥籌。", "茲焉皆汩汩，去矣從休休。", "伊惟小門生，莫計攀前輈。", "彌溪桃花水，舟行願悠悠。", "行有賜還詔，佇立螭坳頭。"]'),
('28afc532-56b9-4792-a7ac-f7cb08a9b76f','拜范文正公祠','趙孟堅','宋','宋诗','song-poetry','','[]','瘦石插半天，玲瓏聳蒼翠。',192,'全唐诗/poet.song.214000.json','["瘦石插半天，玲瓏聳蒼翠。", "想從混沌初，有此紛破碎。", "斷截不分離，欹危不顛墜。", "乃於其中間，穿沿石路細。", "頻勞謝屐行，捫撫足幻怪。", "下有泉溶溶，根來從石背。", "香山纔品題，名得因人貴。", "瘦筇行清秋，西風吹我袂。", "躋攀幸未疲，俯仰一歎喟。", "下山拜范祠，遺像儼如在。", "胸中萬甲兵，曾使西夏畏。", "巖瞻石不移，可想鐵肝肺。", "嘻其羣小人，風林犬空吠。", "於今孰存亡，取捨良亦易。", "但堅自力心，歲寒見節槩。", "卓爾彼何人，晞之則亦是。"]'),
('623177bc-55c8-41d4-a480-6320746d1a12','詠史贈王侍御','趙孟堅','宋','宋诗','song-poetry','','[]','昔有陽城子，高卧中條山。',288,'全唐诗/poet.song.214000.json','["昔有陽城子，高卧中條山。", "粵從丹詔聘，職諫居朝端。", "北垣七八年，一詞曾靡殫。", "於中常戚戚，事以秦越看。", "諍臣論一篇，見誚昌黎韓。", "城日洽壺觴，視之無汗顔。", "一朝天子誤，鼎鼐庸雄姦。", "皇皇朝野人，敢議不敢言。", "城曰茲可矣，不言吾豈安。", "當廷壞其麻，勢若迴狂瀾。", "臣言不可奪，臣肉所可剜。", "孰謂雄猜主，天聽亦爲還。", "一鳴必驚人，朝陽之祥鸞。", "一飛必衝天，北溟之鵬摶。", "啾啾燕雀輩，終歲寒簷間。", "君今踵其武，可想倚任專。", "士習弊滋久，未易一匕痊。", "遺臭偃月姦，殆今逾百年。", "利欲錮人心，深矣莫洗湔。", "幾新更化機，仍澁膠柱弦。", "洗泥何能清，救弊應其源。", "昔無起樓地，今舉田連阡。", "而以求善治，却行而欲前。", "復有事誕衒，奮臂張虛拳。"]'),
('78328de8-fa44-4c34-b484-8fe14539ba4e','送放生池碑','趙孟堅','宋','宋诗','song-poetry','','[]','維書號心畫，於以觀厥德。',228,'全唐诗/poet.song.214000.json','["維書號心畫，於以觀厥德。", "堂堂太師顔，忠義挺不屈。", "怒張鐵柱立，凜若駡蔡賊。", "蠶頭而蠆尾，屋漏而壁拆。", "豈事筆端求，要自心胸出。", "心源儻匪正，馬謾按圖索。", "君侯冰玉清，一點塵不入。", "擺脫世緣盡，四壁無良物。", "源清流應隨，心同寧異跡。", "前年鎮霅城，清風貪者格。", "人言政化明，如仕唐大曆。", "人言八法具，儼是浯溪刻。", "卑棲小李掾，松茂悅見柏。", "甚欲事灑掃，筆硯供洗滌。", "官身類匏繫，唯向清夢覿。", "手搨魯池碑，潢謄寄遠驛。", "既異裹苞苴，抑匪徒掛壁。", "舉目見顔公，英氣聳辟易。", "又若小子勤，祗莊常侍側。"]'),
('43c248f6-f046-4ce0-8e41-0291a40a968d','別贈陳新叔弟','趙孟堅','宋','宋诗','song-poetry','','[]','神靈造天極，仁深祚綿遠。',288,'全唐诗/poet.song.214000.json','["神靈造天極，仁深祚綿遠。", "光堯渡江初，屬族扶日輦。", "南來逾百年，瓜瓞載繁衍。", "開江一枝燈，海濱發長燄。", "紹興庚辰第，伯祖維創見。", "自此燈燈續，儒科已累踐。", "姪也幼則孤，門戶中屯蹇。", "執編青衿後，浪策禮部選。", "有叔行派親，隔驀此異閈。", "天都邂逅初，覿面苦恨晚。", "爲言起家難，銖積勤靡倦。", "相從忽問勞，把臂互驚嘆。", "霅城每頻過，訪我李曹掾。", "及茲脫選海，幾擬謝深眷。", "三年在奔波，留滯顔色靦。", "扁舟此經從，相見笑而莞。", "排日羅酒漿，延顧禮既腆。", "所欣廷蘭秀，一一莫可揀。", "讀書固有獲，而况多積善。", "竇桂未足誇，王槐定應顯。", "願言闡宏規，涵肆觀文典。", "士業止科名，耕耨工亦淺。", "胸中澆萬卷，落筆自精悍。", "何當它年來，大雅見文憲。"]'),
('7a5ed43f-e2eb-42a3-9be6-845e776ed8b9','乙未春初解漕幕兼職訪秋壑西湖探韻得柳字','趙孟堅','宋','宋诗','song-poetry','','["\u897f\u6e56"]','浮生恍流萍，聚難別易久。',144,'全唐诗/poet.song.214000.json','["浮生恍流萍，聚難別易久。", "經年稀會面，感歎兩執手。", "佳賓稍翕集，歷落馬蹄驟。", "競誇摛錦文，雄騁翻河口。", "主人金叵羅，頗費黄封酒。", "環坐松下亭，海納翕敷受。", "飲酣氣張王，聯題健揮肘。", "山凹日斜射，簷額風穿逗。", "恨無秉燭遊，以夜繼斯晝。", "聊追擘韻戲，嶮窄互呈鬭。", "分携上木蘭，漾槳幾回首。", "遥追飛蓋歸，數徧蘇堤柳。"]'),
('cf533f0b-de6a-4bcd-b5c3-a0b75492fdce','必大弟赴新城簿','趙孟堅','宋','宋诗','song-poetry','','[]','乃翁換官班，幾鬰青雲志。',216,'全唐诗/poet.song.214000.json','["乃翁換官班，幾鬰青雲志。", "晚以身徇國，而得祿及嗣。", "妙年當膴仕，應識珍重此。", "簿領職任輕，正合親文史。", "東安吾舊遊，山水清且美。", "編戶雖不稠，而亦有文士。", "擇友如擇木，所貴高於己。", "遊觀固有時，要在不踰禮。", "飲爵不過三，馬向坦塗履。", "幕府儻留連，謹抑如處子。", "切勿事軒昂，攻者蠭蝟起。", "我已慣嘗此，說病乃真意。", "第守謙謙心，由天工處置。", "命透如春回，不壓重石底。", "爾祖積善在，造物報必侈。", "以我苦澀詞，普告兄與弟。", "莫怪欠誇諛，食橄有回味。", "謂余言不信，識者試質以。"]'),
('ec0153c0-e4a7-493a-8e69-51169ec8f61a','辛丑孟夏甲申日得雨','趙孟堅','宋','宋诗','song-poetry','','[]','物理寓乘除，天存好還道。',252,'全唐诗/poet.song.214000.json','["物理寓乘除，天存好還道。", "去年夏迄秋，旱枯苗盡槁。", "繁霜打麥根，療饑茲已兆。", "逾春秀葽葽，修翠摇旌葆。", "黄雲割未盡，赤日仍杲杲。", "秧針方刺牙，還憂水泉少。", "正深傷弓虞，曲成由大造。", "耕雨刈欲晴，從來難兩好。", "來牟迨既登，甘霖乃方到。", "甲甲占久雨，古語信可考。", "首夏際茲辰，其應孚未禱。", "繁聲喧若注，陰雲陣如掃。", "入夜聽簷溜，滴瀝響到曉。", "蝗螟腐翅翼，蛙黽喊池沼。", "從茲雨未艾，調潤知可保。", "一畝數石收，麥秋功已告。", "千倉而萬箱，應占富禾稻。", "匪藉天功然，人力寧爾巧。", "端由政致和，天示賢侯報。", "不死見豐年，鼓腹歸醉飽。", "末掾與農氓，熙熙歌皡皡。"]'),
('ee06f922-e192-4998-961a-7fa502bee8f3','夜飲歸戲作','趙孟堅','宋','宋诗','song-poetry','','[]','夜雪合三更，崑崙兵密渡。',216,'全唐诗/poet.song.214000.json','["夜雪合三更，崑崙兵密渡。", "常時喜慨談，此夕若親覩。", "杯行數已長，談辯氣掀舉。", "微酣上籃輿，迢迢向歸路。", "出門林盡白，飛雪正零舞。", "苦寒嗟僕夫，鼈跛良窘步。", "北風惡打頭，滅燭失四顧。", "平生功名心，每作艱危慮。", "小試應危機，却輿自行去。", "脚力幸未衰，乘之酒力怒。", "踏雪如踏雲，了不見辛苦。", "尚奚畏泥塗，寧卹雙靴汙。", "僕失莫余追，瞥若肘生羽。", "鶱騰甫登橋，健翎已逾兔。", "還歸坐中堂，長嘯默不語。", "絲鬢且勿生，未謂余不武。", "夜雪向桑乾，立勳期晚暮。", "凜凜金石心，捐軀事明主。"]'),
('2c91dea7-3736-40c6-8c66-db16b4b7b18c','九三月丹','趙孟堅','宋','宋诗','song-poetry','','[]','有花血嫣紅，侈娭大於碗。',264,'全唐诗/poet.song.214000.json','["有花血嫣紅，侈娭大於碗。", "五出猩袍裂，萬攢金釘滿。", "數日色彌鮮，不畏風日暖。", "山茶越丹輩，馬塍豐土産。", "殊名幾百種，並立色俱赧。", "客言名之由，其說鄰怪誕。", "昔有樵弁山，絕頂路迷返。", "見此物尤異，斲置歸里閈。", "九三橐駞流，厥藝工養豢。", "惟以第行稱，姓名微考按。", "香泥密封籜，接度根暗換。", "若古姚魏然，因從九三喚。", "從茲入西浙，移根遍名苑。", "家家尚此花，買價不論貫。", "青油障曉日，朱檻護雕瓚。", "微物因人成，感此一喟嘆。", "憶昔洛陽花，壽安紅爲冠。", "要其所從出，亦自薪槱伴。", "伊維花卉流，第以色媚眼。", "青青三寸松，養可凌霄漢。", "明堂須衆木，未易一材辦。", "工師無遐遺，材滿巖崖畔。"]'),
('b57a1bbb-5f97-4e50-9e21-98f3a725bb78','題吳門顔氏敬享亭石記','趙孟堅','宋','宋诗','song-poetry','','[]','蜾臝祝類我，慈烏知反哺。',192,'全唐诗/poet.song.214000.json','["蜾臝祝類我，慈烏知反哺。", "伊人矧最靈，而不以斯故。", "養雛數羽毛，初志亦辛苦。", "懷哉肯堂念，寥寥幾千古。", "君其若而人，悽愴踐霜露。", "欽聞先君子，清白守儒素。", "何以遺後人，多文以爲富。", "潭潭詩書府，魚魚禮法度。", "王槐信厚成，竇桂陰德著。", "雪玉塵不緇，鍾美見垂裕。", "勤修不自閟，刻詞流肺腑。", "應無忝厥紹，錫類及噲伍。", "卑飛未仰報，有淚滂如雨。", "山高不礙天，水流必東注。", "願言堅此心，宜詣聖賢處。", "他石或可攻，庸效南陔賦。"]'),
('9854fb20-1d0c-4c00-ba02-c560c7709c4e','題陳山龍祠','趙孟堅','宋','宋诗','song-poetry','','[]','白龍生陽山，龍生龍母死。',288,'全唐诗/poet.song.214000.json','["白龍生陽山，龍生龍母死。", "於何藏斯陳，其說從古始。", "豈伊冥邈中，而亦有地利。", "季春旬八日，歲歲雨冥晦。", "龍下大如柱，萬目儼駭視。", "謂龍來朝母，人胡不知禮。", "邑人嚴奉供，神宮聯梵寺。", "龍君與龍母，居中堂殿位。", "兩廡香火誰，分祀及四子。", "山腰有龍湫，泓澄一掬水。", "水旱不涸溢，甘冽冷牙齒。", "禱雨乞一滴，闔境得沾濟。", "昔年令君來，瀝酒方奠啟。", "有物蜿蜒見，舉體金色被。", "巡沿上巾幞，馴狎了無畏。", "令君端笏迎，迎入香奩裏。", "誕四子如粟，久矣傳神異。", "逮置湫石邊，倏與電俱逝。", "或示夢畫工，畫龍要珠戲。", "或載見蜿蜒，躍戲花壺際。", "神靈及事怪，龔碑詳紀記。", "迎享送三辭，上軋騷章麗。", "荔子丹蕉黄，羅池未專美。", "余來擊節誦，金石歌聲曳。"]'),
('7d59250a-90b9-4c93-9965-624cd38fa860','重賦暨邑池亭','趙孟堅','宋','宋诗','song-poetry','','[]','新沐試絺綌，凉生神骨清。',96,'全唐诗/poet.song.214000.json','["新沐試絺綌，凉生神骨清。", "髮疎逗風爽，半幅紗巾輕。", "逍遥池上亭，綠陰取次行。", "清和又重見，時序無留停。", "叢委簿書間，那得散漫情。", "乍此偷隙閑，雲開月蹔明。", "故園松菊荒，蛛網罩南榮。", "琴書知好在，奧窅誰爲評。"]'),
('3cf42db5-9235-4d8b-92ff-5155953a2dc6','憲使陳習菴先生除司業','趙孟堅','宋','宋诗','song-poetry','','[]','連宵對凉月，閒吟祖行篇。',72,'全唐诗/poet.song.214000.json','["連宵對凉月，閒吟祖行篇。", "攬挹南卉香，入句期清妍。", "追隨剪吳江，送君翔九天。", "豈爲兒女情，戀戀祈恩憐。", "茲惟時多虞，活國資清賢。", "近者小司業，繇之入諫垣。"]'),
('a5aed400-51ee-4437-a4dd-9cf67440a292','古劍詞','趙孟堅','宋','宋诗','song-poetry','','[]','古劍三尺長，土花上鱗甲。',60,'全唐诗/poet.song.214000.json','["古劍三尺長，土花上鱗甲。", "幾年閉蟄藏，射斗光夜發。", "提携繞區市，鮮復事磨刮。", "嫖姚一拂拭，蛟斷犀可截。", "志士寧終窮，行逢達觀達。"]'),
('c918345c-dc41-47fe-a853-a74148d57183','曲澗','趙孟堅','宋','宋诗','song-poetry','','[]','山頭分兩崖，知有泉來處。',72,'全唐诗/poet.song.214000.json','["山頭分兩崖，知有泉來處。", "曲澗潄琮琤，夜來應驟雨。", "葉嫩明琉璃，藤生絡松樹。", "石脚漲所痕，莓苔濕無路。", "玩之室生白，明是春將暮。", "何當門對開，小結幽廬住。"]'),
('1905bb4d-8d01-4619-a49a-705e0a275ea6','江灣僧舍水石芭蕉','趙孟堅','宋','宋诗','song-poetry','','[]','老耳最怕風雨聲，芭蕉葉上聲偏鳴。',240,'全唐诗/poet.song.214000.json','["老耳最怕風雨聲，芭蕉葉上聲偏鳴。", "新枝日展翦不替，况見蕺蕺成添丁。", "呼童具鍤斲寒玉，蔓圖貴早除其萌。", "醜疑烏喙側著附，又訝蹲鴟不可羹。", "一笑翻成有料理，古盆石供泉清泠。", "黄梅彌旬雨霢霂，苔封沙擁生意成。", "小試抽書嚏撚細，鼠牙入水銀鬚生。", "漸離土性安臞瘠，淡與水石相忘形。", "巡除日課長養事，莖添葉比紛欹傾。", "炎威不到琉璃碧，水脈透尖珠貫縈。", "萼綠華仙斷火食，雲裾曳翠身輕盈。", "風軒暑簟足蕭爽，晴曦更有冬窗明。", "丁寧閉塞謹愛護，秋霜夜氣防憑凌。", "一年一年春風好，根株宛在葱蘢青。", "崇桃遮莫金壺貯，日暮隨風紅雨零。"]'),
('4a16aeba-cd9c-4f92-860e-1839ea2dc61a','登普滿塔','趙孟堅','宋','宋诗','song-poetry','','[]','海濱荒凉斗絕地，古寺窣堵標蒼旻。',160,'全唐诗/poet.song.214000.json','["海濱荒凉斗絕地，古寺窣堵標蒼旻。", "三面黄茅連巨浸，突立嵯峨超不羣。", "可憐前此無管領，欄干罩網蛛絲塵。", "相携暇日足登覽，晝長正度南風薰。", "冰盤朱李冷熨齒，雪絲細葛輕襯身。", "飲酣神王氣浩浩，半空笑語驚行人。", "墨圓新磨紺於漆，大字題成泣鬼神。", "交酬錯勸互賓主，雅論諧談肺腑真。", "觚稜掛月筵初散，歸從傳呼紛若雲。", "英游便可誇盛事，緇流勿訝吾來頻。"]'),
('820288eb-55fc-434f-9912-0a94683eb524','甲辰歲朝把筆','趙孟堅','宋','宋诗','song-poetry','','[]','四十五番見除夕，稍知慚愧此之日。',344,'全唐诗/poet.song.214000.json','["四十五番見除夕，稍知慚愧此之日。", "小時辛苦習科場，惟恐一官身未得。", "二十七歲方塵忝，又閲八年初實歷。", "又閲十年滿兩任，汲汲皇皇望通籍。", "况逾百指家累重，蔭贍浩穰憂不給。", "所以中心懷蹐跼，每至歲朝常戚戚。", "前年涉險趨淮幕，去年舉剡甫及格。", "猶自奔波趁班見，來往時時在塗陌。", "今年事定已改官，分邑不遠近鄉國。", "秋風行可報瓜熟，便得怡愉奉慈色。", "所以親邊知自幸，笑語團欒竟通夕。", "雖然丈夫致君澤民事業匪僅此，要是此去無限隔。", "但辦勞心供撫字，忠信尚可行蠻貊。", "斷不依阿事嫵媚，亦不聚歛求封殖。", "升而戾天沈而淵，一聽天公無固必。", "若綴班行儘向高，爐香夾侍螭坳側。", "剩擬抗論高回天，粗有外氏之遺策。", "或分一壘向邊疆，願作長城如李勣。", "霜臺直筆屏姦回，機幕飛毫草文檄。", "更令小試經綸手，黼黻曾夢江淹筆。", "不然種花蒔藥老海濱，却覓長年當官職。"]'),
('5668b591-548d-4cee-85fa-21b4da77e7ce','食雪','趙孟堅','宋','宋诗','song-poetry','','[]','君不見蘇子卿，十有九年留朔廷。',270,'全唐诗/poet.song.214000.json','["君不見蘇子卿，十有九年留朔廷。", "牧羝未乳歸未得，吞氈莫救饑腸鳴。", "又不見陶學士，家居三冬足文史。", "玉堂退直清興生，謾把烹茶誇婢子。", "我生徒飽太倉粟，慨懷伊人常縮恧。", "我才又無揮翰手，食此豈不顔增厚。", "浪游枉自在江湖，幾年見雪一語無。", "只同兒童跳梁喜，欲吟自覺腸乾枯。", "朔風打頭夜來泊，擁篷曉見銀糢糊。", "銀盤收拾和蔗漿，銀匙攪碎紅珊瑚。", "一抄入口清風生，再抄乍覺心眼明。", "連抄疾啜盤已竟，肌膚起粟神魂輕。", "食罷拱手謝蒼天，小儒不學食露盤，無補多慾妄求僊。", "願言片片皆詩料，吐吞造化歸毫端。", "亦不吟河橋送別凄凉句，亦不吟依本胡蘆取天怒。", "但願冰稜雪塊在心胸，飄飄解做梅花賦。"]'),
('ab3203b4-f16d-4f4f-8975-ce0916dbdba3','斬偶行','趙孟堅','宋','宋诗','song-poetry','','[]','君不見昌黎諫佛骨，竟莫遂請水火投。',139,'全唐诗/poet.song.214000.json','["君不見昌黎諫佛骨，竟莫遂請水火投。", "中丞擊妖蛇，此蛇初不爲民尤。", "寧如立斬興妖偶，卓哉偉見吾邦侯。", "吁嗟三輔州，尚鬼逾蠻酋。", "此輩生身已麗法，尚何智慧靈諸幽。", "惟伊姦兇愚爾俗，假憑威毒相仇讐。", "依乘土木作幻怪，竊取血味神其謀。", "除兇破僞砉一劍，較功韓孔茲爲優。", "嗟嗟願公寶此劍，更煩借截姦臣頭。"]'),
('fc6a6f3f-000a-4502-bf2b-d771cba3913f','送朱支倉試刑法科','趙孟堅','宋','宋诗','song-poetry','','[]','士業讀書讀律恥，亦不屑至其有以。',120,'全唐诗/poet.song.214000.json','["士業讀書讀律恥，亦不屑至其有以。", "男兒奮身自力耳，有足成功奚擇地。", "誦德科條似流水，筆端端可判生死。", "用之自貴勿輕視，贈君飽霜毫錐子，萬毫齊力鋒穎銳。", "庭陰未側可萬字，十問俱通策勳易。", "即次風雷星斗位，還取儒科濟世美。", "更贈一言君我記，終身行之恕而已。"]'),
('88f3925c-9420-4995-9e53-5b4e36163383','厖蚓圖','趙孟堅','宋','宋诗','song-poetry','','[]','一蚓蜿蜒行燥土，定是明朝天作雨。',64,'全唐诗/poet.song.214000.json','["一蚓蜿蜒行燥土，定是明朝天作雨。", "六厖酣憨初眈乳，乍見異物吠驚覩。", "老厖垂涎傍睨顧，此心亦以舐犢故。", "鶉衣百結多兒女，錦屏鴛帳輒獨處。"]'),
('1d63bb2a-5645-49c2-9afe-60504ac8479d','送馬上嬌圖與秋壑監丞','趙孟堅','宋','宋诗','song-poetry','','[]','繡韉金狨玉蹀躞，天寶繁奢逾大業。',146,'全唐诗/poet.song.214000.json','["繡韉金狨玉蹀躞，天寶繁奢逾大業。", "華清浴已宴沈香，弓箭才人擁旌節。", "前頭樂部紫雲回，催駕顒迎奏三疊。", "阿瞞駐轡立多時，欲上花驄尚嬌色。", "俯頭縋𩍐力士徒，曾以脫靴爲屑屑。", "步步相隨那肯離，嘗聞願作連理枝。", "燕安儻及思艱危，那有馬嵬攀訣時。", "漢家山河安四維，披香千秋惟弋綈。", "龍眠畫茲非衒奇，端與曹高向孟陳元龜。"]'),
('f654e2c6-9c45-4ad1-8e9b-ddda500866cc','秋壑納室慶席諸友分韻','趙孟堅','宋','宋诗','song-poetry','','[]','蘆葦戰風聲颯索，細雨吹絲冰簾箔。',64,'全唐诗/poet.song.214000.json','["蘆葦戰風聲颯索，細雨吹絲冰簾箔。", "暖盤醉客珠履喧，聳鸞筆飛璣唾落。", "詩人大義在切磋，曳裾彈鋏籍若何。", "正倫風化理不二，御邦即是家之和。"]'),
('44552d42-f4a1-4d87-ae94-4e2f57a86734','採桑曲','趙孟堅','宋','宋诗','song-poetry','','[]','桑椹紫來蠶務急，带曉採桑桑葉濕。',72,'全唐诗/poet.song.214000.json','["桑椹紫來蠶務急，带曉採桑桑葉濕。", "屋頭綠暗勃姑啼，柱礎朝朝汗流出。", "人家蠶老婦勤苦，銀釧忙催隔窗霧。", "方花古塼衮香絮，院靜簾垂明燕語，沉炷銷來烟半縷。"]'),
('958c80c3-d9a2-4f16-ba64-b00262455ba6','賣鏡','趙孟堅','宋','宋诗','song-poetry','','[]','賣明鏡，怕明鏡。',56,'全唐诗/poet.song.214000.json','["賣明鏡，怕明鏡。", "從來面瘦兩高顴，况復星星添鬢影。", "世間萬事只宜晦，明鏡何須炯相對。", "鏡明賣却昏不磨，從教雙鬢雪婆娑。"]'),
('62e670bc-6d71-4a5e-aed8-e0ed6e557f07','青春能幾何  其一','趙孟堅','宋','宋诗','song-poetry','','[]','青春能幾何，青春能幾何。',92,'全唐诗/poet.song.214000.json','["青春能幾何，青春能幾何。", "蒼髯紺髮看成皤，亦有紅顔嫩於花，東風馳道屬誰家。", "可道光陰流電轉，草上霜飛峭如翦。", "心如不知恍重見，心語不通惟見面。", "重見面，愁轉多。", "歸來銀燭炯長夜，歎息青春能幾何。"]'),
('2fdecc21-0742-43f6-b2a8-d28fd4f9db4e','青春能幾何  其二','趙孟堅','宋','宋诗','song-poetry','','[]','青春能幾何，青春能幾何。',97,'全唐诗/poet.song.214000.json','["青春能幾何，青春能幾何。", "日烏月兔去如梭，膠粘難安枝上花。", "頗惜相逢殊草草，中心有言不復道。", "鵲喜傳訛易顛倒，想得也應生懊惱。", "謾自有千金，無方駐臉霞。", "休言洛陽看花伴，經年浪蕩不歸家。", "君不見青春能幾何。"]'),
('1803dd04-2e29-4aff-a15c-732234a3d2ef','二禽言戲贈難弟 歸歸歸','趙孟堅','宋','宋诗','song-poetry','','[]','歸歸歸，三月將盡方始啼。',84,'全唐诗/poet.song.214000.json','["歸歸歸，三月將盡方始啼。", "木林翠密陰成幄，花片紅嫣風蕩飛。", "歸歸歸，汝既勸歸胡不歸。", "歸來深院日正長，煮酒菖蒲玉屑香。", "醉眠藤牀覺晚凉，須臾月色到回廊。", "歸歸歸，真箇歸來樂未央。"]'),
('3efbec7d-5c3c-46ee-a310-941818a98324','二禽言戲贈難弟 篤篤篤','趙孟堅','宋','宋诗','song-poetry','','[]','篤篤篤，日長正午睡初熟。',80,'全唐诗/poet.song.214000.json','["篤篤篤，日長正午睡初熟。", "誰其扣門訪幽獨，見他利喙啄枯木。", "枯木中間能有幾，小蟲何足飽爾腹，盡日勞苦食不足。", "篤篤篤，此聲尚且聒人耳，人之多言寧不瀆。", "戒之哉，篤篤篤。"]'),
('8679a5ae-3e85-4d13-9845-6993464792ec','庚辰除夕','趙孟堅','宋','宋诗','song-poetry','','[]','生計從來拙，奚疑壁四空。',48,'全唐诗/poet.song.214000.json','["生計從來拙，奚疑壁四空。", "解憂惟父母，謀事等兒童。", "無競身如偶，訛言耳願聾。", "丈夫心鐵石，肯自泣塗窮。"]'),
('dbfcfc9a-9df4-4d14-9eab-04172e778b5a','辛巳除夕','趙孟堅','宋','宋诗','song-poetry','','[]','歲事今其暮，而多悵惋心。',48,'全唐诗/poet.song.214000.json','["歲事今其暮，而多悵惋心。", "功名一成否，身世幾浮沉。", "荄甲四牆在，根株百蠹侵。", "白雲飛處遠，東望動微吟。"]'),
('b78760f2-d56c-4ec8-819a-6fb2ecd93c75','山行晚歸','趙孟堅','宋','宋诗','song-poetry','','[]','背日踏寒影，歸程路覺長。',48,'全唐诗/poet.song.214000.json','["背日踏寒影，歸程路覺長。", "水流逢石響，花晚度秋香。", "前去多林莽，新傳有虎狼。", "行行應勿緩，掠面已風霜。"]'),
('88b41ff6-05f0-4a43-9baf-f4938be7f347','尤美亭','趙孟堅','宋','宋诗','song-poetry','','[]','雖未及瑯琊，看來亦自佳。',48,'全唐诗/poet.song.214000.json','["雖未及瑯琊，看來亦自佳。", "微坳著新月，聳翠带餘霞。", "巨鑿應靈禹，斜拋或女媧。", "小亭相對好，莫放竹叢遮。"]'),
('ed602f99-a72f-4df5-aca7-9fb7c5501ea1','夜熱','趙孟堅','宋','宋诗','song-poetry','','[]','夜熱寢復起，獨行池上亭。',48,'全唐诗/poet.song.214000.json','["夜熱寢復起，獨行池上亭。", "欹荷傾泫露，高柳掛疎星。", "秋蛩已啼草，涸魚時唼萍。", "無雲那有雨，湛湛一天青。"]'),
('dd02282a-d29a-4506-9196-9d09438f5ed5','蒙齋','趙孟堅','宋','宋诗','song-poetry','','[]','此閟先天地，名齋曷扁蒙。',48,'全唐诗/poet.song.214000.json','["此閟先天地，名齋曷扁蒙。", "祇應防太潔，未必果冬烘。", "釀臈重醅酒，初陽逗煖風。", "當年郭有道，此意與君同。"]'),
('aa5bfaad-2641-4b56-8db2-dd6e3dd33a70','文宣公祠宇新成','趙孟堅','宋','宋诗','song-poetry','','[]','旋斲蓱蕪地，亭臺出水瀕。',48,'全唐诗/poet.song.214000.json','["旋斲蓱蕪地，亭臺出水瀕。", "人知便行樂，誰識念賢臣。", "淡月花無影，微風浪有鱗。", "飛梁如跨水，遊子更來頻。"]'),
('3168dc0f-1ec1-43b0-a4bc-5326284b36e7','何氏書堂','趙孟堅','宋','宋诗','song-poetry','','[]','元正假得晴，野服暫山行。',48,'全唐诗/poet.song.214000.json','["元正假得晴，野服暫山行。", "遇石松盤蓋，懸崖蘭倒生。", "壁間題字古，潭面鑒形清。", "官滿應求此，讀書秋月明。"]'),
('14dc6d7d-08c5-4f95-9bac-eeecd8acdba1','鴻禧觀次高橫槎韻  其一','趙孟堅','宋','宋诗','song-poetry','','[]','逍遥微物累，出處任天真。',48,'全唐诗/poet.song.214000.json','["逍遥微物累，出處任天真。", "薄宦已陳夢，青山猶故人。", "鑑湖凉不暑，荷葉浄無塵。", "往往入圖畫，扣舷欹角巾。"]'),
('f390e828-69cd-4a0d-879a-f2a58a85b7dc','鴻禧觀次高橫槎韻  其二','趙孟堅','宋','宋诗','song-poetry','','[]','秦望與蘭亭，山山遞送迎。',48,'全唐诗/poet.song.214000.json','["秦望與蘭亭，山山遞送迎。", "蓴鱸方嫩美，草木亦欣榮。", "去繼漢疏傅，名肩齊魯生。", "鴻都讀遺事，誰不動歸情。"]'),
('9add501a-a8d8-402a-9182-45e26e3a5a00','和陳魯山社日西湖二首  其一','趙孟堅','宋','宋诗','song-poetry','','["\u897f\u6e56"]','遶堤千障碧，過雨一回新。',48,'全唐诗/poet.song.214000.json','["遶堤千障碧，過雨一回新。", "並駕館中傑，分題湖上春。", "杯觴同臭味，篇什倍精神。", "招手年時燕，遄歸尚及辰。"]'),
('5697e31c-7c37-4195-ae2e-ea5b58f5b619','和陳魯山社日西湖二首  其二','趙孟堅','宋','宋诗','song-poetry','','["\u897f\u6e56"]','海棠料客醉，故作暈微紅。',48,'全唐诗/poet.song.214000.json','["海棠料客醉，故作暈微紅。", "借路山無雨，惜花天不風。", "揚鑣聯勝士，琢句策奇功。", "讀罷身何許，晴光蕩漾中。"]'),
('7015807d-3dff-4864-971b-ab6dc5858e3d','江樓遲客','趙孟堅','宋','宋诗','song-poetry','','[]','野外遊神迥，望中塵物稀。',48,'全唐诗/poet.song.214000.json','["野外遊神迥，望中塵物稀。", "天連遠水盡，鳥背夕陽飛。", "木葉初摇落，鄉懷動式微。", "興闌不忍去，遲子一舠歸。"]'),
('1ce20aea-6f95-4072-9840-5168d1cbbfab','早春牡丹','趙孟堅','宋','宋诗','song-poetry','','[]','香泥封籜接頭新，幻出花王見早春。',64,'全唐诗/poet.song.214000.json','["香泥封籜接頭新，幻出花王見早春。", "時節不須寒食候，工夫遠勝洛陽人。", "嫩黄蠟葉拳微皺，半醉宮粧粉未勻。", "恐怕晚風須愛護，羅幃遮却看頻頻。"]'),
('cff42d6d-f781-450a-be2d-6dd513bfd15e','安吉州賦牡丹','趙孟堅','宋','宋诗','song-poetry','','[]','眼眩繁妍錦一機，銅缾分插遞參差。',64,'全唐诗/poet.song.214000.json','["眼眩繁妍錦一機，銅缾分插遞參差。", "幾於飣坐看如偶，却爲輕寒謝較遲。", "售用奢豪須藉酒，形容妖艷每難詩。", "微風忽度輕披展，絕憶霓裳駐拍時。"]'),
('0dc46ecc-ded2-43ac-8d89-0aebac6c2368','謝徐正十一兄惠牡丹顔帖','趙孟堅','宋','宋诗','song-poetry','','[]','左携珍帖右花王，雅貺何殊照乘光。',64,'全唐诗/poet.song.214000.json','["左携珍帖右花王，雅貺何殊照乘光。", "拆壁漏痕含蠆尾，珍珠露顆带天香。", "數千葉密憐檀暈，怕六丁收謹匣藏。", "答謝苦慚無好語，撚髭空斷不成章。"]'),
('ec2d69e3-e7d5-4f2b-93bb-27341024ab71','種水芭蕉','趙孟堅','宋','宋诗','song-poetry','','[]','石上芭蕉手自移，黄梅便得雨如期。',64,'全唐诗/poet.song.214000.json','["石上芭蕉手自移，黄梅便得雨如期。", "水根聯絡銀絲漾，風葉紛抽羽扇欹。", "日驗發生疑有準，心加愛護每忘疲。", "猶如老大初生子，及見成人長立時。"]'),
('954d7d67-0954-4c4a-83dc-bddc9ae0abb9','初冬客中見小春海棠','趙孟堅','宋','宋诗','song-poetry','','[]','一痕朝日界晴窗，森肅清寒昨夜霜。',64,'全唐诗/poet.song.214000.json','["一痕朝日界晴窗，森肅清寒昨夜霜。", "硯怕生澌微貯水，爐因撥火起餘香。", "最耽詩帖閑中樂，無奈塵埃客裏忙。", "却是小春花謝絕，海棠經月駐紅粧。"]'),
('dd6bdf8b-a4bc-4463-aee9-e399969cd7a5','客中','趙孟堅','宋','宋诗','song-poetry','','[]','睡覺簷牙月一鈎，適閑真不願封侯。',64,'全唐诗/poet.song.214000.json','["睡覺簷牙月一鈎，適閑真不願封侯。", "病多藥裹長爲侶，靜著爐薰轉更幽。", "席上眼明梅破臘，霜餘珍重菊經秋。", "從茲可向家居否，强半經年在客舟。"]'),
('80af81d5-4113-432b-9657-059a14042dec','和帑院叔','趙孟堅','宋','宋诗','song-poetry','','[]','久居朝蹟遲遷次，雖在琴齋頗寂寥。',64,'全唐诗/poet.song.214000.json','["久居朝蹟遲遷次，雖在琴齋頗寂寥。", "交少自應無援拔，地寒安得有肥饒。", "桃花落處春風緊，梅蘂開時臘雪銷。", "畢竟徐行能遠到，樽前贏得且逍遥。"]'),
('1a7fbe61-6e16-403a-a62f-d69c017396b5','及書六考喜效白體','趙孟堅','宋','宋诗','song-poetry','','[]','無庸下考又三書，知愧知慚意少舒。',64,'全唐诗/poet.song.214000.json','["無庸下考又三書，知愧知慚意少舒。", "儻便盍簪叨墨綬，縱然休仕亦緋魚。", "何人不願重金服，那箇無心駟馬車。", "修短洪纖應賦定，好存方寸一由渠。"]'),
('ed9f0b35-b530-4e4d-8eca-27e2ef16d6d4','不寐','趙孟堅','宋','宋诗','song-poetry','','[]','不夢華胥仍不醉，燈青室白自高眠。',64,'全唐诗/poet.song.214000.json','["不夢華胥仍不醉，燈青室白自高眠。", "頻聞乾葉下空砌，遥認征鴻唳遠天。", "慮淡殊非同槁木，無營豈復在齠年。", "回思撲漉紅塵久，虧損工夫只自憐。"]'),
('3d0a789f-a846-4e38-b638-f59fd44dcaa7','邑圃池上','趙孟堅','宋','宋诗','song-poetry','','[]','南薰初愛葉田田，忽見莖枯欲倒懸。',64,'全唐诗/poet.song.214000.json','["南薰初愛葉田田，忽見莖枯欲倒懸。", "風露漸凄生澹泊，水天相映作澄鮮。", "無人領會微吟意，獨自咿唔薄暮天。", "一對陶朱山下鷺，飛飛衝破晚炊烟。"]'),
('fc5d8eb6-f735-46bb-a449-6c7c90d69f9d','養鸂鶒','趙孟堅','宋','宋诗','song-poetry','','[]','護毛不用籠寬織，半殺彫翎養自馴。',64,'全唐诗/poet.song.214000.json','["護毛不用籠寬織，半殺彫翎養自馴。", "退易進難微鶴歎，凉來炎去異鴻賓。", "橫枝梅下眠和月，臨水薇邊遊近人。", "更著花栽安蘚石，黄筌圖畫鎮長新。"]'),
('1bf71441-8825-44bd-917b-dfb05d660a82','十日同憲僚登高','趙孟堅','宋','宋诗','song-poetry','','[]','自嘆凄凉客寄身，已孤茱酒奉慈親。',64,'全唐诗/poet.song.214000.json','["自嘆凄凉客寄身，已孤茱酒奉慈親。", "未應一夜無芳菊，共上層樓有可人。", "日射寒山宜近晚，霜殷秋葉艷於春。", "清歡率爾吾儕事，帽落龍山意更真。"]'),
('fc88d89a-17ba-4cf4-9279-ba8b74d36d2d','讀元舅雪溪先生墓銘','趙孟堅','宋','宋诗','song-poetry','','[]','二祖霜臺有烈聲，傳家文憲見先生。',64,'全唐诗/poet.song.214000.json','["二祖霜臺有烈聲，傳家文憲見先生。", "剛而不折松筠壽，貧弗濫求冰玉清。", "陶令秫田詩料足，竇家桂子義方成。", "即茲更有高賢傳，豈羨區區世上名。"]'),
('5236f833-c737-4f26-8395-cdc3a5db8b91','拜掃易齋先生墓  其一','趙孟堅','宋','宋诗','song-poetry','','[]','行樂今非少壯時，一樽聊以酹吾師。',64,'全唐诗/poet.song.214000.json','["行樂今非少壯時，一樽聊以酹吾師。", "隻雞豈敢方前輩，下馬猶能慰所思。", "原上松杉新種植，望中桃李半披離。", "歸途劇飲賡新句，顛倒綸巾不自持。"]'),
('cbf605dc-d54f-4547-8376-827d27c0787f','拜掃易齋先生墓  其二','趙孟堅','宋','宋诗','song-poetry','','[]','隻雞斗酒禮雖微，苦雨終風志不移。',64,'全唐诗/poet.song.214000.json','["隻雞斗酒禮雖微，苦雨終風志不移。", "卧病已辜寒食約，踐盟猶及小春時。", "老懷傷感渾如舊，同舍追陪尚可期。", "少憩東湖勿怱遽，片雲來往正催詩。"]'),
('67af7f49-6b71-49fd-86c7-098f8f327916','寄湯帳幹','趙孟堅','宋','宋诗','song-poetry','','[]','鎖窗寂寞守燈熒，熟數陳蹤迹杳冥。',64,'全唐诗/poet.song.214000.json','["鎖窗寂寞守燈熒，熟數陳蹤迹杳冥。", "已自無心雲淡淡，不應逐計鼠營營。", "發生最普惟春力，幽隠旁昭是月明。", "試品梅花霜下角，動人深淺似秦箏。"]'),
('85217f65-442b-42e9-9c8b-8a72f39dab62','招石希孟朝飯','趙孟堅','宋','宋诗','song-poetry','','[]','水臨軒檻絕纖埃，砌面茸茸上綠苔。',64,'全唐诗/poet.song.214000.json','["水臨軒檻絕纖埃，砌面茸茸上綠苔。", "伺餧金鱗渾可狎，低飛翠羽不生猜。", "篆薰欲起筵初集，清磬纔敲夢恰回。", "正好西風坐蕭爽，官程翻怕驛書催。"]'),
('e290130d-88b7-43b9-8e61-acff154d752a','與帥幹架閣宗叔','趙孟堅','宋','宋诗','song-poetry','','[]','曾聞老吏說先猷，咳唾珠璣下筆遒。',64,'全唐诗/poet.song.214000.json','["曾聞老吏說先猷，咳唾珠璣下筆遒。", "大器莫爲時所用，高科還有子能收。", "相逢禹會嗟何晚，薄可郊寒匪暗投。", "珍重斯文肯勉力，清朝墳典要人修。"]'),
('2ed4ec56-a9aa-48b0-9f0b-c577d9143b8c','寓言','趙孟堅','宋','宋诗','song-poetry','','[]','詡詡言詞巷陌兒，傾心反目易安危。',64,'全唐诗/poet.song.214000.json','["詡詡言詞巷陌兒，傾心反目易安危。", "可嗟香盡蝶猶戀，誰謂機萌鷗不知。", "寥落丹青秋後扇，縱橫黑白局中碁。", "料應主意非疎賈，其奈難祛絳灌疑。"]'),
('6507f495-4e62-4de2-92c3-330b73c715fd','追詠西湖行樂寄傅清叔','趙孟堅','宋','宋诗','song-poetry','','["\u897f\u6e56"]','聞借侯家宅，湖邊度夏凉。',216,'全唐诗/poet.song.214000.json','["聞借侯家宅，湖邊度夏凉。", "鐘魚連梵寺，雉堞傍城牆。", "閑適心無事，清和日正長。", "藕花雖尚稚，荷葉自多香。", "苦笋回餘味，青梅弄半黄。", "生綃畫團扇，細葛製輕裳。", "水近風生座，簷虛月滿廊。", "龍舟花槳榾，騮馬紫絛韁。", "竟日歌聲沸，通宵水面光。", "不妨投轄飲，更稱靜琴張。", "詩社聯行卷，仙姝學道粧。", "英遊伴王謝，清夢到羲皇。", "曾約陪遊蓋，慚稽動客檣。", "憶君成悵望，爲我細思量。", "幾度吟成後，憑誰遠寄將。", "意多收不盡，事鄙每牽忙。", "今夕微醺起，中宵捉筆狂。", "浪吟無次第，聊表未遺忘。"]'),
('a13dc45e-8fc8-42f4-8c75-3e6878af5464','九里松馬上作','趙孟堅','宋','宋诗','song-poetry','','[]','九里松株不斷青，松風上發下泉聲。',32,'全唐诗/poet.song.214000.json','["九里松株不斷青，松風上發下泉聲。", "耳邊爲愛聞天籟，故約遊韁緩緩行。"]'),
('49844d65-74e8-4d8b-b9b1-687d97169a99','送客','趙孟堅','宋','宋诗','song-poetry','','[]','素娥懶駕水晶輪，此夕飛來夜欲分。',32,'全唐诗/poet.song.214000.json','["素娥懶駕水晶輪，此夕飛來夜欲分。", "送客出門還獨立，一天清露湛無雲。"]'),
('c01cee24-df17-4e4d-bc57-67d4bc5ac19c','臨安客中','趙孟堅','宋','宋诗','song-poetry','','[]','小樓面面著疎櫺，靜有蟾光絕市聲。',32,'全唐诗/poet.song.214000.json','["小樓面面著疎櫺，靜有蟾光絕市聲。", "讀罷離騷臨晉帖，菊花香裏數寒更。"]'),
('5002c6ed-1797-438a-9166-dff9fc3f3b0c','折枝','趙孟堅','宋','宋诗','song-poetry','','[]','奚囊金勒逗春行，醉咏歸來隴月生。',32,'全唐诗/poet.song.214000.json','["奚囊金勒逗春行，醉咏歸來隴月生。", "折得生香渾懶向，斷簪零珥任縱橫。"]'),
('0415af79-3a0e-4f76-a685-60253fc2c143','清明','趙孟堅','宋','宋诗','song-poetry','','[]','節近清明長是陰，黄花間在麥苗深。',32,'全唐诗/poet.song.214000.json','["節近清明長是陰，黄花間在麥苗深。", "倦行却上高樓望，烟鎖前村一半林。"]'),
('5f83f548-fd9f-4724-a4e4-4fc749b516c4','經過','趙孟堅','宋','宋诗','song-poetry','','[]','二十年前漫浪遊，海天霜氣夜深浮。',32,'全唐诗/poet.song.214000.json','["二十年前漫浪遊，海天霜氣夜深浮。", "竹窗夢斷聞雞處，常憶溪灣塢聚頭。"]'),
('a4e69efa-0e8c-4e7c-8a8d-bb818860d6a8','南林張園','趙孟堅','宋','宋诗','song-poetry','','[]','凄凄寒菊委霜叢，下有微吟腐葉蛩。',32,'全唐诗/poet.song.214000.json','["凄凄寒菊委霜叢，下有微吟腐葉蛩。", "倚著欄干聽不了，自來我輩最情鍾。"]'),
('512f1283-7145-4d5d-b0fd-37bf69abf01f','種石菖蒲','趙孟堅','宋','宋诗','song-poetry','','[]','少年眼力健觀書，卷裏千言一覽無。',32,'全唐诗/poet.song.214000.json','["少年眼力健觀書，卷裏千言一覽無。", "官事簿書昏惘惘，效尤石上種菖蒲。"]'),
('c595cbcf-9d17-4f40-8d0c-a49d7c0e1b12','蕙花','趙孟堅','宋','宋诗','song-poetry','','[]','光風蕩煖曉晴天，雅有幽香入簡編。',32,'全唐诗/poet.song.214000.json','["光風蕩煖曉晴天，雅有幽香入簡編。", "尋見野花都不是，山蜂引到石崖邊。"]'),
('3d6dd853-6f3e-4ff1-88cc-25b8033ed0b0','夢回','趙孟堅','宋','宋诗','song-poetry','','[]','點點桃花短短牆，雨聲徹夜響迴廊。',32,'全唐诗/poet.song.214000.json','["點點桃花短短牆，雨聲徹夜響迴廊。", "覺來蝴蝶家山夢，一半分明一半忘。"]'),
('8939ac03-2d6b-45bb-b7a0-c229d4b77371','贈術者','趙孟堅','宋','宋诗','song-poetry','','[]','紛紛塵土簿書堆，職在其間怎可辭。',32,'全唐诗/poet.song.214000.json','["紛紛塵土簿書堆，職在其間怎可辭。", "不向先生問榮達，但言何日是閑時。"]'),
('843e8859-1b90-489d-a9a6-7f79c3ddb92c','買硯碑  其一','趙孟堅','宋','宋诗','song-poetry','','[]','鳳城凉雨新秋後，幾處朱樓試管弦。',32,'全唐诗/poet.song.214000.json','["鳳城凉雨新秋後，幾處朱樓試管弦。", "有客貰金收古歙，短檠竟夕自摩研。"]'),
('839f99e4-aa15-4976-b8f7-7231138e77bc','買硯碑  其二','趙孟堅','宋','宋诗','song-poetry','','[]','恰在貰金醉硯直，又逢古洛蔡公碑。',32,'全唐诗/poet.song.214000.json','["恰在貰金醉硯直，又逢古洛蔡公碑。", "摩挲不忍教他去，笑殺典衣償直時。"]'),
('6e8b8e06-3d4b-4dad-885a-2137b157da74','問梅寄賈秋壑先生','趙孟堅','宋','宋诗','song-poetry','','[]','生成欲見化工功，不在漫山桃李中。',32,'全唐诗/poet.song.214000.json','["生成欲見化工功，不在漫山桃李中。", "爲向梅梢問消長，地寒先却得春風。"]'),
('75ed0799-c0e9-4042-8d4b-44692b731ad8','天平方丈梅下見持要舊題','趙孟堅','宋','宋诗','song-poetry','','[]','枯梅一樹半斜欹，繞匝行行欲詠詩。',32,'全唐诗/poet.song.214000.json','["枯梅一樹半斜欹，繞匝行行欲詠詩。", "忽覿季難遺墨在，西風吹淚滿髯絲。"]'),
('d5b52ab6-0ce1-418f-be4e-68be1f2aaac5','謝送牡丹  其一','趙孟堅','宋','宋诗','song-poetry','','[]','官舍無花甑有塵，縱將畫展不如真。',32,'全唐诗/poet.song.214000.json','["官舍無花甑有塵，縱將畫展不如真。", "若非折寄珍珠顆，幾是蕭條過一春。"]'),
('6fcd173b-c4c6-43f6-bbb3-c368b965c88a','謝送牡丹  其二','趙孟堅','宋','宋诗','song-poetry','','[]','蘸蠟封枝翦處新，開奩带露尚精神。',32,'全唐诗/poet.song.214000.json','["蘸蠟封枝翦處新，開奩带露尚精神。", "洛陽路遠風塵暗，腸斷應無做譜人。"]'),
('aab6a9ee-64c7-4d50-ad33-de5b7d6ecf81','高渭南席上燭照牡丹  其一','趙孟堅','宋','宋诗','song-poetry','','[]','高燒燭照御黄衣，疑是沈香夜宴歸。',32,'全唐诗/poet.song.214000.json','["高燒燭照御黄衣，疑是沈香夜宴歸。", "固是不教花睡著，只愁驚起露蟬飛。"]'),
('47839010-e25a-4c60-8b07-ba3a0d5b02fb','高渭南席上燭照牡丹  其二','趙孟堅','宋','宋诗','song-poetry','','[]','日午貓睛一線時，紅嫣紫媚正猖披。',32,'全唐诗/poet.song.214000.json','["日午貓睛一線時，紅嫣紫媚正猖披。", "爭如絳蠟通宵照，玉葉金鬚色愈滋。"]'),
('9b03f0a9-5cc8-4029-8b59-40e10d48f87a','題玉川月蝕詩後','趙孟堅','宋','宋诗','song-poetry','','[]','哆口搘牙月蝕詩，遺編讀著凜風規。',32,'全唐诗/poet.song.214000.json','["哆口搘牙月蝕詩，遺編讀著凜風規。", "如何晚節從汙合，竟與姦臣血作泥。"]'),
('508de0c9-5b12-4f17-a0c2-1a041c68b487','題趙大年小景  其一','趙孟堅','宋','宋诗','song-poetry','','[]','霜輕榆柳未全黄，兩岸菰蒲洲渚長。',32,'全唐诗/poet.song.214000.json','["霜輕榆柳未全黄，兩岸菰蒲洲渚長。", "鷗鳥背人飛撲漉，西風嘗是入斜陽。"]'),
('65820f52-56ec-411e-80fb-af5bb3bd879a','題趙大年小景  其二','趙孟堅','宋','宋诗','song-poetry','','[]','一行白鷺過前山，飛去沙鷗半復還。',32,'全唐诗/poet.song.214000.json','["一行白鷺過前山，飛去沙鷗半復還。", "更有精能君見否，黄鸝兩兩綠楊間。"]'),
('ce2c31fa-c7cc-48a7-b674-78a366043583','客中思家  其一','趙孟堅','宋','宋诗','song-poetry','','[]','微風過處有清香，知是荼䕷隔短牆。',32,'全唐诗/poet.song.214000.json','["微風過處有清香，知是荼䕷隔短牆。", "相得故園成索寞，詩盟誰復爲平章。"]'),
('1f86386d-2879-47a2-b6f2-fa18c759ab3f','客中思家  其二','趙孟堅','宋','宋诗','song-poetry','','[]','楚楚輕衫翦薄紗，而今憶得在山家。',32,'全唐诗/poet.song.214000.json','["楚楚輕衫翦薄紗，而今憶得在山家。", "蕭娘爲是親蠶事，嗔带含香紫笑花。"]'),
('b00ac1a9-d892-46cf-9117-6deaca2bc031','客中思家  其三','趙孟堅','宋','宋诗','song-poetry','','[]','柳絮悠悠拂面輕，隨風到處若爲情。',32,'全唐诗/poet.song.214000.json','["柳絮悠悠拂面輕，隨風到處若爲情。", "西池應也無人到，一面青青萍自生。"]'),
('d521d24a-93ae-45f9-989a-d509dd1f1742','里中康節庵畫墨梅求詩因述本末以示之','趙孟堅','宋','宋诗','song-poetry','','[]','逃禪祖花光，得其韻度之清麗。',236,'全唐诗/poet.song.214000.json','["逃禪祖花光，得其韻度之清麗。", "節庵紹逃禪，得其蕭散之布置。", "回觀玉面而鼠鬚，已見工夫較精緻。", "雙枝倒作鹿角曲，生意由來端若爾。", "所傳正統諒末節，捨此的傳皆僞耳。", "僧花工之工則麤，夢良意到工則未。", "女中却有鮑夫人，能守師繩不輕墜。", "可憐聞名不識面，云有江西陸公濟。", "季衡麤醜惡拙祖，弊到雪篷濫觴矣。", "所恨二王無巨法，多少東鄰擬西子。", "是中有趣豈不傳，要以眼力求其旨。", "踢鬚正七萼則三，點眼名椒梢鼠尾。", "枝分三疊墨濃淡，花有正背多般蕊。", "夫君固已悟筌蹄，重說偈言吾亦贅。", "誰家屏障得君畫，更以吾詩跋其底。"]'),
('81f02731-258b-45e0-8507-d4261167277b','康不領此詩又有許梅谷者仍求再賦長律','趙孟堅','宋','宋诗','song-poetry','','[]','濃寫花枝淡寫梢，鱗皴老幹墨微焦。',160,'全唐诗/poet.song.214000.json','["濃寫花枝淡寫梢，鱗皴老幹墨微焦。", "筆頭三踢攢成瓣，珠暈一圓工點椒。", "粧綴蜂鬚擬笑靨，穩拖鼠尾施長條。", "盡吹花側風初急，猶带枝頭雪未消。", "松竹襯時明掩映，水波浮處見飄颻。", "黄昏時候朦朧月，清淺溪山長短橋。", "閙裏相挨如有意，靜中背立似無聊。", "筆端的皪明非畫，軸上縱橫不是描。", "頓覺坐來春盎盎，因思行過雨瀟瀟。", "從頭總是湯楊法，拚下工夫豈一朝。"]'),
('0bf71e8d-8237-4d4d-aeef-5ae7c2d755e9','王翠巖寫竹求詩','趙孟堅','宋','宋诗','song-poetry','','[]','古畫畫物無定形，隨物賦形皆逼真。',116,'全唐诗/poet.song.214000.json','["古畫畫物無定形，隨物賦形皆逼真。", "其次祖述有師繩，如印印泥隨前人。", "尚疑屋下重作屋，參以新意意乃足。", "晉魏而來幾百年，羲獻斷絃誰解續。", "何况高束李杜編，江湖競賣新詩讀。", "願君種取渭川一千畝，飽飯逍遥步捫腹。", "風晴烟雨盡入君心胸，吐出毫端自森肅。"]'),
('3c3bad00-f0f4-426b-a64d-9c8f66a24abe','題水仙','趙孟堅','宋','宋诗','song-poetry','','[]','自欣分得櫧山邑，地近錢塘易買花。',64,'全唐诗/poet.song.214000.json','["自欣分得櫧山邑，地近錢塘易買花。", "堆案文書雖鞅掌，簪瓶金玉且奢華。", "酒邊已愛香風度，燭下獨憐舞影斜。", "礬弟梅兄來次第，攙春熱閙令君家。"]'),
('91f3e311-5f58-4330-b580-e314207a7d28','夜泊法忍寺','趙孟堅','宋','宋诗','song-poetry','','[]','秋泊禪扉夜，清吟入興頻。',48,'全唐诗/poet.song.214000.json','["秋泊禪扉夜，清吟入興頻。", "風生水鱗甲，雲放月精神。", "禪有機鋒祕，詩無句法新。", "舊題尋不見，吹遍壁間塵。"]'),
('cc60afc8-add3-43f1-8498-bca5b39a6795','題墨蘭圖','趙孟堅','宋','宋诗','song-poetry','','[]','六月衡湘暑氣蒸，幽香一噴冰人清。',32,'全唐诗/poet.song.214000.json','["六月衡湘暑氣蒸，幽香一噴冰人清。", "曾將移入浙西種，一歲纔華一兩莖。"]'),
('6e79f8de-391e-4c3d-a6cd-61e6938a579f','牆頭花','趙孟堅','宋','宋诗','song-poetry','','[]','牆頭花，紅且白。',92,'全唐诗/poet.song.214000.json','["牆頭花，紅且白。", "一百五日過寒日，寒食過了好風日。", "風又吹，日又炙。", "枝頭好花盡狼藉，人生百年罕七十。", "愚者見花不知惜，我輩看花常唧唧。", "有酒莫停杯，當歌莫停拍。", "頭上絲絲霜雪來，老大見花方歎息。"]'),
('93e75260-e4b8-4732-b403-766ffbedb939','題高氏烟雨館  其一','趙孟堅','宋','宋诗','song-poetry','','[]','溟溟復靄靄，極望欲無涯。',48,'全唐诗/poet.song.214000.json','["溟溟復靄靄，極望欲無涯。", "村遠如相合，天底若四垂。", "櫓聲因濕小，塔影被雲欺。", "不但長烟雨，陰晴有間時。"]'),
('86d58f74-a00a-4f78-b6ee-be0dec0d04ca','題高氏烟雨館  其二','趙孟堅','宋','宋诗','song-poetry','','[]','人多晴晝至，此趣未應知。',48,'全唐诗/poet.song.214000.json','["人多晴晝至，此趣未應知。", "我獨身常寓，烟霏雨暗時。", "曀添波面闊，綠壓柳絲垂。", "忽有片帆過，驚飛雙鷺鷥。"]'),
('1f479f0e-4d60-4c14-bd68-e7132f1175a6','題照禪師道場','趙孟堅','宋','宋诗','song-poetry','','[]','重到招提十七年，吟題墨色又成嫣。',64,'全唐诗/poet.song.214000.json','["重到招提十七年，吟題墨色又成嫣。", "蟠虯老檜枝垂舞，像刻前碑石載鎸。", "留賦縱然常滿壁，玄機竟莫悟枯禪。", "道場法子叢居盛，奚復蘆花施釣船。"]'),
('62cc3e42-615a-4848-9d57-6184e815cac5','道愛堂','孫夢觀','宋','宋诗','song-poetry','','[]','多幸廛居辱鎮臨，政平底用減科箴。',64,'全唐诗/poet.song.214000.json','["多幸廛居辱鎮臨，政平底用減科箴。", "昔聞偃室絃歌化，今見邦君撫字心。", "簾度荷香供永晝，水寒山影瀉清音。", "從來縣譜無他事，祇說恩波一脈深。"]'),
('913f2e26-dedb-4c05-b708-b02bcee1f728','橘二首  其一','趙與{𥫗/？/心}','宋','宋诗','song-poetry','','[]','野色烟波外，西風橘柚香。',48,'全唐诗/poet.song.214000.json','["野色烟波外，西風橘柚香。", "湖光杳無際，山色忽深藏。", "塔古燈猶照，壇餘竈已荒。", "何當蛻塵鞅，從此訪漁郎。"]'),
('103404ae-64bd-4fda-a01b-58e79517471b','橘二首  其二','趙與{𥫗/？/心}','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','倦客滄浪意，扁舟汗漫遊。',48,'全唐诗/poet.song.214000.json','["倦客滄浪意，扁舟汗漫遊。", "雲歸林屋晚，木落洞庭秋。", "此地真堪老，中原卒未休。", "可知侯萬戶，不似橘千頭。"]'),
('5bab60a4-6f0d-418b-9dc1-da759cd7e5e1','桐','趙與{𥫗/？/心}','宋','宋诗','song-poetry','','[]','晚來狂索酒，量大酒無功。',48,'全唐诗/poet.song.214000.json','["晚來狂索酒，量大酒無功。", "窗豁能容月，樓高易得風。", "碎聲聞蟋蟀，疎影舞梧桐。", "夜半成清夢，江湖垂釣翁。"]'),
('83e5937a-982d-4ef8-a52d-82bea9ded1a5','冬晚湖上','吳燧','宋','宋诗','song-poetry','','[]','山色寒仍瘦，湖光晚再明。',48,'全唐诗/poet.song.214000.json','["山色寒仍瘦，湖光晚再明。", "松蒼仁者壽，梅古聖之清。", "日淡草無影，風乾葉有聲。", "三年湖上客，鷗鷺得無情。"]'),
('a885f4cd-81a2-4fd5-a294-9d38ae1835ae','寶祐五年史院修高孝光寧四朝國史成上進九月明堂升侑高宗禮成進詩三章稱賀  其一','程元鳳','宋','宋诗','song-poetry','','[]','聖主嚴恭德意真，兩儀合饗鑒精純。',64,'全唐诗/poet.song.214000.json','["聖主嚴恭德意真，兩儀合饗鑒精純。", "九筵五室儀章舊，一祖三宗侑典新。", "風日盎溫鑾輅駕，月星明穊玉巵陳。", "元良式獻邦家慶，共祝吾皇壽萬春。"]'),
('24168c54-5c77-4b55-8ef6-cb948d2ea3c4','寶祐五年史院修高孝光寧四朝國史成上進九月明堂升侑高宗禮成進詩三章稱賀  其二','程元鳳','宋','宋诗','song-poetry','','[]','格天盛德素躬全，肸蠁交通心即天。',64,'全唐诗/poet.song.214000.json','["格天盛德素躬全，肸蠁交通心即天。", "供幣用將祈永命，奉粢端爲告豐年。", "寬條日布民安業，捷幟星馳將護邊。", "虎拜紫宸稱賀處，祥光縈繞御爐烟。"]'),
('8fc7a4c4-f9e7-42d3-b807-ba439ff66b93','寶祐五年史院修高孝光寧四朝國史成上進九月明堂升侑高宗禮成進詩三章稱賀  其三','程元鳳','宋','宋诗','song-poetry','','[]','愚臣何幸際明時，才本疎庸玷宰司。',64,'全唐诗/poet.song.214000.json','["愚臣何幸際明時，才本疎庸玷宰司。", "未報聖恩懷夕惕，更叨使領侍親祠。", "駿奔重屋儀文肅，雞揭端門惠術施。", "歸美慚微天保頌，畏威願繼我將詩。"]'),
('6fb5dcb9-40f3-439e-8a3c-3b8affd0621c','淳祐己酉歲謁祖梁將軍忠壯公廟','程元鳳','宋','宋诗','song-poetry','','[]','有美英姿七尺長，桓桓威武孰能當。',64,'全唐诗/poet.song.214000.json','["有美英姿七尺長，桓桓威武孰能當。", "保州蕭史來依德，拒逆侯生竟敗亡。", "爵受重安持督節，謚書忠壯配高皇。", "堂堂廟宇黄牢下，暮鼓晨鍾不暫忘。"]'),
('117a53ec-0b9d-47a3-8578-8a1741774b74','和竹塢過曹柘嶺','程元鳳','宋','宋诗','song-poetry','','[]','午雞喔喔嶺頭聞，下嶺相將日已曛。',64,'全唐诗/poet.song.214000.json','["午雞喔喔嶺頭聞，下嶺相將日已曛。", "跨澗小橋斜貼水，懸崖峭壁冷生雲。", "青帘漸喚新從事，白壁猶存舊墨君。", "桑柘漸濃麻麥秀，田夫村婦總欣欣。"]'),
('0d635557-c770-4f6d-8ac1-8dd00f0c32c7','居然菴','程元鳳','宋','宋诗','song-poetry','','[]','山人坐題山水清，一空霽色無陰晴。',64,'全唐诗/poet.song.214000.json','["山人坐題山水清，一空霽色無陰晴。", "虛堂夜看星斗落，老鼎晝汲風泉烹。", "杯間聊學蔬筍氣，雲外遠飄絃誦聲。", "晦翁溪齋二三友，神遊於此留其名。"]'),
('8253440a-94a6-4126-80a0-365999837be1','遊清泉寺','程元鳳','宋','宋诗','song-poetry','','[]','爲愛山房峭絕，十年兩借禪床。',28,'全唐诗/poet.song.214000.json','["爲愛山房峭絕，十年兩借禪床。", "松聲夜半清枕，洗盡世間笙簧。"]'),
('41ca6ba1-7a6d-4d11-a4d3-b551d7840896','虎頭巖','程元鳳','宋','宋诗','song-poetry','','[]','共趁雲龍會，爾何獨負嵎。',48,'全唐诗/poet.song.214000.json','["共趁雲龍會，爾何獨負嵎。", "猝逢驚履尾，孰視稍摩鬚。", "野老與相狎，行人畏不趨。", "敢煩猿臂手，射此老於菟。"]'),
('32e9adc9-ab6c-4481-b53a-88252e915bc0','同山窗遊黄山','程元鳳','宋','宋诗','song-poetry','','[]','解鞍小憩索胡床，五載重來兩鬢霜。',64,'全唐诗/poet.song.214000.json','["解鞍小憩索胡床，五載重來兩鬢霜。", "庭下幽花迷蛺蝶，屋頭喬木弄笙簧。", "棣華喜遂團欒樂，柳絮從教上下狂。", "明月浮丘訪僊伯，徑迷芳草馬蹄香。"]'),
('da04b2fb-259b-4b8d-8e41-30e6982a6dd8','明堂大禮慶成詩  其一','程元鳳','宋','宋诗','song-poetry','','[]','聖心翼翼對蒼穹，蕆事明禋協肅雍。',64,'全唐诗/poet.song.214000.json','["聖心翼翼對蒼穹，蕆事明禋協肅雍。", "玉輅曉升香霧滃，紫壇夜款瑞烟濃。", "風聲應律諧簫管，月色澄空映璧琮。", "丹鳳樓前恩施溥，歡呼三祝效堯封。"]'),
('30000a2e-a435-4dc1-be30-9f986c6456a2','明堂大禮慶成詩  其二','程元鳳','宋','宋诗','song-poetry','','[]','森嚴羽衛擁和鑾，咫尺龍顔侍至尊。',64,'全唐诗/poet.song.214000.json','["森嚴羽衛擁和鑾，咫尺龍顔侍至尊。", "禋祀儀文勤聖問，敬天實意進芻言。", "百神受職來鴻祉，多士承休肅駿奔。", "右饗不常威可畏，載歌周頌報皇恩。"]'),
('babea72f-4c99-478d-88e9-223a13aaa31f','句','程元鳳','宋','宋诗','song-poetry','','[]','漁翁收網處，衰柳自穿魚。',12,'全唐诗/poet.song.214000.json','["漁翁收網處，衰柳自穿魚。"]'),
('24108de0-1c4c-4652-bbf5-2dad64c3c56a','逍遥吟','貝守一','宋','宋诗','song-poetry','','[]','饑餐匕筯飯，渴飲甆罌酒。',48,'全唐诗/poet.song.214000.json','["饑餐匕筯飯，渴飲甆罌酒。", "不忺白晝眠，時復遶庭走。", "不結冷淡交，亦無名利友。", "晚借竹風涼，臨池坐良久。"]'),
('bb1205cc-b483-490b-8425-c5659ba9ca2a','適意','貝守一','宋','宋诗','song-poetry','','[]','不效癡禪誤此身，安居隨分樂天真。',64,'全唐诗/poet.song.214000.json','["不效癡禪誤此身，安居隨分樂天真。", "閒尋草藥防醫病，廣施仙方爲濟人。", "學道未逢師訣竅，收心且養自精神。", "修持要到無空地，掃却從前礙眼塵。"]'),
('8d9e3185-71f2-4f56-a42e-85de0833ff35','自適','貝守一','宋','宋诗','song-poetry','','[]','跡晦心須晦，神清夢亦清。',48,'全唐诗/poet.song.214000.json','["跡晦心須晦，神清夢亦清。", "一窩如斗大，萬事等漚成。", "風月平章易，山林去就輕。", "生生終有累，不若事無生。"]'),
('5279d730-47c2-4b73-9f53-f430a0e87e0f','有何不可  其一','貝守一','宋','宋诗','song-poetry','','[]','園林桃李爭妍，我有蘭花數朵。',28,'全唐诗/poet.song.214000.json','["園林桃李爭妍，我有蘭花數朵。", "盃盤笋蕨鮮肥，恁地有何不可。"]'),
('b7918863-d5f2-4a0e-9206-0f32cd88fb0c','有何不可  其二','貝守一','宋','宋诗','song-poetry','','[]','炎炎火繖張空，避暑林亭趺坐。',28,'全唐诗/poet.song.214000.json','["炎炎火繖張空，避暑林亭趺坐。", "有時解帯披襟，恁地有何不可。"]'),
('b95700e3-8f14-402c-8c21-9068c0337df4','有何不可  其三','貝守一','宋','宋诗','song-poetry','','[]','桂花香滿脩廊，皓月當空照我。',28,'全唐诗/poet.song.214000.json','["桂花香滿脩廊，皓月當空照我。", "徐徐三弄瑶琴，恁地有何不可。"]'),
('012aba25-b013-4874-b1d7-e8a7dbb306ee','有何不可  其四','貝守一','宋','宋诗','song-poetry','','[]','竹塢雪封雲鎖，地爐溫酒添火。',28,'全唐诗/poet.song.214000.json','["竹塢雪封雲鎖，地爐溫酒添火。", "醉來擁被高眠，恁地有何不可。"]'),
('6a8d3518-9317-4c64-9364-4bea7735177e','冬晴晚步','貝守一','宋','宋诗','song-poetry','','[]','浮雲初斂夕陽斜，路入江村四望賒。',64,'全唐诗/poet.song.214000.json','["浮雲初斂夕陽斜，路入江村四望賒。", "木厭霜濃頻脫葉，梅嫌春小未開花。", "翩翩過雁摩晴漢，隠隠孤帆趁落霞。", "欲壯吟懷沽斗酒，野田多處少人家。"]'),
('b0cd61ae-57ee-442e-81b6-a9c1835a9069','絕句','貝守一','宋','宋诗','song-poetry','','[]','高車駟馬謾相誇，竹榻蒲團屬自家。',32,'全唐诗/poet.song.214000.json','["高車駟馬謾相誇，竹榻蒲團屬自家。", "困睡饑餐何所有，一溪明月照梅花。"]'),
('ffbcc5a8-8b41-432c-9fe7-0f961e412a67','天基節靜江祝聖樂語口號','李曾伯','宋','宋诗','song-poetry','','[]','五葉堯蓂紀誕彌，慶流文祖已垂基。',64,'全唐诗/poet.song.214000.json','["五葉堯蓂紀誕彌，慶流文祖已垂基。", "星明南極老人壽，春布東皇太乙時。", "紅入仙桃千歲實，青歸御柳萬年枝。", "嶺民喜見昇平象，拜手同賡天保詩。"]'),
('e4ad7f01-ac75-492d-b230-cc3356968ceb','王母致語口號','李曾伯','宋','宋诗','song-poetry','','[]','碧虛飛信入蓬萊，約我驂鸞伴侶來。',64,'全唐诗/poet.song.214000.json','["碧虛飛信入蓬萊，約我驂鸞伴侶來。", "藹藹祥雲射虹渚，繽繽香霧下龜臺。", "喜乘蓮葉經瓊海，笑指梅花薦玉杯。", "聖算自應天地久，蟠桃不計幾回開。"]'),
('0cdb0b90-55bf-4495-947a-2b88f227fdbb','對廳致語口號','李曾伯','宋','宋诗','song-poetry','','[]','相對封人共祝堯，玉觴瀲灧酒浮椒。',64,'全唐诗/poet.song.214000.json','["相對封人共祝堯，玉觴瀲灧酒浮椒。", "千山佳氣供紅旆，一道仁聲頼翠軺。", "南極仰祈天上壽，東風不隔海濱遥。", "恩濃湛露何爲報，勉屬清忠答聖朝。"]'),
('2d6e7fed-d175-47fe-a64b-15fd51b670c0','代益昌憲運兩司宴制帥樂語口號','李曾伯','宋','宋诗','song-poetry','','[]','春風旗鼓擁元戎，萬馬方嘶一洗空。',64,'全唐诗/poet.song.214000.json','["春風旗鼓擁元戎，萬馬方嘶一洗空。", "不憚八千來劍北，始知十二小齊東。", "將扶灞上真人業，未說隆中宰相功。", "整頓乾坤談笑事，歸來置酒未央宮。"]'),
('94773113-8804-4553-8c97-bcc196a03e46','代蜀總過沔宴制帥','李曾伯','宋','宋诗','song-poetry','','["\u897f\u6e56"]','皇天祚宋啟真儒，手鑰秦關鎮蜀都。',64,'全唐诗/poet.song.214000.json','["皇天祚宋啟真儒，手鑰秦關鎮蜀都。", "方策有之伊呂偶，規模如此漢唐無。", "軍聲劘刜歸帷幄，王事驅馳在粟芻。", "把酒東湖需捷奏，佇催公衮醉西湖。"]'),
('293e8f0d-be25-4a4d-a338-5c611c76ad03','代餞蜀閫赴召樂語口號','李曾伯','宋','宋诗','song-poetry','','[]','自擁琱旂運閫籌，星霜四歷玉關秋。',64,'全唐诗/poet.song.214000.json','["自擁琱旂運閫籌，星霜四歷玉關秋。", "深培根本安全蜀，直用精神定遠陬。", "琴鶴公將離峽口，樵漁我亦訪吳頭。", "溪山好處俱堪飲，江路相銜醉未休。"]'),
('07ac4f7c-67cc-4773-9c50-b1827f32d36c','代蜀總赴召宴制帥樂語口號','李曾伯','宋','宋诗','song-poetry','','[]','曉來微雨過前溪，見說桃花水正肥。',64,'全唐诗/poet.song.214000.json','["曉來微雨過前溪，見說桃花水正肥。", "人送風帆還紫闥，客隨星履近黄扉。", "昔陪關上青牛到，今趁遼東白鶴歸。", "留得春風滿全蜀，尚知楊柳賦依依。"]'),
('eb38db49-5dbe-40c0-9bca-e93cdcd3d1c7','代襄閫宴新除史制卿樂語口號','李曾伯','宋','宋诗','song-poetry','','[]','一從棋折佐籌帷，凜凜威名塞漢知。',64,'全唐诗/poet.song.214000.json','["一從棋折佐籌帷，凜凜威名塞漢知。", "大范老今歸去矣，小申公爲易新之。", "檀溪春草輕車熟，苕霅秋蓴短艇宜。", "千載峴山磨不朽，重添羊杜兩豐碑。"]'),
('a3ef05c2-efa8-4b19-a16a-f3bd3f891a45','揚州宴交代丘總領樂語口號','李曾伯','宋','宋诗','song-poetry','','[]','騑騑牡駕暫臨邊，淮海東頭護玉旃。',64,'全唐诗/poet.song.214000.json','["騑騑牡駕暫臨邊，淮海東頭護玉旃。", "春滿四郊耕穀雨，雲屯萬竈飽炊烟。", "平山柳絮隨絲轡，新水桃花颺綵船。", "瀲灧一杯拚却醉，明朝有詔侍甘泉。"]'),
('faa481a0-36c6-4e9e-9d9b-760a5df7cd52','壽城凱還宴將帥樂語口號','李曾伯','宋','宋诗','song-poetry','','[]','新墉屹屹解嚴圍，十萬全師破賊回。',64,'全唐诗/poet.song.214000.json','["新墉屹屹解嚴圍，十萬全師破賊回。", "元帥擁旄朝授策，將軍畫箠夜銜枚。", "椎牛臠炙歡聲動，伐鼓傳觴哀拍催。", "盡道平淮勳業盛，總須圖像上雲臺。"]'),
('a576411c-69df-42b3-8585-6b4941769230','凱還又宴王宣使樂語口號','李曾伯','宋','宋诗','song-poetry','','[]','八年一柱屹長城，此老胸中百萬兵。',64,'全唐诗/poet.song.214000.json','["八年一柱屹長城，此老胸中百萬兵。", "有造於西棠播頌，窮荒之北草知名。", "喧天笳鼓歸時樂，揭日旂常曠世榮。", "且爲平山應少駐，莫辭酩酊盡歡情。"]'),
('44fdde5c-340b-4e68-b5ec-3bf97777a1c8','桂林宴交代董侍郎樂語口號','李曾伯','宋','宋诗','song-poetry','','[]','同是虛皇老從臣，海山深處細論心。',64,'全唐诗/poet.song.214000.json','["同是虛皇老從臣，海山深處細論心。", "金蘭誼篤新藩翰，玉筍班趨舊禁林。", "對月不妨延桂影，思人惟有護棠陰。", "公歸定是調商鼎，莫忘梅花雪片吟。"]'),
('dbb799d3-6ac8-4b29-b9b5-c25c966a3395','桂林宴提刑樂語口號','李曾伯','宋','宋诗','song-poetry','','[]','鷺洲鴛渚久相知，弭節開藩並此時。',64,'全唐诗/poet.song.214000.json','["鷺洲鴛渚久相知，弭節開藩並此時。", "越俎况當交使事，舉觴何惜話心期。", "欣逢桂子三秋候，細和梅花萬里詩。", "指日驂鸞天上去，倚看接武步丹墀。"]'),
('06e6b817-dbc1-4c6c-a8c8-2a6959aea7ee','桂林鹿鳴宴樂語口號','李曾伯','宋','宋诗','song-poetry','','[]','玉帳宏開會衆英，嶄嶄頭角露崢嶸。',64,'全唐诗/poet.song.214000.json','["玉帳宏開會衆英，嶄嶄頭角露崢嶸。", "人才數半凌烟贊，姓氏推先月旦評。", "桂子風前鵬翮健，梅花雪外馬蹄輕。", "兩魁衣鉢須爭繼，聯轡歸來晝錦榮。"]'),
('56a9a8e6-273b-4e63-ae4e-60d4baa94dbb','荆閫宴交代賈尚書樂語口號','李曾伯','宋','宋诗','song-poetry','','[]','底事元戎輟上流，揚州勢更重荆州。',64,'全唐诗/poet.song.214000.json','["底事元戎輟上流，揚州勢更重荆州。", "要酬棠笏中原志，坐釋楓宸北顧憂。", "白羽一揮新玉帳，朱簾半捲舊紅樓。", "此行整頓乾坤了，公衮萊衣正黑頭。"]'),
('517c3bba-e6c5-46f9-8825-6384fc34ebd9','荆閫宴呂馬帥樂語口號','李曾伯','宋','宋诗','song-poetry','','[]','海風吹月近中秋，碧玉天高灝氣浮。',64,'全唐诗/poet.song.214000.json','["海風吹月近中秋，碧玉天高灝氣浮。", "文武對開王儉幕，主賓同上仲宣樓。", "棋邊正要看新著，酒畔何妨話舊遊。", "了却經營宛洛事，入登樞筦贊帷籌。"]'),
('c82ad643-5161-4b36-8244-122b5a4d816f','丁亥紀蜀百韻','李曾伯','宋','宋诗','song-poetry','','[]','太歲在娵觜，羲馭正東陸。',288,'全唐诗/poet.song.214000.json','["太歲在娵觜，羲馭正東陸。", "羽書西邊來，胡騎報南牧。", "倉茫星火急，飄忽風雨速。", "憑陵我封疆，剽掠我孳畜。", "一越摩雲險，已汙巖岷俗。", "再度峰貼隘，重爲武階毒。", "胡兒忽令名，見謂韃靼屬。", "或疑女真詐，頗訝疊州族。", "衣毛不知帛，飲酪非茹粟。", "勁弓骨爲面，健馬鐵裹足。", "駕言取金夏，其鋒不可觸。", "如竹迎刃解，猶雪以湯沃。", "先聲張虛疑，我師遽蓄縮。", "心已執檄迷，手爲望風束。", "策昧戰爲守，計乏奇與伏。", "西和久間斷，文南暫蹢躅。", "將利僅小退，凱音誤陸續。", "蘭臯要寸功，良將半喪衂。", "敗書丙夜聞，前矛石門宿。", "亟令控三關，謹毋費一鏃。", "魚梁閉仙原，武林護午谷。", "七方對壘持，相戒前轍覆。", "縣官塞蹊徑，戰士據林麓。", "由是關以外，民皆棄廬屋。"]'),
('33c93834-93dd-4097-877a-67f51d6d8139','過涪州懷伊川涪翁兩先生','李曾伯','宋','宋诗','song-poetry','','[]','昌黎昔作潮州游，潮人百世稱名州。',256,'全唐诗/poet.song.214000.json','["昌黎昔作潮州游，潮人百世稱名州。", "又聞柳州柳子厚，柳人至今愛其柳。", "二公皆以文鳴唐，所至不偶爲異常。", "卒今江海流落地，化作文物聲名鄉。", "涪南僻在巴子國，地絕中州少人物。", "天將儒道淑是邦，曾向先朝處羈客。", "河南夫子間世賢，山谷老叟人間仙。", "一時轍迹相繼至，頓使光價增山川。", "嘗嗟道從孟軻死，一貫誰能接原委。", "又嗟詩自杜甫亡，四海誰能造詩壘。", "幸生伊洛續聖傳，鳶魚遂復窮天淵。", "從而江右振餘響，清廟又得存遺絃。", "今踰元祐二百載，草木涪人尚知愛。", "文章性命雖匪倖，氣象風流久皆在。", "惜乎兩公生盛時，下與屈賈同驅馳。", "涪人則幸公不幸，天下應怨涪人私。"]'),
('3e6585c2-af74-4b6c-afe8-e021e88850c6','壽襄閫','李曾伯','宋','宋诗','song-poetry','','[]','江南三月春事濃，人間處處熙東風。',384,'全唐诗/poet.song.214000.json','["江南三月春事濃，人間處處熙東風。", "山陰亭下羽觴舉，長安水邊簫鼓從。", "衣冠酣燕太平久，干戈浸鈍鐵鉞朽。", "神州風景雖慷慨，已付新亭一杯酒。", "皇天佑宋當此時，乃眷疇作邦家基。", "水晶宮裏毓奇瑞，翼日生此神仙姿。", "平時功業在學術，治道邊防講明出。", "遂將姬旦勤勞心，一洗吳人侈奢習。", "襄陽自昔天下雄，形勢今處常蛇中。", "彤弓玈矢自臨牧，輕裘緩带惟從容。", "雞鳴而起夜無寐，切切安危以身繫。", "四維盤石罔遺慮，千里毫釐尚深計。", "一民未飽公足食，一兵尚寒公以衣。", "蒼顔皓鬢已若瘠，黄童白叟人其嬉。", "瞻言二十三郡國，根本其蕃頼封植。", "農知奠枕士超距，豈但邊人戒生隙。", "幾番河檄動漢關，折衝隨出精神間。", "平淮既敵江漢盛，救邢況盡春秋難。", "往時國未一興役，動以千金大農給。", "自公邊用足幕府，不費中朝一毫力。", "往時餽餉識調師，粟殆不及朞年支。", "自公留屯上方略，粒米狼戾如京坻。", "規模宏大有如此，古猶其難况今撽。", "朝廷宿望四海重，中外先生一人耳。"]'),
('be7dd956-201a-463b-88b3-674a95ef0c73','贈黄虛舟','李曾伯','宋','宋诗','song-poetry','','[]','君不見君家知命今師日，白衫騎馿人不識。',298,'全唐诗/poet.song.214000.json','["君不見君家知命今師日，白衫騎馿人不識。", "當時畫作梁園圖，惟有龍眠老仙筆。", "又不見異時知命離戎州，終身願學陶朱遊。", "能令太史爲著語，此比西子同扁舟。", "君今名在嫡孫行，數載浮家渚宮上。", "秋風細起鱸魚釣，落日馱成院花樣。", "孤篷短轡成兩奇，一朝復見江南詩。", "風流信是古難繼，亦有軒輊誰爲之。", "我知長耳困皁櫪，突市衝籬久狂蹶。", "逢京兆節僅免辱，入華陰門幾遭詰。", "不如小艇楓荻洲，水天碧處盟沙鷗。", "凌波三歎洛妃恨，招魂一洗湘纍愁。", "騎馿不下竟爲惑，縱葦所之樂何極。", "與今坐上嘲子瑜，爭似舟中懷李白。", "奚庸二畝藜莧圖，足歸一枕黄粱娛。", "持竿鼓枻貴適我，解鞍截鐙無從渠。", "厥今龍眠麟筆不可復，太史鸞膠尚堪續。", "我亦苕溪漁隠徒，亦有水調遺子以一曲。"]'),
('c3f82875-4ea1-47fc-91ff-e5bb586256a7','和劉清叔襄陽隆中行','李曾伯','宋','宋诗','song-poetry','','[]','老瞞晚當漢道卧，黑雲觸天月新破。',160,'全唐诗/poet.song.214000.json','["老瞞晚當漢道卧，黑雲觸天月新破。", "英雄湖海應如響，獨向南陽靜中坐。", "當時不遇劉豫州，抱膝吟嘯誰爲酬。", "本圖一旅復夏祀，豈爲萬戶伸韓仇。", "彼攸官渡瑜夏口，非不功名咄嗟就。", "甘心蒿布嫁之子，肯以金夫易吾守。", "惜乎天下思漢心，是際不及西都深。", "皇天不祚機再失，馬謖之敗雲長禽。", "空存遺廟千載後，過者猶知袒爲右。", "嗚呼龍乎如有靈，盍使胡營落天狗。"]'),
('995ff5e7-1b9f-41c3-83f3-989261a4f60e','謁南嶽','李曾伯','宋','宋诗','song-poetry','','["\u8861\u5c71"]','來謁衡嶽山，未窮衡嶽境。',168,'全唐诗/poet.song.214000.json','["來謁衡嶽山，未窮衡嶽境。", "爇香赤帝殿，恭祈國壽永。", "婆娑禹指山，僅窺虬龍影。", "分枝萬派別，功與天地準。", "悅亭萬竹間，倚丘甫俄頃。", "披雲挹蒼翠，俗慮須甦醒。", "王事屬有程，山容看難盡。", "歸來短篷底，夢斷青松徑。", "雲開爲韓子，雪霽朱張詠。", "必如三先生，人與此山稱。", "我生等培塿，安敢喬嶽並。", "好峰七十二，詎可一朝竟。", "男兒萬里眼，長嘯付一瞬。", "終朝摘星斗，寘身祝融頂。"]'),
('ea4bcbc3-429a-4aaf-aa16-4a4f587beac7','詠衡嶽禹柏','李曾伯','宋','宋诗','song-poetry','','["\u8861\u5c71"]','我來衡山下，古梵見老柏。',144,'全唐诗/poet.song.214000.json','["我來衡山下，古梵見老柏。", "森然星野分，亶有神明力。", "風霜飽更練，雨露富培埴。", "嶽靈共長久，造化與消息。", "本盛柯葉茂，夫豈一朝積。", "中斷尋復續，生意仁一脈。", "亦由功萬世，何止祚四百。", "五子歎將否，一旅少康出。", "此殆皇天意，髣髴留禹跡。", "倚爲赤帝佐，正此蒼官色。", "存古追蠡在，比休玄圭錫。", "稽首千萬年，五丁謹封植。"]'),
('881980fb-15fe-4fa7-82eb-87e2290d9e96','跋曾玉堂訓子十詩','李曾伯','宋','宋诗','song-poetry','','[]','玉堂義方訓十字，衍而六百十六言。',128,'全唐诗/poet.song.214000.json','["玉堂義方訓十字，衍而六百十六言。", "一門翁季自師友，盡出學問之根源。", "彼援遺書誡敦嚴，暨昶以義名沉渾。", "爭如此作旨哉味，足使聞者推而尊。", "雖然責善友之義，仕教之忠古皆爾。", "讀其詩可知其人，非是父不生是子。", "書紳我亦且服膺，過庭夫豈弗由禮。", "觸屏教諂勢利徒，得不爲之望風愧。"]'),
('fe1e2ef3-6608-4580-8764-33dbfcc7d0d8','戊申和嘉興守瑞麥行','李曾伯','宋','宋诗','song-poetry','','[]','瑞麥歌懷安，三岐及六穗。',288,'全唐诗/poet.song.214000.json','["瑞麥歌懷安，三岐及六穗。", "嘉祥不虛出，良以氣和致。", "人言一草木，華枯且爲異。", "况茲一曰食，有是三足記。", "此邦今扶風，中興號佳地。", "去年歲千厄，衆懼憂莫弭。", "入春雨暘若，嘉驗應期至。", "賢侯政事師，其清一杯水。", "孜孜布上德，念念在民事。", "東都循吏孰，漁陽史君似。", "一麥露雙穎，異世風同軌。", "華黍續新雅，嘉禾繼前瑞。", "老夫卧陋巷，聞此躍而起。", "一廛猥受滕，二天幸托冀。", "誰謂大慶賚，俯亦及憔悴。", "自今豐年兆，不苦力田匱。", "當知太守心，根源自宮閟。", "務豐且重穀，感召至茲類。", "昔襦今五袴，千里共衣被。", "相逢二三叟，相慶更相慰。", "不圖田里歎，轉作謳歌喜。", "酡顔溢鄉老，歡聲浹鄰比。", "餘波賸沾丐，罔功有餘愧。", "攄毫頌公德，拜手及公賜。"]'),
('adf9f5a0-cd83-48c4-a0cf-e33d2f8b396f','己酉夏詠月巖','李曾伯','宋','宋诗','song-poetry','','[]','老蟾竊靈藥，墮魄下塵寰。',192,'全唐诗/poet.song.214000.json','["老蟾竊靈藥，墮魄下塵寰。", "跡誤采石江，名虛巫峽山。", "長風送之來，寄影千丈巖。", "列壁當層雲，虛白生光寒。", "婆娑仙桂影，中著孤根蟠。", "宛宛學扇初，盈盈一鈎彎。", "如出滄海頭，半揭烟霄端。", "風雨不改度，晦朔從循環。", "山靈奪天目，作此奇哉觀。", "閲盡來去人，了不蒼其顔。", "所欠斷鰲始，一闕難磨鑱。", "憑誰駕長梯，取置懷袖間。", "爲施玉斧工，修作寶鑑團。", "豈無女媧之手呂翁指，運此神造應非難。", "何如存我真面目，嫵媚一笑只作青山看。"]'),
('bd71aada-694a-4904-aa98-232c74e06c4d','詠丫頭巖','李曾伯','宋','宋诗','song-poetry','','[]','我嘗采石山頭見蛾眉，且看濃粧淡抹兩湖宜。',119,'全唐诗/poet.song.214000.json','["我嘗采石山頭見蛾眉，且看濃粧淡抹兩湖宜。", "何物老嫗生此兒，又覩雙髻尤爲奇。", "五丁刻畫盤古時，黛綠常假山靈施。", "春風閲盡不肯笄，素螺頭立鬢不絲。", "梳雲沐雨容爲誰，相逢婉孌是似之。", "古今知幾經品題，我困暑役何能詩。", "祗疑前山月鑑故半虧，嫦娥妬吝耶焉知非。"]'),
('c56b2dea-45a6-44b8-b7cc-312e07866aec','庚戌過浯溪讀中興碑','李曾伯','宋','宋诗','song-poetry','','[]','峿山一何青，浯水一何綠。',144,'全唐诗/poet.song.214000.json','["峿山一何青，浯水一何綠。", "上有唐朝碑，蒼崖與天矗。", "清廟倣遺音，靈武號實錄。", "其筆走風雷，其文貴金玉。", "曾經兩賢手，足耀千載目。", "後來紀名氏，前鑱後且續。", "豈無黄絹辭，中寓白圭讀。", "一辭不敢措，我懼此碑辱。", "雖然勿泥古，詠嘆豈不足。", "嶽將降甫申，吾皇車攻復。", "將墨東海水，且汗南山竹。", "勒功岱嵩頂，豈但清溪曲。"]'),
('93e8bbcd-0285-4ba1-a31e-4cb756fdcd5e','和士友傅勉之喜雨韵','李曾伯','宋','宋诗','song-poetry','','[]','老生本不學軍旅，來護荆州國門戶。',210,'全唐诗/poet.song.214000.json','["老生本不學軍旅，來護荆州國門戶。", "慚無善政格休徵，未能雨十與風五。", "今年甫幸登麥喜，入夏又以槁苗苦。", "驕陽杲杲地欲赤，身願爲騂措無所。", "瓣香惟有老天告，難以中心共人語。", "當知歲計國計關，不但區區飽吾楚。", "我持皇穹不絕物，寧忍赤子失其乳。", "彌旬果爾三沛澤，靡間西郊與南畝。", "灌園遂省桔槹力，行道奚憂豆簞呼。", "農皆眉間有色喜，士亦胸中以奇吐。", "炎埃萬里一洗空，手扇爲之却紈羽。", "我願天地朝野和，常若淵泉以時溥。", "多謝豐隆屏翳已奏功，毋使吾民復咨雨。"]'),
('8dec91f1-667a-4710-aa3c-ea4f6142398d','詠荆州瑞蓮','李曾伯','宋','宋诗','song-poetry','','[]','蓮之爲瑞固有之，水神豈肯輕鍾奇。',192,'全唐诗/poet.song.214000.json','["蓮之爲瑞固有之，水神豈肯輕鍾奇。", "雙花僅見子辱表，並蒂嘗著原父詩。", "未如今年荆州幕，拔萃出類羅方池。", "二花三花四五花，至於六花同一枝。", "根荄太華玉井藕，彷彿函德銅池芝。", "曉來朝日千葉開，宛若羣玉齊頃葵。", "花工示人厥有象，豈止綠沉而紅依。", "花中獨此號君子，愛蓮有說聞濂溪。", "方今衆賢聚本朝，左右周召而皋夔。", "朝和物和天地和，薦之千載之一時。", "主人生平不好異，一見錯愕開雙眉。", "此天産也豈人力，賦此直欲同僚知。"]'),
('6a0effb3-190b-4bdb-9568-a93f664681df','曉行梧桐嶺','李曾伯','宋','宋诗','song-poetry','','[]','擔簦畏炎暑，肅肅問宵征。',48,'全唐诗/poet.song.214000.json','["擔簦畏炎暑，肅肅問宵征。", "馬首已十里，雞聲纔五更。", "雲迷青障小，月掛玉鈎橫。", "農舍欲安挽，戒奴毋大驚。"]'),
('c094c07f-4006-4b4e-b587-bfda681d6d58','轎中假寐','李曾伯','宋','宋诗','song-poetry','','[]','孤枕欠曉夢，短輿償午眠。',48,'全唐诗/poet.song.214000.json','["孤枕欠曉夢，短輿償午眠。", "籃摇小兒卧，龕定老僧禪。", "少瞑溪山眼，良勞僕從肩。", "醒來斜日暮，亟喚玉驄鞭。"]'),
('4818144c-5302-4706-b70e-d25281084f94','過京山','李曾伯','宋','宋诗','song-poetry','','[]','總角嬉遊處，重來轉盼然。',48,'全唐诗/poet.song.214000.json','["總角嬉遊處，重來轉盼然。", "溪山猶昨日，朋友盡中年。", "舊話逢人說，新詩爲客傳。", "喚回風雨夢，猶記北窗眠。"]'),
('236b442d-2b18-49ba-83fe-0e0ae5abe5b4','入郢訪張學賓因覩舊句有感','李曾伯','宋','宋诗','song-poetry','','[]','此君嘗識面，閲八載重來。',48,'全唐诗/poet.song.214000.json','["此君嘗識面，閲八載重來。", "倦鳥欣曾宿，棲鸞去不回。", "牆陰餘舊墨，砌下長新苔。", "多謝東屏主，時時爲拂埃。"]'),
('b9ed85c9-cd7c-412d-8ac2-180a74395315','登郢州白雪樓','李曾伯','宋','宋诗','song-poetry','','[]','野迥乾坤闊，樓高歲月深。',48,'全唐诗/poet.song.214000.json','["野迥乾坤闊，樓高歲月深。", "江山不今古，人物幾登臨。", "雲影埋荆樹，風聲快楚襟。", "何須喚商女，白雪想遺音。"]'),
('a566475d-0352-406d-97b6-f8c6b10a6d21','登郢州四望亭','李曾伯','宋','宋诗','song-poetry','','[]','夐出烟塵表，乾坤指顧中。',48,'全唐诗/poet.song.214000.json','["夐出烟塵表，乾坤指顧中。", "數峰連野迥，一水與天通。", "沙外迎孤鶩，雲邊數亂鴻。", "家山在何許，心與大江東。"]'),
('91a8ca48-19d2-4f70-a7d0-832f3320c60e','蜘蛛和韻','李曾伯','宋','宋诗','song-poetry','','[]','物有小而智，虛簷寄微縷。',72,'全唐诗/poet.song.214000.json','["物有小而智，虛簷寄微縷。", "了不介天地，何以芘風雨。", "蜂蠆嘗自投，螳螂不敢侮。", "去面類湯網，取象得羲罟。", "絲吐雖非蠶，蠅視有如虎。", "真巧非人爲，羞煞金針女。"]'),
('a938519d-15c6-46e0-9ff1-f8a606f14009','入蜀墊江道間  其一','李曾伯','宋','宋诗','song-poetry','','[]','紙被夜受用，布袍朝奏功。',48,'全唐诗/poet.song.214000.json','["紙被夜受用，布袍朝奏功。", "光陰半行客，氣象一衰翁。", "何事朝伊夕，纔非雨即風。", "年華苦相背，歸去又匆匆。"]'),
('1d29e47a-dc21-439c-9f46-a327d4f27f5b','入蜀墊江道間  其二','李曾伯','宋','宋诗','song-poetry','','[]','驛路交游熟，江山契分生。',48,'全唐诗/poet.song.214000.json','["驛路交游熟，江山契分生。", "故人梅撲面，薄倖柳忘情。", "馬躍霜橋步，雞啼月店聲。", "豹狼俱斂迹，應避使車行。"]'),
('7b36968c-63c6-46d8-9127-57d40c54457d','用從軍古云樂爲韻賀楊覺甫制幹  其一','李曾伯','宋','宋诗','song-poetry','','[]','海宇材能盛，風雲氣類從。',48,'全唐诗/poet.song.214000.json','["海宇材能盛，風雲氣類從。", "一賢居上介，千里折遐衝。", "咨事須孫楚，論詩得正封。", "城東未爲好，終不似烏龍。"]'),
('2c83740b-bff6-49f4-ad57-6a663373a5d3','用從軍古云樂爲韻賀楊覺甫制幹  其二','李曾伯','宋','宋诗','song-poetry','','[]','明君切西顧，元帥作中軍。',48,'全唐诗/poet.song.214000.json','["明君切西顧，元帥作中軍。", "賓客湖南上，人才冀北群。", "三鱣存絳帳，一鶚在青雲。", "磊磊軒天地，詩書有雋勳。"]'),
('90835a68-e033-48a3-a1f1-308aa5a5a0cb','用從軍古云樂爲韻賀楊覺甫制幹  其三','李曾伯','宋','宋诗','song-poetry','','[]','求士近取材，論人遠稽古。',48,'全唐诗/poet.song.214000.json','["求士近取材，論人遠稽古。", "鄭公得杜陵，晉公有韓愈。", "上思利社稷，下不愧賓主。", "斯言宜服膺，餘子未足數。"]'),
('5101d3ed-5e92-404f-abb1-7ee979e3b5cc','用從軍古云樂爲韻賀楊覺甫制幹  其四','李曾伯','宋','宋诗','song-poetry','','[]','國有金湯在，鄰修玉帛云。',48,'全唐诗/poet.song.214000.json','["國有金湯在，鄰修玉帛云。", "夷侵由廢雅，苗格自敷文。", "當宁形宵慮，公車以歲聞。", "便當從幕府，入校道山芸。"]'),
('8f69d889-7a1c-4517-bed2-991b3a77069f','用從軍古云樂爲韻賀楊覺甫制幹  其五','李曾伯','宋','宋诗','song-poetry','','[]','伊昔先賢心，天下等憂樂。',48,'全唐诗/poet.song.214000.json','["伊昔先賢心，天下等憂樂。", "時分蜀道弓，慮切漢關鑰。", "揮刃得屠牛，察脈寬扁鵲。", "岷峨望不淺，持酒爲君酌。"]'),
('09fca2f6-78ff-47af-b1f7-3e42d68b1db8','用談笑青油幕爲韻賀吳叔永制機  其一','李曾伯','宋','宋诗','song-poetry','','[]','取士雖多術，知人在片談。',48,'全唐诗/poet.song.214000.json','["取士雖多術，知人在片談。", "文書今倚重，謀議許相參。", "餌陋賈生五，策明劉蛻三。", "坤輿方厚載，朋利得西南。"]'),
('83673d99-da2e-44e8-b859-f8dd2d55848e','用談笑青油幕爲韻賀吳叔永制機  其二','李曾伯','宋','宋诗','song-poetry','','[]','勳業登天難，易者付嬉笑。',48,'全唐诗/poet.song.214000.json','["勳業登天難，易者付嬉笑。", "公駕鵾鵬風，來把鯨鰲釣。", "自比小管樂，致主在周召。", "此突豈待黔，早晚有明詔。"]'),
('3bfe10b9-063e-499d-8a99-0fceb8841922','用談笑青油幕爲韻賀吳叔永制機  其三','李曾伯','宋','宋诗','song-poetry','','[]','弟兄眉最白，人物眼常青。',48,'全唐诗/poet.song.214000.json','["弟兄眉最白，人物眼常青。", "論事猶迎刃，談兵若建瓴。", "訏謨皆上策，道德有强形。", "辦却聊城矢，還書劍閣銘。"]'),
('a682fecb-f17f-499e-8874-761b55b9a897','用談笑青油幕爲韻賀吳叔永制機  其四','李曾伯','宋','宋诗','song-poetry','','[]','唐邊重秦隴，蜀鑒在江油。',48,'全唐诗/poet.song.214000.json','["唐邊重秦隴，蜀鑒在江油。", "不易九鼎重，方兼四履憂。", "其間不容髮，自此可前籌。", "局面西風異，從容夜觀謀。"]'),
('35b79949-13c0-49dd-9660-7510f9615e24','用談笑青油幕爲韻賀吳叔永制機  其五','李曾伯','宋','宋诗','song-poetry','','[]','未登紫薇垣，慚依紅蓮幕。',48,'全唐诗/poet.song.214000.json','["未登紫薇垣，慚依紅蓮幕。", "於巷爲遇主，自牖常納約。", "我生類巢燕，君聞羨臯鶴。", "聽取輿人言，岷峨小難著。"]'),
('78262caa-db1d-4c85-a537-33471d053b22','題劍門寺賀費伯矩韻','李曾伯','宋','宋诗','song-poetry','','[]','不見臺城事，君毋說苦空。',48,'全唐诗/poet.song.214000.json','["不見臺城事，君毋說苦空。", "佛隨千劫盡，人與萬山雄。", "吊古春酤綠，談兵夜燭紅。", "終宵皎無寐，萬壑響松風。"]'),
('039ae551-7ae5-4d0c-8874-f1085fe75418','登閬州錦屏','李曾伯','宋','宋诗','song-poetry','','[]','久識屏山面，今朝得勝遊。',48,'全唐诗/poet.song.214000.json','["久識屏山面，今朝得勝遊。", "橋梁橫古渡，樹影倒中流。", "風定春檣度，烟輕晚市收。", "凭欄誰領解，一鷺點沙洲。"]'),
('6c01be80-5b24-41e3-aeb9-25313da5caf8','登果州金泉山和韻','李曾伯','宋','宋诗','song-poetry','','[]','故迹存棲鶴，高風掃鏡鸞。',48,'全唐诗/poet.song.214000.json','["故迹存棲鶴，高風掃鏡鸞。", "烟霞扃地邃，冰雪照人寒。", "妙句揮濃墨，仙顔煥渥丹。", "雖云歸棹晚，猶及附飛翰。"]'),
('7968061c-81e1-4ea6-9b8e-9dc7e1695d9c','過忠州訪酆都觀  其一','李曾伯','宋','宋诗','song-poetry','','[]','是山來自古，與世類相忘。',48,'全唐诗/poet.song.214000.json','["是山來自古，與世類相忘。", "雨染新苔翠，風吹老柏香。", "神仙多漢魏，祠像半隋唐。", "幾許烟霞侶，相從老此鄉。"]'),
('9e4da3e2-2ddf-4453-b5d1-0406d96dee80','過忠州訪酆都觀  其二','李曾伯','宋','宋诗','song-poetry','','[]','迥絕塵埃表，寧無造物司。',48,'全唐诗/poet.song.214000.json','["迥絕塵埃表，寧無造物司。", "鹿馴貪客過，龍老惡人窺。", "丹去爐仍在，雲生洞愈奇。", "歸舟天盡際，杖履復何時。"]'),
('091a724f-924f-4bff-856a-ba95883306e9','過江陵和黄虛舟韻  其一','李曾伯','宋','宋诗','song-poetry','','[]','詩從雙井來，太史氏復作。',48,'全唐诗/poet.song.214000.json','["詩從雙井來，太史氏復作。", "一葦天地旋，玄酒滋味薄。", "有田付鴒原，比屋頼虎幄。", "却笑草玄池，投閣嗟寂寞。"]'),
('3d368830-596d-4572-b621-6275e1baeab2','過江陵和黄虛舟韻  其二','李曾伯','宋','宋诗','song-poetry','','[]','達人樂所樂，小智憂其憂。',48,'全唐诗/poet.song.214000.json','["達人樂所樂，小智憂其憂。", "平生見飛鳶，常憶馬少游。", "門前車騎喧，孰與園林幽。", "虛舟苟欲去，鷗鷺猶當留。"]'),
('9f6c50ba-1439-49c8-848e-13245566ef43','過江陵和黄虛舟韻  其三','李曾伯','宋','宋诗','song-poetry','','[]','聞公有泊渚，不遠在異林。',48,'全唐诗/poet.song.214000.json','["聞公有泊渚，不遠在異林。", "想勝輞川畫，時作梁父吟。", "絳帳豈陳迹，草堂向遺音。", "朝市有真隠，入山無求深。"]'),
('66c75ba4-8214-493e-86e6-b16d6423b6b3','過江陵和黄虛舟韻  其四','李曾伯','宋','宋诗','song-poetry','','[]','士有似之者，異世而同科。',48,'全唐诗/poet.song.214000.json','["士有似之者，異世而同科。", "草亭今蘭亭，人物晉永和。", "於水鮮可釣，有酒旨且多。", "叩舷欠孺子，一賦滄浪歌。"]'),
('f300e2f7-9d71-4301-ae42-df8ce9dc5d2f','襄州道間驟寒','李曾伯','宋','宋诗','song-poetry','','[]','涉盡江湖道，嗟嗟寸步難。',48,'全唐诗/poet.song.214000.json','["涉盡江湖道，嗟嗟寸步難。", "風敲蘆葉響，雨作菊花寒。", "市酒無嫌薄，征衣正怯單。", "家山在何許，回首路漫漫。"]'),
('254a5e37-b4af-47b3-a4f1-2f29e5187bbb','和羅季能上巳習池送客','李曾伯','宋','宋诗','song-poetry','','[]','一雨洗紅蔫，春深晝欲眠。',48,'全唐诗/poet.song.214000.json','["一雨洗紅蔫，春深晝欲眠。", "綠潭波滉漾，紫陌騎聯翩。", "禊事懷觴豆，官身苦檻圈。", "只今王逸少，重見習池邊。"]'),
('8ed92759-c6ef-4c16-b160-4b38801d6781','過樊城用劉清叔韻','李曾伯','宋','宋诗','song-poetry','','[]','古壘連邊色，烟蕪带夕陽。',48,'全唐诗/poet.song.214000.json','["古壘連邊色，烟蕪带夕陽。", "千年周翰祀，一瓣楚人香。", "樓堞新宏壯，丘墟幾廢荒。", "客懷明哲戒，飛夢繞吳鄉。"]'),
('074bd841-1377-47ed-8f0c-41a5b6240009','登峴山用劉清叔韻','李曾伯','宋','宋诗','song-poetry','','[]','向來碑在所，今見下牛羊。',48,'全唐诗/poet.song.214000.json','["向來碑在所，今見下牛羊。", "魂逐江山老，名流史傳香。", "吳謀千載偉，晉事一丘荒。", "不用凭高看，中原尚鹿場。"]'),
('27b70ba0-8156-466a-a285-4a619f018025','淮西幕自皂口入潁道間作','李曾伯','宋','宋诗','song-poetry','','[]','竟日百餘里，相逢三數家。',48,'全唐诗/poet.song.214000.json','["竟日百餘里，相逢三數家。", "平崗盡茅葦，沃壤舊桑蔴。", "短樹巢歸燕，荒城宿亂鴉。", "興亡誰與問，馬首夕陽斜。"]'),
('52cb4f76-77c5-4976-8a21-a1702b66872f','至潁州訪故老','李曾伯','宋','宋诗','song-poetry','','[]','去汴五百里，通淮十八村。',48,'全唐诗/poet.song.214000.json','["去汴五百里，通淮十八村。", "荒原王翦骨，廢井伍奢魂。", "舊築河南塢，新城塞北屯。", "百年遺愛在，六一故碑存。"]'),
('6f455f08-87c3-41d2-b65d-d1f838965e3a','離潁州道間','李曾伯','宋','宋诗','song-poetry','','[]','戰場千古地，咫尺是京河。',48,'全唐诗/poet.song.214000.json','["戰場千古地，咫尺是京河。", "遠磴連荒壁，深林長亂柯。", "路迷人跡少，草密獸蹄多。", "憶著中原事，令人撫劍歌。"]'),
('fb46c037-7fde-49f5-a9a9-a5fe78647e67','曉行潁上縣','李曾伯','宋','宋诗','song-poetry','','[]','斗大一城壘，角分雙佛圖。',48,'全唐诗/poet.song.214000.json','["斗大一城壘，角分雙佛圖。", "戍營多甲士，耕隴少丁夫。", "月落雞聲杳，風高雁影孤。", "征人皎無寐，趣馬問征途。"]'),
('42102522-12fe-4d20-95ae-fc75c3eed850','八公山憶廉頗','李曾伯','宋','宋诗','song-poetry','','[]','在楚猶在趙，始終同一頗。',48,'全唐诗/poet.song.214000.json','["在楚猶在趙，始終同一頗。", "晚年猶矍鑠，勁氣肯消磨。", "非老無能也，如時不利何。", "漢皇還拊髀，用壯莫蹉跎。"]'),
('505dc615-e456-4f69-b309-b3abdf78fd51','淮淝憶幼度','李曾伯','宋','宋诗','song-poetry','','[]','世未聞風鶴，香囊一少年。',48,'全唐诗/poet.song.214000.json','["世未聞風鶴，香囊一少年。", "秦非無敵者，晉固有人焉。", "社稷一枰上，山河孤注然。", "江東正朔在，或者諉諸天。"]'),
('070687a3-af0b-477e-9c63-1215d56986f2','黄州上巳和王子方雪堂韻','李曾伯','宋','宋诗','song-poetry','','[]','五年安出處，斯道繫污隆。',48,'全唐诗/poet.song.214000.json','["五年安出處，斯道繫污隆。", "血指笑餘子，頭顱老此公。", "屋梁懸落月，花卉带香風。", "生氣鎮長在，大江流不窮。"]'),
('ffadcbac-9663-4171-9806-3078f966d300','贈富春子','李曾伯','宋','宋诗','song-poetry','','[]','向說淮東役，江東始見時。',48,'全唐诗/poet.song.214000.json','["向說淮東役，江東始見時。", "相逢無別語，所問者歸期。", "戎馬紛何已，蓍龜聖得知。", "天津橋上看，成此蔡功誰。"]'),
('e2f7ef62-29d9-4ec6-9650-3bdbebcd0e19','贈鄭通菴','李曾伯','宋','宋诗','song-poetry','','[]','與子前言戲，驚人昨夢然。',48,'全唐诗/poet.song.214000.json','["與子前言戲，驚人昨夢然。", "辦心求學道，絕口戒談天。", "適我烟霞外，任渠牛斗邊。", "明年茅屋下，共玩養生篇。"]'),
('7127f261-e61b-44c1-bd68-ce80cf63f310','送揚州胡倅赴堂召  其一','李曾伯','宋','宋诗','song-poetry','','[]','擊楫同呼渡，勤公佐此州。',48,'全唐诗/poet.song.214000.json','["擊楫同呼渡，勤公佐此州。", "邊防新績用，湖學舊源流。", "未了平戎檄，還催向闕舟。", "君王方仄席，檣燕勿遲留。"]'),
('4fde5476-5959-4c01-95a4-860c15bcff9c','送揚州胡倅赴堂召  其二','李曾伯','宋','宋诗','song-poetry','','[]','里社久相於，深知我計疏。',48,'全唐诗/poet.song.214000.json','["里社久相於，深知我計疏。", "壯懷方磊磊，別語又渠渠。", "竟日猶傳箭，何時可荷鋤。", "煩君看三徑，松與菊何如。"]'),
('cc40f992-ca88-4066-9780-3dbc5b87ff82','贈李尉歸霅川','李曾伯','宋','宋诗','song-poetry','','[]','佩絃示良規，恤緯寓憂抱。',48,'全唐诗/poet.song.214000.json','["佩絃示良規，恤緯寓憂抱。", "人爲海鷗懼，誰謂屋烏好。", "子別肯贈言，我愧未聞道。", "藥石十數字，喚醒知幾早。"]'),
('4cda572f-323d-4693-836a-c8995bfb8381','和清湘蔣省幹酒色財氣韻  其一','李曾伯','宋','宋诗','song-poetry','','[]','爛醉非生涯，小人若甘醴。',48,'全唐诗/poet.song.214000.json','["爛醉非生涯，小人若甘醴。", "斧斤戕天和，狂藥害正禮。", "可惜竹溪逸，不飲潁之水。", "名教有餘樂，公未知趣耳。"]'),
('a8785b2f-5762-4696-a96e-429a17581f31','和清湘蔣省幹酒色財氣韻  其二','李曾伯','宋','宋诗','song-poetry','','[]','風花落春紅，歲寒傲霜竹。',48,'全唐诗/poet.song.214000.json','["風花落春紅，歲寒傲霜竹。", "彼欲褒姒笑，焉知周人哭。", "白髮悲梨園，芳草慘金谷。", "無使桑間音，亂我杏壇曲。"]'),
('9608cec1-612b-4ffc-bd78-4ac9a0b9e709','和清湘蔣省幹酒色財氣韻  其三','李曾伯','宋','宋诗','song-poetry','','[]','網者棄魚小，獵人貪鹿肥。',48,'全唐诗/poet.song.214000.json','["網者棄魚小，獵人貪鹿肥。", "不見阿堵物，見惡寧馨兒。", "銅山變荆棘，錦帳啟藩籬。", "萬物與同毀，千駟吾何爲。"]'),
('9def2608-dc15-444d-ba86-350fbe1c1e2e','和清湘蔣省幹酒色財氣韻  其四','李曾伯','宋','宋诗','song-poetry','','[]','乾坤一枰棋，今古一杯酒。',48,'全唐诗/poet.song.214000.json','["乾坤一枰棋，今古一杯酒。", "悲哉易水筑，陋矣鴻門斗。", "將軍跨下出，宰相簣中有。", "唾面使自乾，拭之費人手。"]'),
('6ab79ba8-f750-462a-bbb7-f281da9b4453','小亭閑止','李曾伯','宋','宋诗','song-poetry','','[]','草草家林適，時時步屐過。',48,'全唐诗/poet.song.214000.json','["草草家林適，時時步屐過。", "跨流通略彴，枕岸擬䍧牱。", "牆外千竿竹，亭陰數畝荷。", "年豐遂閑止，老境足婆娑。"]'),
('e3cc102c-a372-4a47-9c38-c5750c311dec','宣公祠','李曾伯','宋','宋诗','song-poetry','','[]','公不生唐世，貞元事若何。',48,'全唐诗/poet.song.214000.json','["公不生唐世，貞元事若何。", "主恩思報切，臣罪忤時多。", "佞舌攻何忍，剛腸死不磨。", "倚蘭凝佇久，一鷺點滄波。"]'),
('7d9cf490-ad82-4cb4-b53d-055b70c9c5a8','招里巷諸友和韻','李曾伯','宋','宋诗','song-poetry','','[]','小有家林適，歸來已恨遲。',48,'全唐诗/poet.song.214000.json','["小有家林適，歸來已恨遲。", "引杯懷楚舞，飽飯和陶詩。", "慷慨多新語，綢繆半舊知。", "夜深橋雪滑，亟命短筇支。"]'),
('955bbb42-f028-437e-91e3-06e6bf31e4a6','諸友遲留待雪再用韻','李曾伯','宋','宋诗','song-poetry','','[]','護風須飲劇，待雪拚眠遲。',48,'全唐诗/poet.song.214000.json','["護風須飲劇，待雪拚眠遲。", "舉席俱佳客，揮毫盡好詩。", "冷薌梅畔覺，清響竹間知。", "莫憶征鞍夢，從渠月下支。"]'),
('57b27808-8d34-4f7c-bf70-e9f1ac3fd541','己酉赴桂初宿會江驛用徐意一韻','李曾伯','宋','宋诗','song-poetry','','[]','江海三吳會，萍途一昔棲。',48,'全唐诗/poet.song.214000.json','["江海三吳會，萍途一昔棲。", "路迎來阜北，船趁長潮西。", "魚鳥隨情適，鵬蜩付物齊。", "羊裘人底處，烟雨故蹤迷。"]'),
('764815d6-5991-407e-b56d-4fca515111fd','過三衢道士鄭雲谷出示謝叔達詩因和韻','李曾伯','宋','宋诗','song-poetry','','[]','世事閲江浪，高情寄空雲。',48,'全唐诗/poet.song.214000.json','["世事閲江浪，高情寄空雲。", "佳氣挹西爽，好風來南薰。", "交情懷契闊，行役苦繽紛。", "一節歲寒在，東山有此君。"]'),
('4625651b-67d0-49d2-a3bd-81ab4caa70ae','題醴泉驛  其一','李曾伯','宋','宋诗','song-poetry','','[]','遠役三纔二，憂端萬有斯。',48,'全唐诗/poet.song.214000.json','["遠役三纔二，憂端萬有斯。", "君恩知欲報，子難痛何追。", "我馬方瘏矣，秋陽更暴之。", "願言行役者，當暑戒驅馳。"]'),
('a67e6882-65a8-473d-833a-657b945d6cd2','題醴泉驛  其二','李曾伯','宋','宋诗','song-poetry','','[]','路遥須到日，官滿有歸時。',48,'全唐诗/poet.song.214000.json','["路遥須到日，官滿有歸時。", "一點終身痛，中途孺子悲。", "老難堪此境，咎必有其基。", "扶憊隨緣去，空餘淚雨垂。"]'),
('b0bedc55-0f1b-4d99-9124-a0bf724e035b','題二水光華驛','李曾伯','宋','宋诗','song-poetry','','[]','歷歷湖南道，駸駸嶺右州。',48,'全唐诗/poet.song.214000.json','["歷歷湖南道，駸駸嶺右州。", "感時僧解夏，觸事客驚秋。", "雨洗流金虐，風生落木愁。", "一萍如寄耳，往夢付悠悠。"]'),
('70944a79-a101-49f0-b628-9714e0ea82ab','登獨秀臺和徐意一韻','李曾伯','宋','宋诗','song-poetry','','[]','老樹憑高看，幽禽向靜聽。',48,'全唐诗/poet.song.214000.json','["老樹憑高看，幽禽向靜聽。", "霜輕冬意薄，日正午陰停。", "榻側從他鼾，江頭自獨醒。", "居然山是似，環顧等繁星。"]'),
('63f5e930-88ed-4b9d-b9c6-46dc1864cdbc','出郊劭農口占','李曾伯','宋','宋诗','song-poetry','','[]','小約賓僚集，相招老父耕。',48,'全唐诗/poet.song.214000.json','["小約賓僚集，相招老父耕。", "寺依青带住，人在翠帷行。", "疊嶂堆春色，微雲護午晴。", "時康田里樂，歸騎踏花輕。"]'),
('5b9143b7-62c1-4ba3-9c28-fb482039cf1d','劭農歸遊白龍洞','李曾伯','宋','宋诗','song-poetry','','[]','老龍昔未蛻，嘗蟄此山中。',48,'全唐诗/poet.song.214000.json','["老龍昔未蛻，嘗蟄此山中。", "霖雨春疇足，風雲夜壑空。", "兩崖高下倚，一徑往來通。", "不願千金劑，惟祈百穀豐。"]'),
('576fa68f-e8a0-48f5-92e2-06ea2285b9a0','春日領僚屬遊龍隠巖','李曾伯','宋','宋诗','song-poetry','','[]','久卧蒼崖底，風雷爲擘開。',48,'全唐诗/poet.song.214000.json','["久卧蒼崖底，風雷爲擘開。", "蛻形猶掛石，鱗迹不沾埃。", "一水將清貫，數峰推爽來。", "渾疑負舟去，烟雨肯低佪。"]'),
('5c251f4f-8e8a-4b56-bef1-39ebb24e7092','自和','李曾伯','宋','宋诗','song-poetry','','[]','一壑馮夷宅，五丁盤古開。',48,'全唐诗/poet.song.214000.json','["一壑馮夷宅，五丁盤古開。", "天將作甘澍，地豈著浮埃。", "梭化雷陂去，槎乘星渚來。", "猶疑真隠在，搜訪莫徘徊。"]'),
('1e3b1f3d-e871-4510-9189-e148e52da9f6','題千山觀','李曾伯','宋','宋诗','song-poetry','','[]','玉筍環星拱，青螺带霧披。',48,'全唐诗/poet.song.214000.json','["玉筍環星拱，青螺带霧披。", "山爲天下勝，境占嶺南奇。", "援筆難窮者，凭闌盡有之。", "不因身世累，築室老於斯。"]'),
('95f2b77b-fa38-4a2e-bdea-ca4980db6a07','禁烟前一日招幕屬小集林提幹有詩和韻','李曾伯','宋','宋诗','song-poetry','','[]','草草登樓適，英流邁昔賢。',48,'全唐诗/poet.song.214000.json','["草草登樓適，英流邁昔賢。", "詩篇長慶集，人物永和年。", "訪古宜聯社，傷春又禁烟。", "青帘家酒賤，賸飲莫論錢。"]'),
('b996615f-6b85-435a-acf5-6690c3b9ca78','桂林即事  其一','李曾伯','宋','宋诗','song-poetry','','[]','每測南方候，時驚北客心。',48,'全唐诗/poet.song.214000.json','["每測南方候，時驚北客心。", "一冬無雁過，三月有蛩吟。", "槐暑常臨午，梅霖不待壬。", "近來知節適，不怕瘴烟侵。"]'),
('a663a08f-ccb8-4e71-89ef-6d5f28c3428a','桂林即事  其二','李曾伯','宋','宋诗','song-poetry','','[]','一日四時具，從來五嶺然。',48,'全唐诗/poet.song.214000.json','["一日四時具，從來五嶺然。", "留連落花雨，依約熟梅天。", "瘴重常垂箔，春深未脫綿。", "新來那戒飲，未夜已思眠。"]'),
('673e035a-10e3-4dec-bf82-505ac3d25765','霽後登水雲閣凭欄偶成','李曾伯','宋','宋诗','song-poetry','','[]','雨過雲烟幕，天成水墨屏。',48,'全唐诗/poet.song.214000.json','["雨過雲烟幕，天成水墨屏。", "江添半篙綠，山失數峰青。", "某寺藏松塢，誰舟繫柳汀。", "杜鵑聲正急，那對夕陽聽。"]'),
('0d9830f6-bc94-4fbb-8be6-285fb8e298d1','洞庭口占','李曾伯','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','舟子方將北，封姨不肯南。',48,'全唐诗/poet.song.214000.json','["舟子方將北，封姨不肯南。", "去帆衝急浪，古寺隠晴嵐。", "遠渚鴉千百，中流鷗兩三。", "短篷聊徙倚，底用客程貪。"]'),
('b390d1b3-7c01-475d-8fa8-caa447478586','重過岳陽','李曾伯','宋','宋诗','song-poetry','','[]','遠役數千里，重來十四春。',48,'全唐诗/poet.song.214000.json','["遠役數千里，重來十四春。", "山城風景舊，人物歲時新。", "官舍多陳迹，君山是故人。", "樓頭一杯酒，聊滌客襟塵。"]'),
('89f177fb-ddd2-4892-a796-9157f2cac342','荆閫偶成','李曾伯','宋','宋诗','song-poetry','','[]','一出嶠南道，重來國北門。',48,'全唐诗/poet.song.214000.json','["一出嶠南道，重來國北門。", "詞源因老涸，心鑑以憂昏。", "可厭惟官事，難忘是主恩。", "衷懷誰共語，流得枕邊痕。"]'),
('926e29f4-89b4-4bbc-af26-091028a48108','題范蠡五湖圖  其一','李曾伯','宋','宋诗','song-poetry','','[]','色美示來鑒，功成思去謀。',48,'全唐诗/poet.song.214000.json','["色美示來鑒，功成思去謀。", "桂棹與蘭槳，羔袖而狐裘。", "夏姬宜去楚，妲己肯歸周。", "恤緯寸心在，鑄金千古求。"]'),
('9d616ad7-3d73-4fb2-8590-bb462047a1c8','題范蠡五湖圖  其二','李曾伯','宋','宋诗','song-poetry','','[]','美婦天下有，忠臣古來稀。',48,'全唐诗/poet.song.214000.json','["美婦天下有，忠臣古來稀。", "去國不潔名，避世良知幾。", "寧侶我舟楫，毋著君宮闈。", "平生萬事足，偕老五湖歸。"]'),
('23c0de04-1b9e-4022-8e4d-d5a6cae436a3','題范蠡五湖圖  其三','李曾伯','宋','宋诗','song-poetry','','[]','江湖存魏闕，翰墨寓規箴。',24,'全唐诗/poet.song.214000.json','["江湖存魏闕，翰墨寓規箴。", "君看龍眠畫，當識鴟夷心。"]'),
('168ae4a6-43cd-43bd-ba3c-90038ce20b13','題黎榷院詩軸','李曾伯','宋','宋诗','song-poetry','','[]','別二十三年，來呼泝峽船。',48,'全唐诗/poet.song.214000.json','["別二十三年，來呼泝峽船。", "昨遊春夢爾，故友曉星然。", "廉譽盈詩卷，忠謀在奏編。", "阿蒙頑自若，應笑老窮邊。"]'),
('71253de0-48f1-4d11-88cb-ea6daf132e6d','題林路鈐詩軸','李曾伯','宋','宋诗','song-poetry','','[]','過眼多陳迹，論心只舊時。',48,'全唐诗/poet.song.214000.json','["過眼多陳迹，論心只舊時。", "艱難幾年事，感慨數公詩。", "覓句新尤健，談兵老不衰。", "效顰聊爾耳，莫說姓名誰。"]'),
('7390085a-49e2-4a3c-b2dc-f1573e4bcedd','和吳居父江陵雄楚樓韻','李曾伯','宋','宋诗','song-poetry','','[]','歲月等新戍，風烟只舊遊。',48,'全唐诗/poet.song.214000.json','["歲月等新戍，風烟只舊遊。", "柳薇今堡障，蘋蓼古滄洲。", "索句慚巴和，懷人笑楚優。", "中原雖在目，無事莫登樓。"]'),
('827ddc4f-5aff-463e-98f5-241f8a0ae814','甲申寧廟挽詞  其一','李曾伯','宋','宋诗','song-poetry','','[]','德化勤三紀，仁聲溢九州。',48,'全唐诗/poet.song.214000.json','["德化勤三紀，仁聲溢九州。", "澣衣昭禹儉，昃食軫文憂。", "潤色恢鴻業，艱難啟燕謀。", "中興宗漢廟，端自敬天休。"]'),
('16717bd7-c1a0-4033-9655-b670b31c2421','甲申寧廟挽詞  其二','李曾伯','宋','宋诗','song-poetry','','[]','自聽山東詔，甘泉息夜烟。',48,'全唐诗/poet.song.214000.json','["自聽山東詔，甘泉息夜烟。", "璽膺新玉帛，圖貢舊山川。", "望切堯民日，憂形杞國天。", "中原尤感泣，不獨老臣然。"]'),
('616b10de-67e4-43bf-8e8a-9c4edce04c3b','挽虞滄江提刑  其一','李曾伯','宋','宋诗','song-poetry','','[]','南渡稱名相，西來見嫡孫。',48,'全唐诗/poet.song.214000.json','["南渡稱名相，西來見嫡孫。", "蜀珍交友盛，雍國典刑存。", "桂苑連鳴鹿，楓宸擬簉鵷。", "平生經濟略，雅志在中原。"]'),
('8c3acfc2-7c4e-4369-a11b-e776c200e634','挽虞滄江提刑  其二','李曾伯','宋','宋诗','song-poetry','','[]','隼旟三易守，駰轡兩觀風。',48,'全唐诗/poet.song.214000.json','["隼旟三易守，駰轡兩觀風。", "欲掃龍庭穴，猶參虎幄弓。", "草餘周圄綠，粟積漢屯紅。", "野渡方橫棹，俄成夜壑空。"]'),
('baade8a6-e129-43c3-8055-c58910a592da','挽虞滄江提刑  其三','李曾伯','宋','宋诗','song-poetry','','[]','自得滄江勝，歸來伴鶴龜。',48,'全唐诗/poet.song.214000.json','["自得滄江勝，歸來伴鶴龜。", "晚年尤好易，暇日且論詩。", "欲問更生佛，非關二豎醫。", "諸生毋拭袂，公訓有餘師。"]'),
('0008dcc0-5570-48d9-b086-73bbcdd22225','挽龔致政  其一','李曾伯','宋','宋诗','song-poetry','','[]','師友龜山出，世家熊楚來。',48,'全唐诗/poet.song.214000.json','["師友龜山出，世家熊楚來。", "决科輕地芥，種德付庭槐。", "祿享千鍾養，年登九袠開。", "可爲朝野惜，袖手老其才。"]'),
('301f7998-2e06-4b5f-bf95-7bf096fbc04c','挽龔致政  其二','李曾伯','宋','宋诗','song-poetry','','[]','綉節榮分使，斑衣喜拜親。',48,'全唐诗/poet.song.214000.json','["綉節榮分使，斑衣喜拜親。", "方將昌厥後，豈必在其身。", "真館仙遊遠，佳城瑞氣新。", "九原看厚報，衮衮耀絲綸。"]'),
('49e110ff-0818-4f4e-afa0-4b82c6342a31','挽觀使鄭尚書  其一','李曾伯','宋','宋诗','song-poetry','','[]','許史推華閲，歐韓策雋名。',48,'全唐诗/poet.song.214000.json','["許史推華閲，歐韓策雋名。", "風流接南渡，步武到西清。", "玉帳勞籌筆，彤墀識履聲。", "壯懷馳萬里，誰壞國金城。"]'),
('38f161f4-c5ed-476e-9258-ed306373f06d','挽觀使鄭尚書  其二','李曾伯','宋','宋诗','song-poetry','','[]','秉鉞岷峨去，分弓淮海遊。',48,'全唐诗/poet.song.214000.json','["秉鉞岷峨去，分弓淮海遊。", "安危勤閫略，得失假家謀。", "不易猗蘭操，何傷薏苡羞。", "蓋棺公論定，知罪付春秋。"]'),
('406802c2-ff55-4e8c-9fb5-37fb2c8d145e','挽觀使鄭尚書  其三','李曾伯','宋','宋诗','song-poetry','','[]','憶昨從游日，烏奴桃李春。',48,'全唐诗/poet.song.214000.json','["憶昨從游日，烏奴桃李春。", "通家聯雅好，入幕厠佳賓。", "綠野歸心切，丹山舊迹陳。", "九原多感愴，掩袂重傷神。"]'),
('140f6a3d-fed5-4094-a760-58e190c49d9e','挽吳總幹  其一','李曾伯','宋','宋诗','song-poetry','','[]','慶積家聲遠，材優官業長。',48,'全唐诗/poet.song.214000.json','["慶積家聲遠，材優官業長。", "胡然嗇諸用，竟爾老於鄉。", "德與年何憾，人期後必昌。", "秦原空睇望，惜此典刑亡。"]'),
('a93001f1-0dce-4a33-aa59-6af0a63ef419','挽吳總幹  其二','李曾伯','宋','宋诗','song-poetry','','[]','夙托彌甥列，常懷范叔寒。',48,'全唐诗/poet.song.214000.json','["夙托彌甥列，常懷范叔寒。", "門闌多厚盼，樽俎有餘驩。", "衣笥袍猶戀，書郵墨未乾。", "官身羈執紼，清淚爲公彈。"]'),
('fc93fc54-e3c2-48ae-aa1e-31123454dd5d','挽吳準齋  其一','李曾伯','宋','宋诗','song-poetry','','[]','持此四海準，得之前聖心。',48,'全唐诗/poet.song.214000.json','["持此四海準，得之前聖心。", "簞瓢富臺閣，朝市等山林。", "說破先天易，流傳正始音。", "太原千載後，思者甚於今。"]'),
('e267f20b-38c9-4911-bbb1-26f1396c3834','挽吳準齋  其二','李曾伯','宋','宋诗','song-poetry','','[]','昨綴都人士，嘗薰一瓣香。',48,'全唐诗/poet.song.214000.json','["昨綴都人士，嘗薰一瓣香。", "蒼茫問淮浦，繾綣餞河梁。", "聞道機緣淺，予人風誼長。", "斯文其已矣，草木亦凄涼。"]'),
('f4108179-c8f9-4d69-b2a7-4bdd7b86100c','挽吳文昌母夫人  其一','李曾伯','宋','宋诗','song-poetry','','[]','懿範儒家出，靈臺佛地平。',48,'全唐诗/poet.song.214000.json','["懿範儒家出，靈臺佛地平。", "活人裨惠愛，教子以忠清。", "康肅母無愧，中郎女有聲。", "老天昭德報，蘭桂滿庭榮。"]'),
('c8934636-ebd5-4544-8ef2-d361929cb088','挽吳文昌母夫人  其二','李曾伯','宋','宋诗','song-poetry','','[]','慶事一門盛，修齡七袠强。',48,'全唐诗/poet.song.214000.json','["慶事一門盛，修齡七袠强。", "綸封四大國，綵侍兩文昌。", "夢幻存真覺，勳庸看顯揚。", "家山空睇望，惜此令儀亡。"]'),
('a7104995-4641-45c4-8d56-587094276b80','挽大資節使史國公  其一','李曾伯','宋','宋诗','song-poetry','','[]','德齒明時冠，詩書正派深。',48,'全唐诗/poet.song.214000.json','["德齒明時冠，詩書正派深。", "修名在原隰，雅志已山林。", "眼歷四朝事，神交千聖心。", "老成天不憖，大雅有遺音。"]'),
('a6708c94-dcd4-4e5e-9455-1248aedcfa09','挽大資節使史國公  其二','李曾伯','宋','宋诗','song-poetry','','[]','早袖經綸手，傳之柱石材。',48,'全唐诗/poet.song.214000.json','["早袖經綸手，傳之柱石材。", "無心到孤棘，有德付三槐。", "五鼎方身饗，兩楹俄夢回。", "百年流澤遠，衮衮幾公台。"]'),
('b6fbd953-aa5e-445f-b7de-525fb2f0f22c','挽大資節使史國公  其三','李曾伯','宋','宋诗','song-poetry','','[]','昔綴都曹後，升堂拜父師。',48,'全唐诗/poet.song.214000.json','["昔綴都曹後，升堂拜父師。", "達尊厪異盼，國士沐深知。", "鶴髮人何在，蠅頭字尚遺。", "遣車無路送，揮淚望豐碑。"]'),
('9112730b-5551-401c-9937-e3a378347e82','挽何司令  其一','李曾伯','宋','宋诗','song-poetry','','[]','太學何蕃譽，當時藹帝鄉。',48,'全唐诗/poet.song.214000.json','["太學何蕃譽，當時藹帝鄉。", "五聯棣華萼，三折桂枝香。", "司社騰聲望，題輿迓寵光。", "奇才今已矣，流慶在虹梁。"]'),
('38c198c0-a8a5-415d-9887-7e3f6f491b4b','挽何司令  其二','李曾伯','宋','宋诗','song-poetry','','[]','憶昨初傾蓋，同登巴岳樓。',48,'全唐诗/poet.song.214000.json','["憶昨初傾蓋，同登巴岳樓。", "江淮重邂逅，幕府屢綢繆。", "夢絕秋城柝，人隨夜壑舟。", "潛山歸路杳，草木亦凄愁。"]'),
('39b1cd0d-a004-49e9-83f2-0595ffb04512','挽吳鶴林尚書  其一','李曾伯','宋','宋诗','song-poetry','','[]','鳳翥鶴林邑，來儀鴛鷺群。',48,'全唐诗/poet.song.214000.json','["鳳翥鶴林邑，來儀鴛鷺群。", "陳謨傾帝聽，摛翰媲皇墳。", "位且踐台斗，心惟寄岫雲。", "詔綸方夜下，天曷喪斯文。"]'),
('52610a31-53fb-42c0-af0f-cb47f7a144f3','挽吳鶴林尚書  其二','李曾伯','宋','宋诗','song-poetry','','[]','一代儒臣表，三州吏治良。',48,'全唐诗/poet.song.214000.json','["一代儒臣表，三州吏治良。", "遺言了生死，新誌盡行藏。", "昔夢崖何異，今知坡可方。", "百僚山下路，千載尚名香。"]'),
('21192e96-ccdb-49e2-a94c-147f212703de','挽吳鶴林尚書  其三','李曾伯','宋','宋诗','song-poetry','','[]','寶屏傾蓋早，公壯我丁年。',48,'全唐诗/poet.song.214000.json','["寶屏傾蓋早，公壯我丁年。", "入幕笑談舊，升朝禮樂先。", "寄書榆柳外，覓句竹梅邊。", "俯仰成疇昔，空餘涕泗漣。"]'),
('dc01b39f-ff09-4439-8e1b-290e67c72944','挽李樓山觀文  其一','李曾伯','宋','宋诗','song-poetry','','[]','展也岷峨秀，鍾爲柱石臣。',48,'全唐诗/poet.song.214000.json','["展也岷峨秀，鍾爲柱石臣。", "直聲留諫紙，碩望壓朝紳。", "群議王師銳，孤忠主聽陳。", "天其昌我宋，堯舜致君民。"]'),
('c9067acf-4691-4bfa-bfed-12cb1b58c7bc','挽李樓山觀文  其二','李曾伯','宋','宋诗','song-poetry','','[]','兩登樞輔地，一武宰衡班。',48,'全唐诗/poet.song.214000.json','["兩登樞輔地，一武宰衡班。", "利澤纔膺寸，良方縮肘間。", "重爲千載惜，竟老十年閑。", "回首西州夢，吳中第幾山。"]'),
('bcfdadcc-e429-4aec-af0d-d6230d044ea7','挽李樓山觀文  其三','李曾伯','宋','宋诗','song-poetry','','[]','相從劍南幕，公壯我丁年。',48,'全唐诗/poet.song.214000.json','["相從劍南幕，公壯我丁年。", "寘彼諸生後，薦之明主前。", "承顔台衮近，托跡午橋邊。", "壤厦千秋隔，潸然老淚漣。"]'),
('b2cda01a-3927-4dc6-bc8d-df2f3ee41b32','挽肇慶胡守  其一','李曾伯','宋','宋诗','song-poetry','','[]','湖學源流盛，鄉評聞望推。',48,'全唐诗/poet.song.214000.json','["湖學源流盛，鄉評聞望推。", "班纔列留邸，材豈止分麾。", "正擬梅邊喜，俄成薤上悲。", "人言公不死，蘭砌典刑垂。"]'),
('574769be-fc32-42ca-ab89-45e22a500c22','挽肇慶胡守  其二','李曾伯','宋','宋诗','song-poetry','','[]','里閈游從早，江淮契闊稠。',48,'全唐诗/poet.song.214000.json','["里閈游從早，江淮契闊稠。", "勤君分月駕，共我濟風舟。", "日者言猶在，辰乎嘆莫留。", "佳城雲水隔，老淚逐江流。"]'),
('aea86b10-9b6f-4b6b-88eb-e6683694849f','挽蜀帥趙侍郎  其一','李曾伯','宋','宋诗','song-poetry','','[]','蜀頼宗臣力，劍光星斗高。',48,'全唐诗/poet.song.214000.json','["蜀頼宗臣力，劍光星斗高。", "位纔登豹尾，身幾付鴻毛。", "節概公何慊，時艱運適遭。", "岷山如不壞，難泯此忠勞。"]'),
('99a3c680-b4ce-4b53-bd46-7d273b5df40f','挽蜀帥趙侍郎  其二','李曾伯','宋','宋诗','song-poetry','','[]','西證膏肓急，人推倉扁醫。',48,'全唐诗/poet.song.214000.json','["西證膏肓急，人推倉扁醫。", "惜哉當局晚，爲此厲階誰。", "公在民猶望，公亡事轉危。", "忠魂千古在，近有紫巖知。"]'),
('82888c27-16b2-4c92-9448-764ed6726252','池陽清泉舊名鮑公泉又名趙公泉真西山易爲清泉坦齋作記','李曾伯','宋','宋诗','song-poetry','','[]','泉流巖竇本來清，易以清名亦狥名。',32,'全唐诗/poet.song.214000.json','["泉流巖竇本來清，易以清名亦狥名。", "却笑兩公徒蚌鷸，如今贏得坦齋聲。"]'),
('025d5242-00f3-4266-8c5d-31996d903684','舟過霅川  其一','李曾伯','宋','宋诗','song-poetry','','[]','一簇樓臺鎖翠烟，雨疏溪闊晚秋天。',32,'全唐诗/poet.song.214000.json','["一簇樓臺鎖翠烟，雨疏溪闊晚秋天。", "西風吹老芙蓉院，兩兩鷗鳬傍水眠。"]'),
('26711819-5f50-4cf4-83b5-516ca79eee8c','舟過霅川  其二','李曾伯','宋','宋诗','song-poetry','','[]','水繞眉峰碧一灣，荻花楓葉暮生寒。',32,'全唐诗/poet.song.214000.json','["水繞眉峰碧一灣，荻花楓葉暮生寒。", "呼船催向漁村宿，要買鮮鱸薦晚餐。"]'),
('439ed90c-0bf9-4452-935f-b414f86d7a1f','過鄰水道間','李曾伯','宋','宋诗','song-poetry','','[]','竹新得雨筍爭綠，蕉不知霜花自紅。',32,'全唐诗/poet.song.214000.json','["竹新得雨筍爭綠，蕉不知霜花自紅。", "時候江南二三月，調胹元氣此杯中。"]'),
('2c69a202-2d99-4815-9e2e-a7df2fe73210','鄰水寺有竹數百竿中有孤梅可愛','李曾伯','宋','宋诗','song-poetry','','[]','蕭蕭勁竹古君子，凜凜孤梅節婦人。',32,'全唐诗/poet.song.214000.json','["蕭蕭勁竹古君子，凜凜孤梅節婦人。", "不作東風蝴蝶夢，短籬流水一家春。"]'),
('43ec3fa4-908a-4317-a414-6f1e5f5af9dd','訪閬州讀書巖','李曾伯','宋','宋诗','song-poetry','','[]','從來廊廟出山林，師友相資好弟兄。',32,'全唐诗/poet.song.214000.json','["從來廊廟出山林，師友相資好弟兄。", "料得至今風雨夜，山神猶記讀書聲。"]'),
('c4a7e234-9672-4f09-ba7b-0f2650f559ef','題利州道上江月軒','李曾伯','宋','宋诗','song-poetry','','[]','何用朝朝夜夜鐘，一拳打透徹虛空。',32,'全唐诗/poet.song.214000.json','["何用朝朝夜夜鐘，一拳打透徹虛空。", "詩僧不見禪僧老，月自西沉江自東。"]'),
