('cf62275b-23e8-477b-9cf2-1a88db6983d0','自和山房十詠  其四','李曾伯','宋','宋诗','song-poetry','','[]','人生須富貴何時，駟馬還家只布衣。',32,'全唐诗/poet.song.214000.json','["人生須富貴何時，駟馬還家只布衣。", "林壑幸便麋鹿侶，不堪寒色逐人歸。"]'),
('6de2e42c-06f8-4863-94f2-91ad84425e16','自和山房十詠  其五','李曾伯','宋','宋诗','song-poetry','','[]','禪房寂寂夜昏昏，相對長明一點燈。',32,'全唐诗/poet.song.214000.json','["禪房寂寂夜昏昏，相對長明一點燈。", "舉似新詩共僧話，笑儂綺語污溪藤。"]'),
('ac343b7d-354c-4ae1-98c2-cbb216c0a6ba','自和山房十詠  其六','李曾伯','宋','宋诗','song-poetry','','[]','尺寸功名幾短長，區區馳騖等空忙。',32,'全唐诗/poet.song.214000.json','["尺寸功名幾短長，區區馳騖等空忙。", "皮毛盡剝丹心在，世味風霜已飽嘗。"]'),
('49084370-6432-4bc1-8093-e26b9aff410a','自和山房十詠  其七','李曾伯','宋','宋诗','song-poetry','','[]','蕭蕭風籟助清吟，秋去冬來令又更。',32,'全唐诗/poet.song.214000.json','["蕭蕭風籟助清吟，秋去冬來令又更。", "惟有老禪都不管，任它簷鐸作何聲。"]'),
('a120acb8-5090-43d9-afc8-c3e119146a90','自和山房十詠  其八','李曾伯','宋','宋诗','song-poetry','','[]','鄰有山田價似輕，擬求種秫效淵明。',32,'全唐诗/poet.song.214000.json','["鄰有山田價似輕，擬求種秫效淵明。", "相逢村叟問誰者，歎息年來主屢更。"]'),
('af9e660a-fa63-49a2-97d1-884ca9db24bb','自和山房十詠  其九','李曾伯','宋','宋诗','song-poetry','','[]','真機渾不露中邊，自是閑中小有天。',32,'全唐诗/poet.song.214000.json','["真機渾不露中邊，自是閑中小有天。", "一飲且拚今日醉，萬金不博五更眠。"]'),
('c603f539-93b4-4259-b428-de33ea058e35','自和山房十詠  其一○','李曾伯','宋','宋诗','song-poetry','','[]','舟子來催歸去休，朔風吹浪打船頭。',32,'全唐诗/poet.song.214000.json','["舟子來催歸去休，朔風吹浪打船頭。", "挑包又作家林計，還是梅開酒熟不。"]'),
('24285135-a074-46a4-8267-d7858f964449','定花阻風  其一','李曾伯','宋','宋诗','song-poetry','','[]','客纜相銜繫柳邊，不禁雪浪苦粘天。',32,'全唐诗/poet.song.214000.json','["客纜相銜繫柳邊，不禁雪浪苦粘天。", "尋常溪口魚蝦賤，今度船留倍索錢。"]'),
('ed39d76b-d281-439c-948f-199d8c611eb9','定花阻風  其二','李曾伯','宋','宋诗','song-poetry','','[]','準擬新烟定到家，可憐漂泊對風沙。',32,'全唐诗/poet.song.214000.json','["準擬新烟定到家，可憐漂泊對風沙。", "見他紅雨飛籬落，憶殺小園桃杏花。"]'),
('3ab28d4f-44ec-4c81-840d-50e53495097a','定花阻風  其三','李曾伯','宋','宋诗','song-poetry','','[]','綠柳橋頭舊酒爐，幾番艤棹勞篙夫。',32,'全唐诗/poet.song.214000.json','["綠柳橋頭舊酒爐，幾番艤棹勞篙夫。", "恍疑風撤青帘去，敲盡荆扉閉不酤。"]'),
('736805ae-3525-4e60-8dd0-57b273171083','定花阻風  其四','李曾伯','宋','宋诗','song-poetry','','[]','夜色昏昏带遠烟，誰家燈火待歸船。',32,'全唐诗/poet.song.214000.json','["夜色昏昏带遠烟，誰家燈火待歸船。", "小遲月上風須息，且伴白鷗今夕眠。"]'),
('6f1fa1bc-4e1b-4e5a-9e2c-f5417e9e2599','定花阻風  其五','李曾伯','宋','宋诗','song-poetry','','[]','邊湖六六片時程，况可籃輿度岸行。',32,'全唐诗/poet.song.214000.json','["邊湖六六片時程，况可籃輿度岸行。", "西舫東船從此辦，任他風浪與陰晴。"]'),
('bd8d4fe4-d36e-43cd-ad87-d85f4f2c4481','和傅山父小園十詠  其一','李曾伯','宋','宋诗','song-poetry','','[]','剖破藩籬出一頭，要追巖壑老人游。',32,'全唐诗/poet.song.214000.json','["剖破藩籬出一頭，要追巖壑老人游。", "知他栽得花和竹，髣髴舊時風度不。"]'),
('bb0e9f0f-5b0c-498b-9a0f-d6a2416389ff','和傅山父小園十詠  其二','李曾伯','宋','宋诗','song-poetry','','[]','喬木豈能忘故國，結茅聊復紀新亭。',32,'全唐诗/poet.song.214000.json','["喬木豈能忘故國，結茅聊復紀新亭。", "此君玉立傍無友，猶有幽禽靜可聽。"]'),
('6a892be4-5714-4538-bc92-34249b010cef','和傅山父小園十詠  其三','李曾伯','宋','宋诗','song-poetry','','[]','著我數椽浮翠碧，借公一水漾琉璃。',32,'全唐诗/poet.song.214000.json','["著我數椽浮翠碧，借公一水漾琉璃。", "心閑境樂鎮長好，拈起風光總是詩。"]'),
('c2baf3c5-c174-4d48-8ca2-14f6d91a7794','和傅山父小園十詠  其四','李曾伯','宋','宋诗','song-poetry','','[]','竹邊聞鶴思高舉，松下觀禽覺倦飛。',32,'全唐诗/poet.song.214000.json','["竹邊聞鶴思高舉，松下觀禽覺倦飛。", "幸有故書千帙在，呼兒共讀嗣前徽。"]'),
('1d660cfb-9bd6-48b0-83de-0331c0c7f81a','和傅山父小園十詠  其五','李曾伯','宋','宋诗','song-poetry','','[]','蒼苔迹在堂無燕，綠水痕生沼自魚。',32,'全唐诗/poet.song.214000.json','["蒼苔迹在堂無燕，綠水痕生沼自魚。", "回首釣遊徒感慨，何時復古喜而書。"]'),
('e350789e-279a-4627-960f-4325a4084bee','和傅山父小園十詠  其六','李曾伯','宋','宋诗','song-poetry','','[]','招來暇日頻呼酒，買得清風不用金。',32,'全唐诗/poet.song.214000.json','["招來暇日頻呼酒，買得清風不用金。", "月姊水妃無老態，天光野色有遺音。"]'),
('01947c95-868c-4697-8561-1588a23f68bb','和傅山父小園十詠  其七','李曾伯','宋','宋诗','song-poetry','','[]','一室掃除才斗許，幾番醉夢與梅清。',32,'全唐诗/poet.song.214000.json','["一室掃除才斗許，幾番醉夢與梅清。", "琱戈翠節成何事，紙帳蒲團了此生。"]'),
('7d99ab05-1ca5-4d7c-afa7-8e3cefac42f1','和傅山父小園十詠  其八','李曾伯','宋','宋诗','song-poetry','','[]','宜琴宜弈尤宜酒，種竹種梅仍種蓮。',32,'全唐诗/poet.song.214000.json','["宜琴宜弈尤宜酒，種竹種梅仍種蓮。", "意得無時不堪適，可人不只是荷天。"]'),
('8751d92c-01aa-42c7-82df-0c1b26e01e5e','和傅山父小園十詠  其九','李曾伯','宋','宋诗','song-poetry','','[]','賸種秫秔供靖節，要餐杞菊學天隨。',32,'全唐诗/poet.song.214000.json','["賸種秫秔供靖節，要餐杞菊學天隨。", "不知底事池塘夢，猶到邊城月暗時。"]'),
('b2814e60-e875-463d-8c3a-43e086677828','和傅山父小園十詠  其一○','李曾伯','宋','宋诗','song-poetry','','[]','蠟英要占菊天破，玉樹須乘梅雨培。',32,'全唐诗/poet.song.214000.json','["蠟英要占菊天破，玉樹須乘梅雨培。", "金粟如來還出世，清香不許別花開。"]'),
('6ef147d0-d9a2-404a-a12c-26928d5c146f','和水竹梅燭韻  其一','李曾伯','宋','宋诗','song-poetry','','[]','南枝肯領衆芳隨，一點冠名在處知。',32,'全唐诗/poet.song.214000.json','["南枝肯領衆芳隨，一點冠名在處知。", "摸索暗中香自別，底須絳蠟逼輕肌。"]'),
('398ab870-ae66-46f5-bd55-95d9e5f2819c','和水竹梅燭韻  其二','李曾伯','宋','宋诗','song-poetry','','[]','誰將花燭聘東風，與海棠時恨不同。',32,'全唐诗/poet.song.214000.json','["誰將花燭聘東風，與海棠時恨不同。", "意已不求真會合，何妨一白對千紅。"]'),
('91c73537-8a05-4bb4-96da-2975d5192650','登桂林宜樓和李帥柱間韻','李曾伯','宋','宋诗','song-poetry','','[]','誰言南服遠王畿，面面青山總是詩。',32,'全唐诗/poet.song.214000.json','["誰言南服遠王畿，面面青山總是詩。", "桂後梅前正清淑，倚樓但覺九秋宜。"]'),
('78b804d0-482a-4648-9c38-0ed2da2e03b5','送李琴士據梧  其一','李曾伯','宋','宋诗','song-poetry','','[]','流水高山爾調，冷灰槁木吾心。',28,'全唐诗/poet.song.214000.json','["流水高山爾調，冷灰槁木吾心。", "不必神交蒙叟，柴桑老子知音。"]'),
('099a44d9-052a-4e58-94dc-a68828d6d1c6','送李琴士據梧  其二','李曾伯','宋','宋诗','song-poetry','','[]','戶外世塵皆累，山中天籟無聲。',28,'全唐诗/poet.song.214000.json','["戶外世塵皆累，山中天籟無聲。", "莫看螗蟬相捕，要教鶴舞魚聽。"]'),
('84fbc2c8-b059-4f38-9f35-7c1b6f9282da','題馮司法水月書堂  其一','李曾伯','宋','宋诗','song-poetry','','[]','水能清亦能濁，月有滿亦有虧。',28,'全唐诗/poet.song.214000.json','["水能清亦能濁，月有滿亦有虧。", "清濁滿虧區別，馮君書以知之。"]'),
('61df96e7-7f7a-498f-a5ba-ddb668c1da84','題馮司法水月書堂  其二','李曾伯','宋','宋诗','song-poetry','','[]','玉局仙翁公案，梅亭老子偈言。',28,'全唐诗/poet.song.214000.json','["玉局仙翁公案，梅亭老子偈言。", "莫向空中捉影，要須達處窮源。"]'),
('3d60bb80-c006-485e-befb-62613995f683','丙子登峴山','李曾伯','宋','宋诗','song-poetry','','[]','漢江爲带楚山維，多少興亡此地知。',64,'全唐诗/poet.song.214000.json','["漢江爲带楚山維，多少興亡此地知。", "萬里邊風寒故壘，千年隴月老殘碑。", "塵迷柏土龍根幻，水繞檀溪馬骨悲。", "舉世豈無羊叔子，草萊猶未起男兒。"]'),
('d1b4426f-0f9e-4a0d-82c9-17fb91e5d903','宿江州藥王寺','李曾伯','宋','宋诗','song-poetry','','[]','指點烟林正午鐘，亭亭樓閣有無中。',64,'全唐诗/poet.song.214000.json','["指點烟林正午鐘，亭亭樓閣有無中。", "鋪張翠蓋松間日，掃灑紅塵竹外風。", "啼鳥不驚禪入定，落花無跡色成空。", "解鞍暫作今宵歇，恰與雲堂旦過同。"]'),
('8c755db6-b0bb-4807-91bc-cd3f368034f4','壬午昌化道間','李曾伯','宋','宋诗','song-poetry','','[]','暑雨祁寒路兩經，二童一馬影竛竮。',64,'全唐诗/poet.song.214000.json','["暑雨祁寒路兩經，二童一馬影竛竮。", "簷花夜滴溪添綠，雲葉暮橫山減青。", "篛笠芒鞋今古道，竹籬茅店短長亭。", "未妨老子登臨興，解却征鞍且暫停。"]'),
('b005a6ab-9c27-4b60-ba4a-cd906f816aca','過廬山','李曾伯','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','問訊匡廬幾度經，何時袖手摘天星。',64,'全唐诗/poet.song.214000.json','["問訊匡廬幾度經，何時袖手摘天星。", "世如春夢空頭白，山似故人終眼青。", "便欲移文尋鶴帳，又還呼渡過鷗汀。", "它年學得香山士，定結茅庵入翠屏。"]'),
('c7a35544-ee87-4203-829c-4fe66d78cb5d','寧國道間喜晴','李曾伯','宋','宋诗','song-poetry','','[]','怪得虛簷寂溜聲，起來雲淡月微明。',64,'全唐诗/poet.song.214000.json','["怪得虛簷寂溜聲，起來雲淡月微明。", "只消一夜西風力，盡掃千山宿霧清。", "農舍少酬終歲望，客途擬過小春晴。", "枝禽亦似欣欣意，飛入烟林自在鳴。"]'),
('91ab6298-b8af-4ebe-affe-8c04827f65cb','寧國道間即事','李曾伯','宋','宋诗','song-poetry','','[]','楓染酏顔菊亦酣，霜天風味飽相諳。',64,'全唐诗/poet.song.214000.json','["楓染酏顔菊亦酣，霜天風味飽相諳。", "馬蹄去去江之北，雁影來來塞以南。", "雲外數峰輕抹翠，雨餘一水碎挼藍。", "肩輿催問誰家宿，落日西山已半含。"]'),
('d2b440b9-ea85-4d7b-a812-edc2c8fd88f8','蜀江和周昞仲百丈韻','李曾伯','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','欲知峽路打灘渦，千尺蒼筠用力多。',64,'全唐诗/poet.song.214000.json','["欲知峽路打灘渦，千尺蒼筠用力多。", "進退不煩篙影動，東西惟聽柁師呵。", "命垂一縷惟天耳，力挽千鈞如水何。", "爭似錢塘江上路，夜深柔櫓聽吳歌。"]'),
('c3142afb-d6a0-4108-8416-212ae7be8ae6','和周昞仲過踏洞灘','李曾伯','宋','宋诗','song-poetry','','[]','堪憐濆淖上舟難，爭似山坳住舍安。',64,'全唐诗/poet.song.214000.json','["堪憐濆淖上舟難，爭似山坳住舍安。", "雷鼓喧呼人挽纜，風鬟笑語女盤灘。", "倦憑秫酒生春思，愁怯衾裘禦夜寒。", "多謝新詩慰牢落，燈前一笑病懷寬。"]'),
('379efc28-407a-4cad-9a42-bb9f3435d6b3','題雙廟鎮峽樓','李曾伯','宋','宋诗','song-poetry','','[]','峰巍鼇柱疑媧立，地峻龍門自禹開。',64,'全唐诗/poet.song.214000.json','["峰巍鼇柱疑媧立，地峻龍門自禹開。", "山色半昏朝欲雨，灘聲不蟄夜何雷。", "雲屏烟障相迎送，沙鳥風檣幾去來。", "徙倚闌干不知倦，一詩彈壓愧非材。"]'),
('64b18106-9a32-4a81-87c7-292f3e6b9ad3','題孔明白帝二祠','李曾伯','宋','宋诗','song-poetry','','[]','安劉事固異危劉，相去英雄二百秋。',64,'全唐诗/poet.song.214000.json','["安劉事固異危劉，相去英雄二百秋。", "火德方中徒僣帝，星營何隕遽亡侯。", "草廬龍去存吳恨，陛戟蛙狂遺漢羞。", "成敗不同俱廟食，寧非霸業結偏州。"]'),
('ab152848-9ee4-40be-924e-48afcc05d0b8','連日過灘','李曾伯','宋','宋诗','song-poetry','','[]','一灘纔過一灘催，雖若危哉亦壯哉。',64,'全唐诗/poet.song.214000.json','["一灘纔過一灘催，雖若危哉亦壯哉。", "白狗甫隨狼尾去，黄牛又逐虎頭來。", "狂瀾逐淖幾成沸，墜石穿江亂作堆。", "堪笑舟人詫春漲，泝流難及順流回。"]'),
('7fb4fc84-3876-449a-995a-2bfb135dacc5','昭君溪','李曾伯','宋','宋诗','song-poetry','','[]','巴峽向來惟屈姊，漢宮奚事出明姬。',64,'全唐诗/poet.song.214000.json','["巴峽向來惟屈姊，漢宮奚事出明姬。", "當時本有平戎術，中國難容絕世姿。", "忍死定仇婁敬策，惜生不遇武皇時。", "後人却恨毛延壽，斷送春風入遠夷。"]'),
('b14a8f61-07eb-4729-bbe1-ad11a1c79a0c','益昌官舍簡昞仲','李曾伯','宋','宋诗','song-poetry','','[]','不管天涯與海瀕，萬紅千紫一番新。',64,'全唐诗/poet.song.214000.json','["不管天涯與海瀕，萬紅千紫一番新。", "樓頭鐘鼓三更雨，牆外鶑花二月春。", "風軟雁奴歸羽急，日遲鳩婦喚聲頻。", "青門載酒渾閑事，愁殺英雄老塞塵。"]'),
('fc53bbcb-75ea-4d87-9ca0-7aefc4337724','初夏即事簡昞仲','李曾伯','宋','宋诗','song-poetry','','[]','夏雲方建漢旗赤，春事已如周轍東。',64,'全唐诗/poet.song.214000.json','["夏雲方建漢旗赤，春事已如周轍東。", "幾度炎涼經嫩綠，一番榮辱委殘紅。", "杜鵑豈爲歸心設，蝴蝶也無清夢通。", "萬里天涯喜强健，賸開窗牖納南風。"]'),
('1ff8a90f-4097-498f-8867-65bc3898e010','利州登棧道','李曾伯','宋','宋诗','song-poetry','','[]','足跡初來劍北州，試登危棧瞰江流。',64,'全唐诗/poet.song.214000.json','["足跡初來劍北州，試登危棧瞰江流。", "萬山西接地窮處，一水東歸天盡頭。", "欲訪殽函無健馬，相忘楚漢付輕鷗。", "丈夫要了中原事，未分持竿老釣舟。"]'),
('b9233ae6-0cc6-4aee-baf1-17e1a421e1e4','侍親勞監遊雪峰','李曾伯','宋','宋诗','song-poetry','','[]','一水橫橋碧作彎，兩山排闥翠成環。',64,'全唐诗/poet.song.214000.json','["一水橫橋碧作彎，兩山排闥翠成環。", "寺居野色烟光外，春在人情物意間。", "點檢花稍香淺淺，摩娑苔刻字斑斑。", "門前車馬空來去，雲自無心鳥自還。"]'),
('97d04a50-ac7c-4db8-a803-2399d810e7f3','丙戌春過梓潼即事','李曾伯','宋','宋诗','song-poetry','','[]','天公殊不間西東，物意人情處處同。',64,'全唐诗/poet.song.214000.json','["天公殊不間西東，物意人情處處同。", "麥壟綠雛猶欠雨，花蹊紅穉不禁風。", "子規又喚天涯客，布穀還催田舍翁。", "欲挽遊絲網春住，歸鞍催我又匆匆。"]'),
('dd79355f-f923-4840-8b8d-6a9920939d86','宿柳池松風亭','李曾伯','宋','宋诗','song-poetry','','[]','軋軋肩輿上劍門，春和身健快於奔。',64,'全唐诗/poet.song.214000.json','["軋軋肩輿上劍門，春和身健快於奔。", "風翻紅雨摧芳信，山带青烟入燒痕。", "領略物華無好句，破除旅思有清樽。", "高人喜與松風接，莫遣梨花到夢魂。"]'),
('1d0664b6-8904-448d-b35f-b5199d8b5bf7','丁亥沔陽春時即事簡吳叔永','李曾伯','宋','宋诗','song-poetry','','[]','朝來漸可試春衣，弩末輕寒力已微。',64,'全唐诗/poet.song.214000.json','["朝來漸可試春衣，弩末輕寒力已微。", "木葉未繁山尚瘦，桃花欲落水初肥。", "疆陲虜逐征鴻去，庭館人隨社燕歸。", "紫陌青門無恙在，不妨携酒問芳菲。"]'),
('48dad666-2325-43fc-9ab9-96516be1eca9','題漢中嶓冢觀高祖廟試劍石','李曾伯','宋','宋诗','song-poetry','','[]','手袖干將射斗牛，當時天意在興劉。',64,'全唐诗/poet.song.214000.json','["手袖干將射斗牛，當時天意在興劉。", "不勞游刃烹秦鹿，直以餘鋒剪楚猴。", "將相豈煩加越砥，寬仁自足淬吳鈎。", "斷蛇斷石都休問，遺恨平城雨雪羞。"]'),
('b09e0a16-802f-4b13-9ab2-93ebefa7ad37','道間懷益昌總所海棠','李曾伯','宋','宋诗','song-poetry','','[]','點點紅妝綴綠枝，睡猶未足已相宜。',64,'全唐诗/poet.song.214000.json','["點點紅妝綴綠枝，睡猶未足已相宜。", "欠呼杜老供吟筆，僅約楊妃倒酒巵。", "數日以來應爛漫，一風之後想離披。", "憑誰警戒司花女，密遣輕陰謹護持。"]'),
('ea5a1354-bc6c-4f65-aa56-d286909477dc','重陽登益昌錦屏山','李曾伯','宋','宋诗','song-poetry','','[]','徙倚闌干目送間，山容如我亦蒼顔。',64,'全唐诗/poet.song.214000.json','["徙倚闌干目送間，山容如我亦蒼顔。", "恍思戲馬登吳會，擬逐飛鴻度漢關。", "草木與俱嗟歲月，古今無恙只江山。", "天公幸自無風雨，一笑黄花分也慳。"]'),
('1ae91fa3-d27e-4fbd-96f6-da5d8dac189b','和吳叔永見寄韻  其一','李曾伯','宋','宋诗','song-poetry','','[]','眼空凡馬絕全牛，肯念江萍萬里浮。',64,'全唐诗/poet.song.214000.json','["眼空凡馬絕全牛，肯念江萍萬里浮。", "一倡朱絃補騷雅，片言華衮續春秋。", "禮羅自昔須溫造，文館而今欠薛收。", "要任丘墟百年責，慎毋樽俎上南樓。"]'),
('6b17ceb7-24f0-470c-9598-562fc0ab5071','和吳叔永見寄韻  其二','李曾伯','宋','宋诗','song-poetry','','[]','詩懷今古浩無垠，誰寄梅花隴首人。',64,'全唐诗/poet.song.214000.json','["詩懷今古浩無垠，誰寄梅花隴首人。", "芻豢悅心文字趣，筌蹄忘象性情真。", "相望夜月袁宏渚，一洗西風庾亮塵。", "我欲蓴鱸便歸去，雁來應問五湖春。"]'),
('0ccfcf7e-9478-4d92-9bbb-97e87ce7d2e5','送糟蟹遺制幕','李曾伯','宋','宋诗','song-poetry','','[]','江鄉霜後飽珍肴，萬里持來僅带糟。',64,'全唐诗/poet.song.214000.json','["江鄉霜後飽珍肴，萬里持來僅带糟。", "雖惜橫戈酣白蟻，尚知解甲護紅膏。", "開樽祗覺牽歸興，作賦猶當繼老饕。", "油幕晚寒梅影靜，亟持大白薦雙螯。"]'),
('24f54bee-f98b-495b-b090-fc32db9b0faf','和夔門開濟堂韻','李曾伯','宋','宋诗','song-poetry','','[]','世事紛更局面棋，滔滔逝水只東之。',64,'全唐诗/poet.song.214000.json','["世事紛更局面棋，滔滔逝水只東之。", "幾堆頑石鬼神護，一節高風今古奇。", "司馬豈能無戰壘，卧龍祗合在籌帷。", "將星一落空遺恨，費盡詩人幾許詩。"]'),
('ccac8ee9-214e-481c-a4b0-4c4daea73967','宿新政縣登鮮于氏離堆拜顔魯公遺像公曾赴蓬州作鮮于氏碑','李曾伯','宋','宋诗','song-poetry','','[]','屹屹金城唐砥柱，如何流落向蓬州。',64,'全唐诗/poet.song.214000.json','["屹屹金城唐砥柱，如何流落向蓬州。", "一時名節猶山重，千古忠魂與水流。", "不待遺文垂紀錄，自存生氣沮姦謀。", "當時誰挽浯溪水，爲洗離堆一段愁。"]'),
('f6d2b846-c62e-459d-b40f-1c7e8ea3683d','至金泉登聚鶴樓','李曾伯','宋','宋诗','song-poetry','','[]','我住華亭慣識伊，九皋仙去逐雲飛。',64,'全唐诗/poet.song.214000.json','["我住華亭慣識伊，九皋仙去逐雲飛。", "北山久爲悲空帳，赤壁還曾夢羽衣。", "姑和黄樓崔顥賦，爲邀華表令威歸。", "腰纏却笑揚州客，應對金泉媿子微。"]'),
('02eb017b-17a1-44a9-aeda-1ac12d463000','登江陵沙市楚樓','李曾伯','宋','宋诗','song-poetry','','[]','徙倚闌干日未斜，四圍不著一山遮。',64,'全唐诗/poet.song.214000.json','["徙倚闌干日未斜，四圍不著一山遮。", "浪花滾滾翻春雪，烟樹霏霏夾暮霞。", "壯麗中居荆楚會，風流元向蜀吳誇。", "樓頭恰稱元龍卧，切勿輕嗤作酒家。"]'),
('bc881236-83f7-42be-9573-26518c895a1d','簡項仲宗遊亭皋','李曾伯','宋','宋诗','song-poetry','','[]','試從沙渚入荆城，十里金堤掌樣平。',64,'全唐诗/poet.song.214000.json','["試從沙渚入荆城，十里金堤掌樣平。", "曉露香留紅芰濕，午風清逐白蘋生。", "柳邊繫馬頻酤酒，沙際呼魚旋作羹。", "所欠直惟佳客耳，明朝能輟暇偕行。"]'),
('8ebc5861-cdf0-4456-b230-c93899888f29','宜城道間','李曾伯','宋','宋诗','song-poetry','','[]','蕭蕭風雨問南關，客裏單衣八月寒。',64,'全唐诗/poet.song.214000.json','["蕭蕭風雨問南關，客裏單衣八月寒。", "燈火數家棲逆旅，江山千里走卑官。", "飄零岐路憑詩紀，寂寞襟懷借酒寬。", "亟寫音書寄鄉國，北山高卧儘平安。"]'),
('d4740777-35f1-4f1d-b6bc-483c98bf6d30','送清湘蔣尉  其一','李曾伯','宋','宋诗','song-poetry','','[]','我學言詩詩不奇，蔣君言命却能詩。',64,'全唐诗/poet.song.214000.json','["我學言詩詩不奇，蔣君言命却能詩。", "歲寒如許松不改，春信未來梅已知。", "丘壑何如歸去好，江湖終匪老來宜。", "辰州極去湘南近，辦取柴桑三徑資。"]'),
('61d0605a-7a07-4f02-ac2a-db8f10ab92b1','送清湘蔣尉  其二','李曾伯','宋','宋诗','song-poetry','','[]','昔插金蓮醉五泉，與君抵掌共談天。',64,'全唐诗/poet.song.214000.json','["昔插金蓮醉五泉，與君抵掌共談天。", "蜀山歷遍數千里，荆渚重逢八九年。", "子爲丹砂行作吏，我無金鼎可求仙。", "更憐不是春風手，雪意垂垂送去船。"]'),
('aae744f9-0597-4b93-a66a-d61d17f8dfdb','和闕幹雪中韻  其一','李曾伯','宋','宋诗','song-poetry','','[]','夜來白鳳下天潢，幻得人間玉樣光。',64,'全唐诗/poet.song.214000.json','["夜來白鳳下天潢，幻得人間玉樣光。", "萬里園林變春景，幾家籬落失秋香。", "黄紬歌枕水爲骨，紙帳吟梅鐵作腸。", "爭似城南老夫婦，地爐相對擁蒲穰。"]'),
('dd9b89a3-56d9-46cd-8053-c6e4906ba3a7','和闕幹雪中韻  其二','李曾伯','宋','宋诗','song-poetry','','[]','青女欺寒未肯霜，先將銀鑠散祥光。',64,'全唐诗/poet.song.214000.json','["青女欺寒未肯霜，先將銀鑠散祥光。", "芙蓉曉院不禁老，薝蔔滿林惟欠香。", "冷入寶環銷翠羽，聲隨石鼎煮羊腸。", "兔園賦罷誰能繼，留得詩人祝歲穰。"]'),
('31d7de7a-9307-4e42-9cdc-db3608f4606e','題荆門蒙泉','李曾伯','宋','宋诗','song-poetry','','[]','向來亭上醉流杯，千朶蓮花一樹梅。',64,'全唐诗/poet.song.214000.json','["向來亭上醉流杯，千朶蓮花一樹梅。", "金炬依然霜不管，瓊琚猶待雪相催。", "凌波仙子欣無恙，姑射真人喚不來。", "風景則同懷抱異，倚欄欲去更徘徊。"]'),
('ea775787-007b-4c7e-9438-d03daec94d29','偕張總幹章帥機同游檀溪登極目和韻  其一','李曾伯','宋','宋诗','song-poetry','','[]','底須風景歎新亭，且聽樽前賤子陳。',64,'全唐诗/poet.song.214000.json','["底須風景歎新亭，且聽樽前賤子陳。", "拚却玉山頹綠醑，莫將銀海眩黄塵。", "山容似畫屏環立，世事如棋局幾新。", "惟有東風不今古，露花烟柳一般春。"]'),
('5e59ca0c-8b02-49b8-adc8-22429752e092','偕張總幹章帥機同游檀溪登極目和韻  其二','李曾伯','宋','宋诗','song-poetry','','[]','美哉輪奐若天成，一笑凭欄趁喜晴。',64,'全唐诗/poet.song.214000.json','["美哉輪奐若天成，一笑凭欄趁喜晴。", "彈厭江山詩句老，破除胸臆酒樽盈。", "溪頭圉圉觀魚躍，柳外蕭蕭憶馬鳴。", "明日無妨再聯轡，海棠猶未醉春酲。"]'),
('2a38eca1-eddd-4b18-a256-68488ba113c5','從制垣觀閲和韻','李曾伯','宋','宋诗','song-poetry','','[]','春風小試被廬蒐，抵掌功名一戰收。',64,'全唐诗/poet.song.214000.json','["春風小試被廬蒐，抵掌功名一戰收。", "萬里關河走狐兔，五更笳鼓肅貔貅。", "星馳列騎看騰躍，雲合嘉賓樂獻酬。", "機會不來人易老，故都惆悵麥油油。"]'),
('64b4ff43-0aba-40f9-b7b6-06ae561cf535','同羅季能章成父張子直登樊城制勝樓','李曾伯','宋','宋诗','song-poetry','','[]','避愁聊復上層樓，上到層樓轉更愁。',64,'全唐诗/poet.song.214000.json','["避愁聊復上層樓，上到層樓轉更愁。", "杳杳青烟榆夾塞，鱗鱗翠浪麥平疇。", "山連楚甸三千里，地隔中原四百州。", "立盡欄干誰領會，滄波渺處起沙鷗。"]'),
('eafd3cd4-ca22-4172-8e6e-c7261bc5a9d0','送羅季能赴江陵幕  其一','李曾伯','宋','宋诗','song-poetry','','[]','淳熙公論盛槐門，文獻依然故笏存。',64,'全唐诗/poet.song.214000.json','["淳熙公論盛槐門，文獻依然故笏存。", "晉世昔聞期畢萬，魯人今喜見臧孫。", "交遊半是清流望，趨向難爲俗子論。", "久客諸侯寧鬰鬰，公卿元自出藩垣。"]'),
('fcbc9d96-4fdc-44fb-b76b-d93d58bc1aca','送羅季能赴江陵幕  其二','李曾伯','宋','宋诗','song-poetry','','[]','留臺雄峙渚宮邊，江漢中間別一天。',64,'全唐诗/poet.song.214000.json','["留臺雄峙渚宮邊，江漢中間別一天。", "號令半皆歸後務，規模幾不減中權。", "况從席上分鄒湛，細向樓頭訪仲宣。", "爲報荆人好相慶，幕中無事帥垣賢。"]'),
('5dc49682-b706-4e22-9190-8e76987be34d','送羅季能赴江陵幕  其三','李曾伯','宋','宋诗','song-poetry','','[]','幕底從游數月間，孤燈凍酒飽相歡。',64,'全唐诗/poet.song.214000.json','["幕底從游數月間，孤燈凍酒飽相歡。", "平生得此於人寡，舉世如斯知己難。", "舍我遽輕千里別，祝君惟有一分寬。", "楊花正怯春歸去，忍向南關送客看。"]'),
('50913580-a192-41fa-8ba0-2b95a738d6bd','以勸分出伏龍因謁武侯廟','李曾伯','宋','宋诗','song-poetry','','[]','廬存龍去跡成非，草木空山聖得知。',64,'全唐诗/poet.song.214000.json','["廬存龍去跡成非，草木空山聖得知。", "成敗論人陳壽史，功名餘恨少陵詩。", "初心何只三分漢，偉略徒誇十倍丕。", "半夜松聲捲風雨，猶如抱膝嘯吟詩。"]'),
('b49eb2c2-b748-4f6a-a986-204529c0b1f9','和劉清叔檀溪韻','李曾伯','宋','宋诗','song-poetry','','[]','一溪清入漢江東，千載興亡指顧中。',64,'全唐诗/poet.song.214000.json','["一溪清入漢江東，千載興亡指顧中。", "自昔霸圖成匹馬，至今生氣貫長虹。", "當時枉駕先諸葛，底事浮江後阿童。", "髀肉已生騅逝矣，空餘款段踏塵紅。"]'),
('7da37cd9-0295-4e7a-83e7-928a3652a62f','壬辰過鄂渚簡張子直總幹  其一','李曾伯','宋','宋诗','song-poetry','','[]','一自檀溪把酒餘，年來夷路浸崎嶇。',64,'全唐诗/poet.song.214000.json','["一自檀溪把酒餘，年來夷路浸崎嶇。", "樓頭落日人空老，局面西風事頓殊。", "故國山容增黯淡，舊時柳色半荒蕪。", "草堂想見憂時切，曾賦官軍近捷無。"]'),
('6b6b3055-5970-4eb8-82f3-1c5db125b7c9','壬辰過鄂渚簡張子直總幹  其二','李曾伯','宋','宋诗','song-poetry','','[]','三載三來漢水湄，做成底事又空歸。',64,'全唐诗/poet.song.214000.json','["三載三來漢水湄，做成底事又空歸。", "塵埃暫解微官縛，雨雪猶存戰士衣。", "黄鶴喜尋詩侶約，白鷗還悟海翁機。", "掀髯一接春風笑，便覓漁蓑老釣磯。"]'),
('c6d7140b-77a6-4718-8077-d611ec72fe8c','甲午淮幕和蕭應父贈鄭允蹈韻  其一','李曾伯','宋','宋诗','song-poetry','','[]','休從太上問靈均，華髮駸駸及此辰。',64,'全唐诗/poet.song.214000.json','["休從太上問靈均，華髮駸駸及此辰。", "萬里斗槎難遠問，一時星弁玷同寅。", "縱逢裨竈言何益，自斷虞翻相己屯。", "且喜歲星臨宋分，今年頡利定稱臣。"]'),
('0737c408-c9c7-44e5-99b6-9859847e617e','甲午淮幕和蕭應父贈鄭允蹈韻  其二','李曾伯','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','客來遠自洞庭濱，一笑相逢耳競傾。',64,'全唐诗/poet.song.214000.json','["客來遠自洞庭濱，一笑相逢耳競傾。", "把酒未須論後約，讀書已恨欠前生。", "疇堪太乙青藜照，亦有豐城寶劍精。", "近在眼前休蹉却，君如未識問君平。"]'),
('8f94ac81-c290-4df1-9564-dd8d46ba60fd','和蕭應父贈黄子芸韻','李曾伯','宋','宋诗','song-poetry','','[]','久負詩壇第一評，肯教棲鳳久榛荆。',64,'全唐诗/poet.song.214000.json','["久負詩壇第一評，肯教棲鳳久榛荆。", "西堂有夢堪追謝，北海何書可薦衡。", "匹馬歸來嗟我俗，孤鴻吟對羨君清。", "霜前蟹嫩新篘美，爲問江頭潮已生。"]'),
('6b7626f2-b371-4385-a5c3-adf1d8cec611','和蔣志父春風亭韻  其一','李曾伯','宋','宋诗','song-poetry','','[]','不須舉扇障西風，且付黄花一笑中。',64,'全唐诗/poet.song.214000.json','["不須舉扇障西風，且付黄花一笑中。", "漸喜盧㕙成兩斃，仍愁蜂蟻起群雄。", "未能長策轅從北，果有真儒轍豈東。", "老我數奇何所用，快教兒輩學從戎。"]'),
('5a2a1f78-da2c-46dd-8f5c-7267e28c4a4d','和蔣志父春風亭韻  其二','李曾伯','宋','宋诗','song-poetry','','[]','誰能草檄愈頭風，有酒時時共一中。',64,'全唐诗/poet.song.214000.json','["誰能草檄愈頭風，有酒時時共一中。", "莫把丹青羨蘇武，且將玄白玩揚雄。", "將軍事在龍荒北，客子心馳馬首東。", "休笑晉朝人物少，猶知口不道和戎。"]'),
('5675a13e-c469-41c9-aaaa-0e5a839fd706','次蔣志父韻','李曾伯','宋','宋诗','song-poetry','','["\u897f\u6e56"]','中原百戰徯來蘇，浸喜衣冠復舊區。',64,'全唐诗/poet.song.214000.json','["中原百戰徯來蘇，浸喜衣冠復舊區。", "要得一行須老將，曾何千慮付狂夫。", "山川感慨詩難盡，烟火蕭條酒尚無。", "若問西湖已蕪沒，望窮惟有幾浮圖。"]'),
('f3040c14-f72b-4e3b-a0d9-0e38f9d30e46','甲午七夕在京和朱子木韻','李曾伯','宋','宋诗','song-poetry','','[]','巫雲一去付悠悠，堪笑星河老不休。',64,'全唐诗/poet.song.214000.json','["巫雲一去付悠悠，堪笑星河老不休。", "天上凄涼兩魂夢，人間閲歷幾春秋。", "銷磨長恨詩難盡，領略良宵酒莫留。", "借我天槎試相問，拙人還與巧同不。"]'),
('5a54479c-0581-40ea-8a72-a3e48663410f','甲午中秋在魏塘值風雨','李曾伯','宋','宋诗','song-poetry','','[]','向來玩事每欣逢，老去相忘更客中。',64,'全唐诗/poet.song.214000.json','["向來玩事每欣逢，老去相忘更客中。", "天下山河清影在，人間風雨此宵同。", "孤鸞夜泣菱花暗，老兔秋悲桂子空。", "料得嫦娥念摇落，不教無酒對征篷。"]'),
('c734f4a2-af45-4661-8ec2-ef1045c855c6','乙未渡淮點軍登壽春南樓','李曾伯','宋','宋诗','song-poetry','','[]','曾向春秋識此州，西風吹袂過淮頭。',64,'全唐诗/poet.song.214000.json','["曾向春秋識此州，西風吹袂過淮頭。", "人還故老衣冠喜，我爲中原草木愁。", "屹若長城今重鎮，棄如敝屣昔輕謀。", "功名不是吾曹事，且對空山徙倚樓。"]'),
('4a15d423-d16e-46be-8e43-4b7cfe68f577','己亥題茅山玉晨觀','李曾伯','宋','宋诗','song-poetry','','[]','烟雲作嶂松作關，夜深迫人星斗寒。',64,'全唐诗/poet.song.214000.json','["烟雲作嶂松作關，夜深迫人星斗寒。", "分明已在天上坐，不可更作人間看。", "須臾睡去復睡覺，髣髴前身在巖壑。", "洞門鎖鑰呼未應，時有天香暗飄落。"]'),
('afa9e636-1859-4caa-8a1b-de8216268189','庚子祈雨蔣山贈月老','李曾伯','宋','宋诗','song-poetry','','[]','欲知計寺金穀吏，便是鍾山粥飯頭。',64,'全唐诗/poet.song.214000.json','["欲知計寺金穀吏，便是鍾山粥飯頭。", "爾欲朝朝動魚鼓，我期日日飽貔貅。", "幾爲曉竈炊烟喜，又作秋田渴雨憂。", "自有寶公能辦供，元憑心上細推求。"]'),
('59d75e89-14db-47aa-8b16-9c09489379a4','送趙鼎臣赴召  其一','李曾伯','宋','宋诗','song-poetry','','[]','幾載江湖負雋聲，秋風千里起弓旌。',64,'全唐诗/poet.song.214000.json','["幾載江湖負雋聲，秋風千里起弓旌。", "石渠喜得今劉向，宣室應知舊賈生。", "臺閣致身將貴顯，朝廷論事且和平。", "更須記取申公語，不在多言在力行。"]'),
('bfbd7ab0-7684-4c65-8926-10c0c8accd22','送趙鼎臣赴召  其二','李曾伯','宋','宋诗','song-poetry','','[]','師旅之餘旱繼之，可爲太息此何時。',64,'全唐诗/poet.song.214000.json','["師旅之餘旱繼之，可爲太息此何時。", "江頭人類魚鱗集，局面憂深虎口危。", "國事不應分爾汝，邊防豈特固藩籬。", "茂弘若問金陵事，說與江東米價知。"]'),
('20716f47-d85e-484d-89ba-e6e6e766c07e','和別制垣金陵勸駕韻','李曾伯','宋','宋诗','song-poetry','','[]','殷勤儒帥餞圖南，文物彬彬歲比三。',64,'全唐诗/poet.song.214000.json','["殷勤儒帥餞圖南，文物彬彬歲比三。", "遠業相期唐進士，流風一洗晉清談。", "歌陳呦鹿筵初宴，分揣庸駑乘莫驂。", "好向瓊林待公衮，杏園春色正紅酣。"]'),
('78e3d71c-cb2d-4ca6-b440-081f6f6eedfa','贈聞人松庵','李曾伯','宋','宋诗','song-poetry','','[]','官術猶能手不龜，子之爲術亦如之。',64,'全唐诗/poet.song.214000.json','["官術猶能手不龜，子之爲術亦如之。", "價增三倍玉麟顧，言訂千金木石詩。", "鷗鷺尋盟吾自計，鷃鵬付分爾何爲。", "異時蓬蓽來相驗，直說太平卿相誰。"]'),
('3f389fd3-ce03-4bac-9387-5d45dc456758','辛丑都司公廨與陳景清諸友小集作  其一','李曾伯','宋','宋诗','song-poetry','','[]','幾年漫浪尚萍流，汩沒京塵雪滿頭。',64,'全唐诗/poet.song.214000.json','["幾年漫浪尚萍流，汩沒京塵雪滿頭。", "得意正濃須却顧，奉身而退是良謀。", "未忘雅志懷安石，長憶平生愧少游。", "歸去何求閑足矣，數椽村屋一虛舟。"]'),
('ac4d2c05-7e72-466e-8d89-43f877210ad0','辛丑都司公廨與陳景清諸友小集作  其二','李曾伯','宋','宋诗','song-poetry','','[]','當才誰可柱中流，我輩何如避一頭。',64,'全唐诗/poet.song.214000.json','["當才誰可柱中流，我輩何如避一頭。", "舊隠要尋鷗作伴，薄田足與鶴爲謀。", "蒹葭白露嗟今老，榆柳西風感昔遊。", "新秫已登鱸蟹賤，溪頭何日艤歸舟。"]'),
('eef5d1c0-ed1f-4a98-aff3-6df1a9240857','送郭靖父還金陵  其一','李曾伯','宋','宋诗','song-poetry','','[]','慈恩得雋綠衣歸，凡客南來罕似之。',64,'全唐诗/poet.song.214000.json','["慈恩得雋綠衣歸，凡客南來罕似之。", "名氏已標希呂第，文華要繼幼安詩。", "行登衮衮諸公上，毋鄙區區一尉卑。", "踏雪同來子先去，夢隨鞭影過江湄。"]'),
('c02693d4-74ca-4934-830b-66a6edfbb49f','送郭靖父還金陵  其二','李曾伯','宋','宋诗','song-poetry','','[]','憶昨相從戎馬間，屢披錦誥慰蒼顔。',64,'全唐诗/poet.song.214000.json','["憶昨相從戎馬間，屢披錦誥慰蒼顔。", "烟塵歷遍疆陲役，風雪同諳道路艱。", "子負此名心已白，我成何事鬢徒斑。", "一杯握手無它祝，歸爲移文問北山。"]'),
('d3387339-0d40-4f27-a147-d04beeefeaf4','贈林相士','李曾伯','宋','宋诗','song-poetry','','[]','賣卜長安作漫游，裹糧千里爲親謀。',64,'全唐诗/poet.song.214000.json','["賣卜長安作漫游，裹糧千里爲親謀。", "時危貴得班超相，命薄那能李廣侯。", "術挾瑟竽雖易售，話逢枘鑿亦難投。", "江頭雨滑東風急，挑却行包歸去休。"]'),
('d9fd63e4-bbe0-4c12-9d5c-38e20b1c6120','維揚再贈林相士用前韻','李曾伯','宋','宋诗','song-poetry','','[]','三數年來已倦遊，祗緣心迹不相謀。',64,'全唐诗/poet.song.214000.json','["三數年來已倦遊，祗緣心迹不相謀。", "深知我類虞翻相，莫怪人驚雍齒侯。", "江國舊懷詩一解，吳鄉新思酒雙投。", "一番公案重拈出，挑却行包歸去休。"]'),
('aee164ef-118c-4830-bacc-b0888aff690a','癸卯制參黎用之爲八仙領客和韻','李曾伯','宋','宋诗','song-poetry','','[]','撲面驚埃掃不開，都忘柳色暗章臺。',64,'全唐诗/poet.song.214000.json','["撲面驚埃掃不開，都忘柳色暗章臺。", "偏饒玳席嘉賓樂，特遣瑶池仙子來。", "自分鐵心徒自苦，相逢玉兔莫相陪。", "樽前休訝清香少，待約瓊花共一杯。"]'),
('08092802-1e5b-4a4f-96b2-42ae219d0f13','夜分和鄭小山韻  其一','李曾伯','宋','宋诗','song-poetry','','[]','弓劍相隨幾歷年，鬢毛斑剝飽風烟。',64,'全唐诗/poet.song.214000.json','["弓劍相隨幾歷年，鬢毛斑剝飽風烟。", "可憐蘆葉胡笳地，又過菊花新酒天。", "耳聽驊騮還紫邏，夢隨白鷺過青田。", "家僮久問謀歸未，想笑吾頑不可鎸。"]'),
('73291f1c-19c4-4829-b5bb-a42424268665','夜分和鄭小山韻  其二','李曾伯','宋','宋诗','song-poetry','','[]','塞上蕭蕭雨更風，秋來興味與誰同。',64,'全唐诗/poet.song.214000.json','["塞上蕭蕭雨更風，秋來興味與誰同。", "短檠聊和燈前句，長槊休誇馬上功。", "挽二石弓陪一校，操方寸管較諸公。", "到頭等是爲形役，盡付掀髯一笑中。"]'),
('915169a0-f72b-4394-ae85-a333e61c384c','贈相士陳林過金陵','李曾伯','宋','宋诗','song-poetry','','[]','疲於吏事老於兵，不特頭方命亦屯。',64,'全唐诗/poet.song.214000.json','["疲於吏事老於兵，不特頭方命亦屯。", "成敗固非予逆睹，窮通何用子前陳。", "登朝不是鳶肩相，守塞尤慚燕頷人。", "見說江東多福德，亟須洗眼望堂麟。"]'),
('2eca9c12-36f8-4280-ac3d-2a6c95bac607','甲辰送淮東黎漕趨朝  其一','李曾伯','宋','宋诗','song-poetry','','[]','簾捲紅樓拍手看，星軺迅步上鵷鸞。',64,'全唐诗/poet.song.214000.json','["簾捲紅樓拍手看，星軺迅步上鵷鸞。", "皇華節下留佳政，玉筍班中作好官。", "卿相致身時則易，忠賢得路古來難。", "端門待漏東風峭，尚憶屯邊鐵甲寒。"]'),
('dbd326b9-a1b6-491b-a99d-117311322c6d','甲辰送淮東黎漕趨朝  其二','李曾伯','宋','宋诗','song-poetry','','[]','始焉來此學分弓，定計初筵畫諾中。',64,'全唐诗/poet.song.214000.json','["始焉來此學分弓，定計初筵畫諾中。", "擊楫少能思祖逖，同舟多頼有婁公。", "老懷不奈周南滯，佳客今成冀北空。", "天上故人如見問，爲言憔悴已成翁。"]'),
('9cd58283-d619-4de4-8db8-4c17e407e007','送胡季轍制參赴堂召  其一','李曾伯','宋','宋诗','song-poetry','','[]','怪得簷頭鵲語頻，好音催召幕中賓。',64,'全唐诗/poet.song.214000.json','["怪得簷頭鵲語頻，好音催召幕中賓。", "喚回雞塞三更夢，趁取鶑花二月春。", "車法陣圖留後效，囊封諫草看前陳。", "退朝若訪孤山去，尚有疏梅可寄人。"]'),
('4af7219c-95d5-4188-8478-09617400eccd','送胡季轍制參赴堂召  其二','李曾伯','宋','宋诗','song-poetry','','[]','君見淮頭尚可爲，勿言蚌鷸正相持。',64,'全唐诗/poet.song.214000.json','["君見淮頭尚可爲，勿言蚌鷸正相持。", "再三國計當加備，第一人材最切時。", "面目山林還爾我，精神帷幄舍渠誰。", "登樓若也披輿地，爲借前籌試及之。"]'),
('a36646bd-cb2a-4766-9732-ce8fc365a4e2','傅山父携示曾玉堂和余韻答之','李曾伯','宋','宋诗','song-poetry','','[]','誰傳新語到邊州，來自鑾坡最緊頭。',64,'全唐诗/poet.song.214000.json','["誰傳新語到邊州，來自鑾坡最緊頭。", "句法自成臺閣樣，交盟猶爲友朋謀。", "憶征西府勞清夢，望上東門想貴游。", "何似天風輕借助，放教歸老釣魚舟。"]'),
('38a1199d-e8cb-4caa-81db-dc44f7d9ee17','右司周昞仲亦用韻併和以謝之','李曾伯','宋','宋诗','song-poetry','','[]','誰將拙句徹名流，勾引春風入筆頭。',64,'全唐诗/poet.song.214000.json','["誰將拙句徹名流，勾引春風入筆頭。", "廊廟喜登端士用，田園盍爲故人謀。", "曾芳草外思淮事，應海棠邊念蜀游。", "細雨挑燈成朗誦，劇談如共峽江舟。"]'),
('f7039788-a720-4c5e-b43f-f2f049f1a76d','送制機豐德馨赴堂召  其一','李曾伯','宋','宋诗','song-poetry','','["\u897f\u6e56"]','元祐豐家幾世孫，依然風概至今存。',64,'全唐诗/poet.song.214000.json','["元祐豐家幾世孫，依然風概至今存。", "著鞭自許河南逖，舉酒相期洛北溫。", "聯句有詩留月觀，禦戎何策告天閽。", "切毋飲却西湖水，齒頰冰霜置勿論。"]'),
('30c9ad9f-5fac-4c6a-b1ff-361a5cafac2a','送制機豐德馨赴堂召  其二','李曾伯','宋','宋诗','song-poetry','','[]','奇章昔送牧之行，舊事今親見廣陵。',64,'全唐诗/poet.song.214000.json','["奇章昔送牧之行，舊事今親見廣陵。", "一叟棲棲嗟孑立，諸賢衮衮慶偕升。", "事來推與參前著，公去吾其失右肱。", "我俟兵休歸决矣，斷無清夢到觚稜。"]'),
('57ff0343-47c8-48dc-9b53-72451576d2e2','壽城圍解制參向君玉貺以凱歌和韻  其一','李曾伯','宋','宋诗','song-poetry','','[]','誰知匕筯落轟雷，三月新城兩月圍。',64,'全唐诗/poet.song.214000.json','["誰知匕筯落轟雷，三月新城兩月圍。", "吉語雖傳淮鶴捷，驚心幾動海鷗機。", "公毋誇伐稱全璧，我爲憂疑已佩韋。", "何處無魚堪薦飯，不須跕跕看鳶飛。"]'),
('5e7919e2-5f0a-47f5-867f-07e3fd9ba4b8','壽城圍解制參向君玉貺以凱歌和韻  其二','李曾伯','宋','宋诗','song-poetry','','[]','中流岌岌此舟同，對越皇天只寸衷。',64,'全唐诗/poet.song.214000.json','["中流岌岌此舟同，對越皇天只寸衷。", "今夜千艘趨險進，明朝萬馬舉群空。", "將軍爭上平戎捷，老子慚無守塞功。", "局面莫貪邊用利，共思穩著待西風。"]'),
('22650314-7b48-42cb-825e-2410e013d8c7','久雨之餘隔窗聞雪簡書院諸丈  其一','李曾伯','宋','宋诗','song-poetry','','[]','雨覆雲翻越月餘，苦疑滕六欠工夫。',64,'全唐诗/poet.song.214000.json','["雨覆雲翻越月餘，苦疑滕六欠工夫。", "倏敲窗竹清成玉，細剪簷花碎作珠。", "已喜新冬三白有，不愁嗣歲二紅無。", "地爐紙帳杯行了，呼起詩翁爲撚鬚。"]'),
('44caf7f4-6364-452e-8160-8005de8725c0','久雨之餘隔窗聞雪簡書院諸丈  其二','李曾伯','宋','宋诗','song-poetry','','[]','玉龍飛下太清境，粉雉凝成不夜城。',64,'全唐诗/poet.song.214000.json','["玉龍飛下太清境，粉雉凝成不夜城。", "眩得窮兒猶暴富，照教暗室亦强明。", "來朝細挹千林色，竟夕都忘萬籟聲。", "不願銜枚蔡州去，鐵衣早撤戍邊兵。"]'),
('5aaffd77-e0ff-45d9-84d8-06ec7160af20','乙巳題制參蕭應父襲芳亭','李曾伯','宋','宋诗','song-poetry','','[]','細攬群英入此亭，重開八葉付公門。',64,'全唐诗/poet.song.214000.json','["細攬群英入此亭，重開八葉付公門。", "無窮真意侵書架，不斷清香對酒樽。", "由實又花花又實，看孫生子子生孫。", "主人不用平泉誓，自有根源六藝存。"]'),
('cf5aaa57-608c-44f5-8e99-8055bcd02b6e','送翟簡卿制參赴南安  其一','李曾伯','宋','宋诗','song-poetry','','[]','渡江華閥尚氈青，人物林中早有聲。',64,'全唐诗/poet.song.214000.json','["渡江華閥尚氈青，人物林中早有聲。", "官轍久更諳世路，邊籌熟試洞戎情。", "整鑣向闕人多羨，出幕持麾古所榮。", "盍爲王言留禁闥，美才何止僅專城。"]'),
('8b8a38ba-a4fd-44c4-baa7-fe447ca0bed2','送翟簡卿制參赴南安  其二','李曾伯','宋','宋诗','song-poetry','','[]','自屈星屏佐碧油，艱危同濟此風舟。',64,'全唐诗/poet.song.214000.json','["自屈星屏佐碧油，艱危同濟此風舟。", "平山楊柳留佳話，庾嶺梅花想勝遊。", "公到玉階宜抗論，我尋畫舸便歸休。", "他時若訪無真里，野水中間一白鷗。"]'),
('438ca1f9-881e-4a45-8c3d-5082551c8ff7','送周昞仲大卿歸江西','李曾伯','宋','宋诗','song-poetry','','[]','中外周旋閲幾年，清忠一節可箋天。',64,'全唐诗/poet.song.214000.json','["中外周旋閲幾年，清忠一節可箋天。", "歷階而上公卿易，拂袖以歸韋布然。", "霅上人稠難買屋，江頭路穩好行船。", "夢回落月應相憶，猶有征人在漢邊。"]'),
('891aae3b-0a2c-4b04-857f-fb7d6de6d4e5','和傅山父喜雨韻  其一','李曾伯','宋','宋诗','song-poetry','','[]','驕陽赫赫正當空，化作甘霖覆手中。',64,'全唐诗/poet.song.214000.json','["驕陽赫赫正當空，化作甘霖覆手中。", "洗滌四郊無點翳，作興群槁有新功。", "惟方寸地能精格，信咫尺天隨感通。", "毋以喜書安僅足，更行好事答高穹。"]'),
('a74efe4a-f0aa-491d-988d-404e97faef90','和傅山父喜雨韻  其二','李曾伯','宋','宋诗','song-poetry','','[]','柔金老火苦相鏖，千里駸駸地不毛。',64,'全唐诗/poet.song.214000.json','["柔金老火苦相鏖，千里駸駸地不毛。", "忽遂所祈欣欲舞，舉蒙其利潤於膏。", "昭蘇田畯禾千頃，飽滿舟人水一篙。", "我老發揮無好句，須拈健筆付詩豪。"]'),
('76881125-5921-4958-bc16-d4ac00f09f1c','和幕府稅巽父弔陳任二諫議韻','李曾伯','宋','宋诗','song-poetry','','[]','出門三十里平原，仰止高山禮甚專。',64,'全唐诗/poet.song.214000.json','["出門三十里平原，仰止高山禮甚專。", "烈日秋霜千祀後，寒烟荒草兩塋前。", "一瞻文獻生何晚，三歎姦邪死不先。", "臣也不忠宜共戒，烝嘗何惜更加籩。"]'),
('f5685cc8-842e-4fab-9191-418685236d40','東西正陽獻捷和傅山父凱歌韻','李曾伯','宋','宋诗','song-poetry','','[]','一從授鉞俾來旬，却敵無謀效不神。',64,'全唐诗/poet.song.214000.json','["一從授鉞俾來旬，却敵無謀效不神。", "士用命焉何有力，臣今老矣不如人。", "誰能河北平三晉，猶慮關中啟一秦。", "留取功名待來者，歸歟抗疏告嚴宸。"]'),
('3eef17cc-aa15-4d75-bebd-3dcea0e56846','食河豚鱸魚席間口占','李曾伯','宋','宋诗','song-poetry','','[]','午食河豚晚食鱸，兩魚風味絕懸殊。',64,'全唐诗/poet.song.214000.json','["午食河豚晚食鱸，兩魚風味絕懸殊。", "懷歸未必因茲品，適口何能計此軀。", "春岸荻芽常喜有，秋風蓴菜不愁無。", "笑他俗子甘鰍鱔，爲此杯羹戒不虞。"]'),
('89cc39c2-d511-477a-ab6e-5e6582078203','丙午九日將過陽羨偶成','李曾伯','宋','宋诗','song-poetry','','[]','年年秋晚對風沙，今近重陽喜在家。',64,'全唐诗/poet.song.214000.json','["年年秋晚對風沙，今近重陽喜在家。", "自斷此生甘皓首，能消幾度看黄花。", "閑身頗覺便筇竹，醉態都忘脫帽紗。", "且問小舟溪上去，飛鷗數點夕陽斜。"]'),
('70ca1663-10a5-460f-b8cd-30c98c06d9d8','遊張公祠  其一','李曾伯','宋','宋诗','song-poetry','','[]','坤靈闌迹漢何時，木石深山聖得知。',64,'全唐诗/poet.song.214000.json','["坤靈闌迹漢何時，木石深山聖得知。", "大塊鑿開真境祕，太虛藴出衆峰奇。", "攀蘿攬秀俯可即，秉燭窮幽遠莫窺。", "盍遣神龍謹封護，勿容俗子亦游嬉。"]'),
('9062374b-ea10-4f4a-90b9-0b8c556d8726','遊張公祠  其二','李曾伯','宋','宋诗','song-poetry','','[]','十年重過石橋行，松下清流載濯纓。',64,'全唐诗/poet.song.214000.json','["十年重過石橋行，松下清流載濯纓。", "洞隔烟霞知地遠，壇連仙佛信天成。", "人如雲意俱閑適，山带霜容似瘦生。", "步出亭皋便歸去，它時林壑又寒盟。"]'),
('8ec0050b-e72d-4f04-adbe-c5c2d4400012','山中即事','李曾伯','宋','宋诗','song-poetry','','[]','手挼巖菊嗅寒香，陡覺輕飈透薄裳。',64,'全唐诗/poet.song.214000.json','["手挼巖菊嗅寒香，陡覺輕飈透薄裳。", "自是蒼官添老色，不因青女眩寒妝。", "新篘未熟啜茶去，晚稻才收種麥忙。", "願學老農惟苦懶，荷鋤歸去卧斜陽。"]'),
('0f0624a4-e921-4989-be23-d5df11de3aef','送八窗叔歸','李曾伯','宋','宋诗','song-poetry','','[]','歸來百事付休休，又向空山斷送秋。',64,'全唐诗/poet.song.214000.json','["歸來百事付休休，又向空山斷送秋。", "整疊衣篝雙赤脚，携持拄杖一蒼頭。", "儒書梵語相參看，酒柱詩盟自獻酬。", "客有可人留不住，夜長誰與話清愁。"]'),
('33168357-4571-4995-8e2f-349886baba6a','丙午冬徐衍道見訪於可齋','李曾伯','宋','宋诗','song-poetry','','[]','甫能鋤月種梅歸，竹外欣聞客扣扉。',64,'全唐诗/poet.song.214000.json','["甫能鋤月種梅歸，竹外欣聞客扣扉。", "天近城南寧去緩，人閑水北肯來稀。", "風雲迅步新班筍，雨雪休思舊戍薇。", "別後毋厪問名氏，杜門終老但知非。"]'),
('1e569935-09e3-4ba5-90cd-622b94532697','尤木石薦術士松庵求書以詩送之','李曾伯','宋','宋诗','song-poetry','','[]','衝寒得得過吾門，切莫談天不願聞。',64,'全唐诗/poet.song.214000.json','["衝寒得得過吾門，切莫談天不願聞。", "種木十年甘自許，寄梅千里欲何云。", "人誰相記懷明月，我已無心等片雲。", "若向霸陵逢醉尉，不須與說故將軍。"]'),
('373b35d3-b387-493d-b4d6-223a91c63f55','丁未效八窗叔賦黄郎','李曾伯','宋','宋诗','song-poetry','','[]','夙悟金仙空色教，化生千百對青春。',64,'全唐诗/poet.song.214000.json','["夙悟金仙空色教，化生千百對青春。", "强顔翁媼梔爲貌，取悅兒童絲繫身。", "立仗無言開口甚，當筵何事掉頭頻。", "笑他鮑郭經年舞，我過鶑花即問津。"]'),
('fda4e412-c8c5-480d-b862-b087cae40e7a','因賦風箏與黄郎偶','李曾伯','宋','宋诗','song-poetry','','[]','竹君爲骨楮君身，學得飛鳶羽樣輕。',64,'全唐诗/poet.song.214000.json','["竹君爲骨楮君身，學得飛鳶羽樣輕。", "出手能施千丈縷，舉頭可問九霄程。", "高窮寥曠寧無力，少假扶摇即有聲。", "所惜崢嶸能幾日，兒曹僂指已清明。"]'),
('38b647f5-2ad7-439f-81ff-53ce04e14e17','送焦吏部造朝  其一','李曾伯','宋','宋诗','song-poetry','','[]','向來借箸在籌帷，今趣魁纏入太微。',64,'全唐诗/poet.song.214000.json','["向來借箸在籌帷，今趣魁纏入太微。", "漢郡奚勞汲生守，洛人喜見范公歸。", "要持真是明公論，莫急同心濟事機。", "見說九重勤側席，細陳長策慰宵衣。"]'),
('62745051-d2ec-4486-bb91-cf48f4a75585','送焦吏部造朝  其二','李曾伯','宋','宋诗','song-poetry','','[]','火雲赫赫汗衣流，人望公來望有秋。',64,'全唐诗/poet.song.214000.json','["火雲赫赫汗衣流，人望公來望有秋。", "契托棣華承繾綣，辭陳桑土願綢繆。", "行爲霖雨千疇足，坐解西風一段憂。", "從此江頭波浪息，柳邊贏得伴沙鷗。"]'),
('8a323625-9bfc-4bb1-afb6-66b858da03f2','偶得希真巖壑舊隠正在小圃因賦  其一','李曾伯','宋','宋诗','song-poetry','','[]','數峰佳致藹前修，心匠玲瓏小更幽。',64,'全唐诗/poet.song.214000.json','["數峰佳致藹前修，心匠玲瓏小更幽。", "公去我來幾傳舍，人非物是一虛舟。", "矗天柳色新條改，垂地藤陰舊迹留。", "坐對黄花誰領會，猶疑蝴蝶是莊周。"]'),
('919fff9c-bb04-41f0-8aff-6e7c4343c302','偶得希真巖壑舊隠正在小圃因賦  其二','李曾伯','宋','宋诗','song-poetry','','[]','高人已逐烟霞去，此地猶餘巖壑存。',64,'全唐诗/poet.song.214000.json','["高人已逐烟霞去，此地猶餘巖壑存。", "十數小峰纏古蔓，兩三老木長盤根。", "月沉翠柳空梁影，雨洗蒼苔带屐痕。", "留得清風師後進，絕勝金谷憶王孫。"]'),
('dbb1d965-52fd-45e0-a87b-ba6f2f42766c','八窗叔用前韻相寄時留村舍和以謝之  其一','李曾伯','宋','宋诗','song-poetry','','[]','從渠舊隠擅清修，我愛吾廬溪上幽。',64,'全唐诗/poet.song.214000.json','["從渠舊隠擅清修，我愛吾廬溪上幽。", "一幅霜林長短樹，幾灣烟葦去來舟。", "買魚釀秫作新節，招鶴訪梅遲小留。", "却憶故山懷故老，寧忘嫠緯念宗周。"]'),
('e920c77b-7a7d-4f5d-b174-3072d29de91c','八窗叔用前韻相寄時留村舍和以謝之  其二','李曾伯','宋','宋诗','song-poetry','','[]','洛川已矣不復見，斯地巋然猶獨存。',64,'全唐诗/poet.song.214000.json','["洛川已矣不復見，斯地巋然猶獨存。", "九仞成功忍虧簣，百年種德在深根。", "依稀舊燕空梁語，俯仰飛鴻踏雪痕。", "多少名園富花石，爭如書圃付兒孫。"]'),
('ab7a4032-756e-4643-8085-500f5cfc0a27','又和八窗叔見寄','李曾伯','宋','宋诗','song-poetry','','[]','寂寞寒枝問故棲，柳疏梧老影熹微。',64,'全唐诗/poet.song.214000.json','["寂寞寒枝問故棲，柳疏梧老影熹微。", "炊烟冷落犁荒壠，篷雨廉纖纜斷磯。", "擬閲舊書成懶癖，旋篘新酒解愁圍。", "家人不慣田園趣，剛道天寒盍早歸。"]'),
('bd6c8812-b066-4804-9a98-d87f70601039','戊申春偶成','李曾伯','宋','宋诗','song-poetry','','[]','半世崎嶇鬢已凋，元知官職忌之招。',64,'全唐诗/poet.song.214000.json','["半世崎嶇鬢已凋，元知官職忌之招。", "幾番惡夢覺已晚，一片好心磨不消。", "枕上豈堪思往日，樽前更莫計明朝。", "此身若也填溝壑，猶有來生答聖朝。"]'),
('3b4e794d-bde0-455a-984e-59d7da54755e','賦家山夕秀  其一','李曾伯','宋','宋诗','song-poetry','','[]','本因累土作層臺，巧匠俄爲小阜堆。',64,'全唐诗/poet.song.214000.json','["本因累土作層臺，巧匠俄爲小阜堆。", "碧落界邊將塔對，蒼蕪斷處送山來。", "狀成一段林巒勝，欠得幾株松桂栽。", "夕照未沉明月上，倚闌正爾可徘徊。"]'),
('c9044abb-96fb-41a4-bf7f-218ab5bc707e','賦家山夕秀  其二','李曾伯','宋','宋诗','song-poetry','','[]','小亭八尺石爲臺，占綠圍中作翠堆。',64,'全唐诗/poet.song.214000.json','["小亭八尺石爲臺，占綠圍中作翠堆。", "一片閑雲難畫去，四時野色入詩來。", "氣凌月觀身曾到，夢托雲根手自栽。", "更出城樓一頭地，夕陰含雨肯低徊。"]'),
('04a84454-52ff-415c-ab92-cac23341a663','和褚縣丞韻  其一','李曾伯','宋','宋诗','song-poetry','','[]','世味寧如道味濃，誰令小屋卧元龍。',64,'全唐诗/poet.song.214000.json','["世味寧如道味濃，誰令小屋卧元龍。", "何當談笑與雙璧，乃假吟哦對二松。", "傾蓋正欣留槜李，歸檣底事取潘葑。", "先生且辦弦歌計，莫慮瓶無斗粟舂。"]'),
('9a7e2781-09d3-4be5-b4a6-7544308a45c2','和褚縣丞韻  其二','李曾伯','宋','宋诗','song-poetry','','[]','拍拍新書一紙春，相逢牢落易相親。',64,'全唐诗/poet.song.214000.json','["拍拍新書一紙春，相逢牢落易相親。", "霸陵李廣方嗟老，闕里原思乃歎貧。", "顧我棲遲甘一壑，感君慰藉重千鈞。", "燈前欲和梅花引，病髮飄飄滿面塵。"]'),
('e76c5ed5-29b8-4b3d-8005-b33cad129501','己酉慶周子將壽八十','李曾伯','宋','宋诗','song-poetry','','[]','華齡八袠慶朋簪，貴老崇師喜見今。',64,'全唐诗/poet.song.214000.json','["華齡八袠慶朋簪，貴老崇師喜見今。", "絳帳先生從白髮，金閨諸彥盡青衿。", "冰寒水見源流盛，玉在山知潤澤深。", "厚德作人宜壽艾，永傳文獻紀枌陰。"]'),
('dc318f82-3ced-47dc-af34-fa18306d95f1','和褚縣丞韻','李曾伯','宋','宋诗','song-poetry','','[]','哦松之去爭能誦，載月而歸取甚廉。',64,'全唐诗/poet.song.214000.json','["哦松之去爭能誦，載月而歸取甚廉。", "誨掖尚無忘後進，典刑真不愧前瞻。", "新詩慰藉知三復，雅意勤渠示一謙。", "願問閒中讀書味，魚熊何以得而兼。"]'),
('4c1c91df-abd1-401a-ac0a-fea06d3de4c4','己酉赴桂過撫州樟原得雨','李曾伯','宋','宋诗','song-poetry','','[]','夜來一雨洗驕陽，軋軋籃輿趁曉凉。',64,'全唐诗/poet.song.214000.json','["夜來一雨洗驕陽，軋軋籃輿趁曉凉。", "過眼幾多山應接，轉頭二十里相望。", "烟橫夾道松交翠，水拍連疇稻半黄。", "轍迹平生今始到，元知樂土是江鄉。"]'),
('a8e0dc7d-649f-4939-a625-1b07c79f0389','憶幼子','李曾伯','宋','宋诗','song-poetry','','[]','膝下相隨五閲秋，意其可以付箕裘。',64,'全唐诗/poet.song.214000.json','["膝下相隨五閲秋，意其可以付箕裘。", "祗緣老子身無福，致使佳兒命不修。", "宿業結來知有自，暑行壞會復奚尤。", "靈臺一點知何處，痛入肝腸死則休。"]'),
('e36a09fc-8edb-4840-b55c-a4b53d741805','題衡山縣驛','李曾伯','宋','宋诗','song-poetry','','["\u8861\u5c71"]','平生足始涉南方，邸舍稀疏驛路長。',64,'全唐诗/poet.song.214000.json','["平生足始涉南方，邸舍稀疏驛路長。", "尚隔三州纔嶺嶠，更行幾日是瀟湘。", "家人轉苦禁秋熱，輿從常催趁曉凉。", "識破浮生等羈旅，强加餐飯莫悲傷。"]'),
('7c8e6728-1f88-4a0d-b419-e8681559c011','和鄧巽坡韻','李曾伯','宋','宋诗','song-poetry','','[]','身雖湖海常懷主，忠在朝廷肯具臣。',64,'全唐诗/poet.song.214000.json','["身雖湖海常懷主，忠在朝廷肯具臣。", "爲國未嘗知有己，此心可以質諸神。", "綢繆舊話方樽酒，拂滌征塗滿袂塵。", "雍齒且封君豈慮，正須珍重保千鈞。"]'),
('3d665f03-eca1-4542-a49a-f24bd80c6d81','題衡陽臨湘驛','李曾伯','宋','宋诗','song-poetry','','[]','暑塗挈挈問持裝，過眼蘋風倏轉商。',64,'全唐诗/poet.song.214000.json','["暑塗挈挈問持裝，過眼蘋風倏轉商。", "豈爲南魚來丙穴，且先北雁過衡陽。", "童烏已矣腸空斷，老馬疲哉汗欲僵。", "身大塊中猶大瘧，鐵心禁得幾炎凉。"]'),
('6b75812e-818a-4fdc-b3ad-fe92037e57a4','過愚溪','李曾伯','宋','宋诗','song-poetry','','[]','爲底先生此水居，正緣不解學顔愚。',64,'全唐诗/poet.song.214000.json','["爲底先生此水居，正緣不解學顔愚。", "身雖樂彼溪山似，名不期而天壤俱。", "往事勿言今已矣，當時豈意在茲乎。", "擬招故老窮佳勝，烟草蕭蕭宅一區。"]'),
('8c999bff-e807-40fe-ba30-5dad91e0120a','過清湘洮陽驛和方孚若韻','李曾伯','宋','宋诗','song-poetry','','[]','問驛尋梅路漸深，壁間誰帖邁來禽。',64,'全唐诗/poet.song.214000.json','["問驛尋梅路漸深，壁間誰帖邁來禽。", "困詩感歎人才舊，投筆慚書歲月今。", "訪古暫陪湘水滸，憂時遠到雪山陰。", "牧羝持節疇能似，空倩賓鴻爲寄音。"]'),
('7ac517d0-3401-47af-9137-13a7eef7995e','禮湘山佛和別駕叔韻','李曾伯','宋','宋诗','song-poetry','','[]','自得湘南一派奇，禪舂元熟不須師。',64,'全唐诗/poet.song.214000.json','["自得湘南一派奇，禪舂元熟不須師。", "幾千億化如來相，五百年將再出時。", "翠壁雲連秋樹老，寶坊香靜午齋遲。", "我來欲和因緣事，衆衲叢中有解知。"]'),
('f5d66529-b4ff-4119-8cb6-ff8ffe549270','送交代董矩堂赴召  其一','李曾伯','宋','宋诗','song-poetry','','[]','淵源正學富經綸，炳炳如丹一片心。',64,'全唐诗/poet.song.214000.json','["淵源正學富經綸，炳炳如丹一片心。", "中外久期還荷橐，江湖所至是棠陰。", "威聲足使戎心懾，邊腹何虞客氣侵。", "指日玉階清問及，盍思長策濟當今。"]'),
('b63e60cd-480a-4ac4-a696-6e487cc8aa6a','送交代董矩堂赴召  其二','李曾伯','宋','宋诗','song-poetry','','[]','渡瀘已定葛巾北，分陝既成周衮東。',64,'全唐诗/poet.song.214000.json','["渡瀘已定葛巾北，分陝既成周衮東。", "二者於斯皆上意，群然以此望明公。", "香名千載梅邊雪，歸路三秋桂子風。", "百萬民夷休戀戀，公方柄用福無窮。"]'),
('50bf97ba-dde4-460e-8243-698acb4d548a','送交代董矩堂赴召  其三','李曾伯','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','遡風繡節洞庭濱，作噩重逢未識真。',64,'全唐诗/poet.song.214000.json','["遡風繡節洞庭濱，作噩重逢未識真。", "不謂頹齡來嶺海，乃承華武接星辰。", "公捐纍印輕於葉，我愧滿襟皆是塵。", "從此廟堂醫國去，好留肘後遺陳人。"]'),
('00fd62a5-d0cc-44fa-883b-28d9604a2ffb','和鄧巽坡詠菊併見寄韻  其一','李曾伯','宋','宋诗','song-poetry','','[]','天涯秋晚見孤芳，華髮蕭騷易感傷。',64,'全唐诗/poet.song.214000.json','["天涯秋晚見孤芳，華髮蕭騷易感傷。", "對酒未嘗忘北海，因詩惟恐瘦東陽。", "古心翻得風霜白，冷艷寧隨草木黄。", "惟屈可餐陶可採，蝶蜂爭得識寒香。"]'),
('77b748a6-7523-41f4-9aac-7be183f315d6','和鄧巽坡詠菊併見寄韻  其二','李曾伯','宋','宋诗','song-poetry','','[]','轉蓬又是幾三秋，客裏常宜視鼎羞。',64,'全唐诗/poet.song.214000.json','["轉蓬又是幾三秋，客裏常宜視鼎羞。", "嶺首舍梅無所有，衡陽斷雁寄何由。", "凄涼陳迹幾年事，繾綣高情一夕留。", "聖代斷無車蓋禁，詩筒毋惜到南州。"]'),
('e46a0769-d6e7-473c-ae13-7e49b67afe99','登逍遥樓和方孚若韻','李曾伯','宋','宋诗','song-poetry','','[]','堯山舉目見於牆，群玉森森拱巨梁。',64,'全唐诗/poet.song.214000.json','["堯山舉目見於牆，群玉森森拱巨梁。", "一幅畫屏羅偉觀，兩詩銀筆冠當場。", "沙平鷺立秋無盡，月冷烏啼夜未央。", "有客凭闌共清話，逍遥何異白雲鄉。"]'),
('d4189d51-b2f0-436a-8c06-ee82dd71c2d2','登湘南樓和方孚若韻','李曾伯','宋','宋诗','song-poetry','','[]','天教管領衆山來，筍立平章翠作堆。',64,'全唐诗/poet.song.214000.json','["天教管領衆山來，筍立平章翠作堆。", "上馬休憐翁矍鑠，酌罍聊賦彼崔嵬。", "樓高蒼桂奇觀列，人對黄花逸興催。", "公退呼兒同徙倚，卷舒風月等浮埃。"]'),
('cc1d6e18-43b2-4125-a57e-7317e42bc83d','登西樓題柱','李曾伯','宋','宋诗','song-poetry','','[]','分弓來戍嶺南州，勳鏡塵生雪滿頭。',64,'全唐诗/poet.song.214000.json','["分弓來戍嶺南州，勳鏡塵生雪滿頭。", "願進愚言宜簡易，頗哀老子得遨遊。", "青山落處鐘聞寺，白鷺明邊人倚樓。", "衙散吏歸冰樣靜，一庭落葉和晴鳩。"]'),
('760b48a1-ea01-4c64-b8aa-6b77cf1bd583','己酉八桂勸駕','李曾伯','宋','宋诗','song-poetry','','[]','快束行裝穩著鞭，梅邊已報小春天。',64,'全唐诗/poet.song.214000.json','["快束行裝穩著鞭，梅邊已報小春天。", "程開鵬翼三千里，名繼龍頭二百年。", "花插一枝趨燕喜，雲占五色對臚傳。", "丈夫自許當如此，舉酒相期共勉旃。"]'),
('3b822aeb-6343-4c08-98b7-24c7287aad4e','庚戌題雪觀用方孚若韻','李曾伯','宋','宋诗','song-poetry','','[]','纔見春從沙際歸，堂堂背我迅於飛。',64,'全唐诗/poet.song.214000.json','["纔見春從沙際歸，堂堂背我迅於飛。", "病餘窺圃心成怯，老去登樓力苦微。", "岸柳含烟猶綠瘦，海棠裛雨正紅肥。", "山川信美非吾土，强作清吟祗遂非。"]'),
('a982a4d2-90dd-4167-99a3-70120a21b84e','和鄧巽坡見寄元夕韻','李曾伯','宋','宋诗','song-poetry','','[]','一笑芳宵萬慮平，詩翁猶自假詩鳴。',64,'全唐诗/poet.song.214000.json','["一笑芳宵萬慮平，詩翁猶自假詩鳴。", "名邦想見燈成市，病骨相忘月暗城。", "人事誰能記今昨，天公都莫管陰晴。", "窗前細讀梅花句，但覺身輕眼倍明。"]'),
('7c2344c1-93a1-4b66-a996-583b085c68ae','又和梅韻','李曾伯','宋','宋诗','song-poetry','','[]','千里詩來字字香，品題著意到孤芳。',64,'全唐诗/poet.song.214000.json','["千里詩來字字香，品題著意到孤芳。", "以千林表丈人行，洗萬古凡兒女妝。", "自是精神凌雪月，不妨風骨飽冰霜。", "撚髭聊以酬清思，病筆欹斜媿小王。"]'),
('a8fc0b85-2da2-49f9-847b-e34a085cc3ec','寧壽寺劭農登慈氏閣和李誠之柱間韻','李曾伯','宋','宋诗','song-poetry','','[]','持酒殷勤問爾農，憂時同此願年豐。',64,'全唐诗/poet.song.214000.json','["持酒殷勤問爾農，憂時同此願年豐。", "倉箱欲致崇墉積，耒耜宜加曠土功。", "水北有田均夜雨，嶺南無地不春風。", "吾皇德化形扶杖，親見兒嬉七十翁。"]'),
('c2a423c3-2589-4e11-b254-8a970e911029','瓊筦顧守示和愚溪詩用韻餞之','李曾伯','宋','宋诗','song-poetry','','[]','鯨浪中間一島居，往時千慮笑狂愚。',64,'全唐诗/poet.song.214000.json','["鯨浪中間一島居，往時千慮笑狂愚。", "伏波方略今堪擬，渤海聲名斷與俱。", "小醜當從而靡矣，吾民其庶有瘳乎。", "雙旌整頓雙泉了，歸佐清朝澤廣區。"]'),
('3393f1f4-e288-46a1-99a3-37232b0a70b9','題越觀和方孚若韻','李曾伯','宋','宋诗','song-poetry','','[]','簷陰寂寂轉西遲，檢點春工倍費詩。',64,'全唐诗/poet.song.214000.json','["簷陰寂寂轉西遲，檢點春工倍費詩。", "烟樹鬰蒼何處洞，雨苔斑駁舊人碑。", "清泉白石仙遊地，芳草綠陰晴晝時。", "目送水雲誰領會，沙鷗點點柳絲絲。"]'),
('d1c800b4-9f0e-4cc5-b25d-1c3d78d27e9e','禁烟日登嵯峨閣和方孚若韻','李曾伯','宋','宋诗','song-poetry','','[]','漠漠風烟著野棠，一春多恨雨浪浪。',64,'全唐诗/poet.song.214000.json','["漠漠風烟著野棠，一春多恨雨浪浪。", "古榕陰裏作寒食，芳草城頭過艷陽。", "不斷山光通百粵，無邊春思渺三湘。", "伊祁不放花飛盡，露濕薔薇幾陣香。"]'),
('4b7c0fde-09fc-45ac-b965-ab898d217896','庚戌赴荆閫舟過湘江','李曾伯','宋','宋诗','song-poetry','','[]','湘流得雨掌來平，艇子乘風羽樣輕。',64,'全唐诗/poet.song.214000.json','["湘流得雨掌來平，艇子乘風羽樣輕。", "過眼千山纔嶺粵，轉頭一水又衡荆。", "大江東下懷鄉國，落日西邊是戍城。", "鳴鴂數聲青嶂晚，客心如鐵也關情。"]'),
('ec460b1e-a0c4-40f6-b403-7b175a3f6a97','和總幕劉景文題杜立齋遺翰詩韻','李曾伯','宋','宋诗','song-poetry','','[]','一老風流兩社間，至今膏馥尚留殘。',64,'全唐诗/poet.song.214000.json','["一老風流兩社間，至今膏馥尚留殘。", "典刑已矣墨猶潤，生死以之盟未寒。", "淮海屬心知士苦，山林投分只儒酸。", "燈前掩袂空三歎，盍與傳諸琬琰看。"]'),
('73355bbd-af65-408e-b1c2-fe232f68c381','辛亥元夕坐間和劉景文韻  其一','李曾伯','宋','宋诗','song-poetry','','[]','客心似向漢槎來，便盍觀光近斗台。',64,'全唐诗/poet.song.214000.json','["客心似向漢槎來，便盍觀光近斗台。", "王儉池邊新節物，劉郎觀裏舊根栽。", "饒人老月添春好，特地癡雲際晚開。", "明歲傳柑天上宴，馬頭猶記渚宮囘。"]'),
('83ff9e46-e033-4e6a-94ff-2736c36b1d0c','辛亥元夕坐間和劉景文韻  其二','李曾伯','宋','宋诗','song-poetry','','[]','多謝孀娥得得來，肯陪綠鬢映黄台。',64,'全唐诗/poet.song.214000.json','["多謝孀娥得得來，肯陪綠鬢映黄台。", "剪成絳蠟燈間艷，移向青油幕底栽。", "萬目競拚通夕看，兩眉贏得片時開。", "祗憐人亦牽絲戲，任向當場弄幾囘。"]'),
('dac62cf4-573f-4a28-9b29-aa2ae5ef5770','書院諸客登仲宣樓以詩寄之','李曾伯','宋','宋诗','song-poetry','','[]','指點層雲氣可干，官身浩歎不如閑。',64,'全唐诗/poet.song.214000.json','["指點層雲氣可干，官身浩歎不如閑。", "幾回落日詩懷古，一半春風酒破慳。", "許我婆娑從白髮，於人嫵媚有青山。", "前身王粲重拈筆，惜欠胡床著席間。"]'),
('f4d7574a-0521-43dd-915f-35191942f92b','送書記雷宜叔造朝','李曾伯','宋','宋诗','song-poetry','','[]','五色雲邊昔稚圭，軍戎萬里已周知。',64,'全唐诗/poet.song.214000.json','["五色雲邊昔稚圭，軍戎萬里已周知。", "趨朝豈止重憑廣，出幕聊爲送適詩。", "行李羽輕清漲穩，交情珍重歲寒期。", "君王若問荆州事，白玉階前細數之。"]'),
('6d78031e-bbff-40f3-a5df-cbfc6bcdead3','曾總幹以乃尊侍郎二詩見示和韻  其一','李曾伯','宋','宋诗','song-poetry','','[]','別公知閲幾桑陰，玉筍山中舊隠尋。',64,'全唐诗/poet.song.214000.json','["別公知閲幾桑陰，玉筍山中舊隠尋。", "郾暮聯鑣來自舊，涇舟共楫繼由今。", "一門翁季芝蘭味，四海弟兄金石心。", "塞上西風漸蕭瑟，書來毋惜寄規箴。"]'),
('38adb31e-4336-478f-9b56-d8d914ff7a9b','曾總幹以乃尊侍郎二詩見示和韻  其二','李曾伯','宋','宋诗','song-poetry','','[]','疇昔風雲共壯游，笑吳夏口蜀江油。',64,'全唐诗/poet.song.214000.json','["疇昔風雲共壯游，笑吳夏口蜀江油。", "我猶乘險凜孤注，君早得閑先幾籌。", "目底阿蒙元齷齪，膝間文度儘風流。", "箇中妙理誰能會，且向平原喚督郵。"]'),
('40ff3ad8-260e-4494-a0a2-83ffbc6f3553','陳次賈歸以二詩言別和韻送之  其一','李曾伯','宋','宋诗','song-poetry','','[]','百尺樓前艤去桅，元龍豪氣肯低徊。',64,'全唐诗/poet.song.214000.json','["百尺樓前艤去桅，元龍豪氣肯低徊。", "昔從桂嶺訪梅去，今自荆江載月回。", "敢擬王劉曾主客，應嗤瑜遜等輿臺。", "轉頭落日陽關外，三歎可人呼不來。"]'),
('1341c2b3-7217-43e8-b8fb-7bff07f26557','陳次賈歸以二詩言別和韻送之  其二','李曾伯','宋','宋诗','song-poetry','','[]','手袖朱絃綠綺琴，身雖湖海調山林。',64,'全唐诗/poet.song.214000.json','["手袖朱絃綠綺琴，身雖湖海調山林。", "家園千里歸心切，朋友中年別恨深。", "國事艱難殫我力，世情巧令聽渠任。", "海門雁過應相憶，塞上征人正苦心。"]'),
('6b38b66a-0fc9-4c0f-9675-ff02924d6342','壽利州趙漕  其一','李曾伯','宋','宋诗','song-poetry','','[]','天稟銀河一派清，藹然中外播休聲。',64,'全唐诗/poet.song.214000.json','["天稟銀河一派清，藹然中外播休聲。", "金城方略今充國，斜谷規模舊孔明。", "屈久轡絲勤使指，再須班筍著宗英。", "九重側席親賢切，有詔西南起老成。"]'),
('f551926f-765f-4c55-b0b0-390704073ce9','壽利州趙漕  其二','李曾伯','宋','宋诗','song-poetry','','[]','幾載星軺惠漢關，埴培壽脈一分寬。',64,'全唐诗/poet.song.214000.json','["幾載星軺惠漢關，埴培壽脈一分寬。", "數絲鶴鬢因民白，一片鷗心爲國丹。", "綠野高風雖獨慕，黄花晚節正爭看。", "勳名麟閣清芬在，且伴松椿傲歲寒。"]'),
('cacac3cb-0f44-4a63-b256-c1d85819f8fe','壽遂寧李漕  其一','李曾伯','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','今世儒宗一泰山，暫乘紫氣下函關。',64,'全唐诗/poet.song.214000.json','["今世儒宗一泰山，暫乘紫氣下函關。", "主盟道學周程上，伯仲詩名李杜間。", "少府暫分膚使節，甘泉合在侍臣班。", "春江一碧平於掌，好趣牙檣待賜環。"]'),
('aea3789b-e1c5-43bf-94b6-1d3635666026','壽遂寧李漕  其二','李曾伯','宋','宋诗','song-poetry','','[]','自從岳牧著民庸，十載岷峨帝眷隆。',64,'全唐诗/poet.song.214000.json','["自從岳牧著民庸，十載岷峨帝眷隆。", "草带雨鋤周圃綠，粟和烟輓漢關紅。", "活人陰德深無盡，壽國良方用不窮。", "一轉鈞間黄閣去，天涯歲歲囿東風。"]'),
('3442e7c2-574e-4fc8-969e-8cf2e9325123','壽遂寧李漕  其三','李曾伯','宋','宋诗','song-poetry','','[]','自是清都紫府仙，德星躔次劍東川。',64,'全唐诗/poet.song.214000.json','["自是清都紫府仙，德星躔次劍東川。", "香浮世界鶑花地，人樂春風燕麥天。", "元祐賢材名閤近，紹興相業慶基綿。", "一年一佛爲公壽，五百尊成五百年。"]'),
('ede8aadf-9268-40b0-bd8e-f3ed545fe9d9','壽蜀帥  其一','李曾伯','宋','宋诗','song-poetry','','[]','天遣長庚衍瓞瓜，幾年清廟著聲華。',64,'全唐诗/poet.song.214000.json','["天遣長庚衍瓞瓜，幾年清廟著聲華。", "九重璿派周麟趾，千里金城漢犬牙。", "未駕說舟儀列鷺，已麾段笏擊長蛇。", "堂堂一節鼎鐺耳，豈借西山太史家。"]'),
('93ddc01a-787f-4080-bc78-166689081b24','壽蜀帥  其二','李曾伯','宋','宋诗','song-poetry','','[]','霄漢當年把繡衣，載持齋鉞建侯珪。',64,'全唐诗/poet.song.214000.json','["霄漢當年把繡衣，載持齋鉞建侯珪。", "春城月淡銅梁北，夜柝星沉玉壘西。", "外閫規模蕭葛上，中朝勳望范韓齊。", "楓宸側席親賢久，早晚鳴珂步相堤。"]'),
('376fec0c-47ac-4734-a1dd-39d77cd57b5a','壽蜀帥  其三','李曾伯','宋','宋诗','song-poetry','','[]','不用江山當壽巵，年年一佛住峨眉。',64,'全唐诗/poet.song.214000.json','["不用江山當壽巵，年年一佛住峨眉。", "崧高復見歌申伯，坰野寧無頌魯僖。", "歲比絳人逾甲子，日逢皇覽揆庚寅。", "書生愧乏梅花賦，引領東風上北枝。"]'),
('80d72dcf-8337-4bfb-bd75-9001e2210db4','壽應茶馬  其一','李曾伯','宋','宋诗','song-poetry','','[]','自聯班序簡宸聰，廊廟江湖一節同。',64,'全唐诗/poet.song.214000.json','["自聯班序簡宸聰，廊廟江湖一節同。", "百世幾人今蜀日，千年一到昔虞風。", "得莘渭上康時策，有伊洛間傳道功。", "早晚爲霖洗炎熱，蒼生俱出炭爐中。"]'),
('0f464e77-15f1-457e-a64d-01d42f25e201','壽應茶馬  其二','李曾伯','宋','宋诗','song-poetry','','[]','太微一宿燭魚鳬，已奏平反課轉輸。',64,'全唐诗/poet.song.214000.json','["太微一宿燭魚鳬，已奏平反課轉輸。", "綠碾雨前舒鳳爪，青鎌雪外長龍顱。", "班崇東壁圖書府，惠暢西夷道德塗。", "佇佐修壤歌六月，載銘石鼓會東都。"]'),
('2d6a8976-7afc-4df6-8246-ff00c66bd69e','壽應茶馬  其三','李曾伯','宋','宋诗','song-poetry','','[]','漢昴殷箕謾擬倫，天將平治啟儒真。',64,'全唐诗/poet.song.214000.json','["漢昴殷箕謾擬倫，天將平治啟儒真。", "鍾英寶婺金華地，斂福銅梁玉壘民。", "冰壑雪山無點暑，桃溪棠蔭有餘春。", "綿綿壽脈無窮處，一派根源在至仁。"]'),
('f5d5e7f9-55c1-4695-9911-a094925b8ac9','壽陳制垣  其一','李曾伯','宋','宋诗','song-poetry','','[]','十載青油駐漢關，勛名高壓峴南山。',64,'全唐诗/poet.song.214000.json','["十載青油駐漢關，勛名高壓峴南山。", "雨滋萬頃春犁樂，月淡三邊夜柝閑。", "爲小朝廷留宿望，升真學士重崇班。", "九重銀信知非遠，白玉階前一武間。"]'),
('b8a3034b-97cb-483e-83d0-5ee2ee7a8c22','壽陳制垣  其二','李曾伯','宋','宋诗','song-poetry','','[]','向來荆楚說邊州，人士今誇樂國游。',64,'全唐诗/poet.song.214000.json','["向來荆楚說邊州，人士今誇樂國游。", "千里潢池自交擾，一江漢水獨安流。", "兵無敢惰身爲率，民有猶饑惠亟賙。", "陰德活人無量大，不須香火祝王侯。"]'),
('87e66018-6cbe-4a23-97e8-4f99ed62a55f','壽陳制垣  其三','李曾伯','宋','宋诗','song-poetry','','[]','東皇妝就牡丹天，來獻蓬萊不老仙。',64,'全唐诗/poet.song.214000.json','["東皇妝就牡丹天，來獻蓬萊不老仙。", "耆舊喜增羊祜傳，蠻夷欣問晉公年。", "休懷苕水清風適，且醉檀溪綠草邊。", "願向衣冠圖上看，銀屏千歲映貂蟬。"]'),
('ea2b5162-7786-4733-b63a-9fb1c2679ef3','代爲其親壽  其一','李曾伯','宋','宋诗','song-poetry','','[]','十載青油駐峴山，屹如一柱倚人寰。',64,'全唐诗/poet.song.214000.json','["十載青油駐峴山，屹如一柱倚人寰。", "秧疇雨足春犁樂，榆塞風清夜柝閑。", "威望龍堆氈帳外，勳名麟閣鼎彝間。", "命圭指日催裴度，樂府無煩唱玉關。"]'),
('f2937369-7abd-47f2-8c9a-44d5db576394','代爲其親壽  其二','李曾伯','宋','宋诗','song-poetry','','[]','兩星相比映文昌，戲綵蹁躚戟衛香。',64,'全唐诗/poet.song.214000.json','["兩星相比映文昌，戲綵蹁躚戟衛香。", "鬢底公因民事白，眉邊人卜詔書黄。", "五千文字爲家計，百萬陰功即壽鄉。", "要學元和同九老，未誇耆舊傳襄陽。"]'),
('aedcccee-94fa-4329-8b17-68276fbd8625','壽岳漕  其一','李曾伯','宋','宋诗','song-poetry','','[]','渡江人物照乾坤，盟府勳庸奕葉存。',64,'全唐诗/poet.song.214000.json','["渡江人物照乾坤，盟府勳庸奕葉存。", "崧岳千年申伯雅，漢臺幾世仲華孫。", "自將翠節臨南紀，更佐金城護北門。", "禁柳官梅正春色，好看鳴玉上天閽。"]'),
('a39c922f-b179-4d81-be0c-8b9bb6da8e0f','壽岳漕  其二','李曾伯','宋','宋诗','song-poetry','','[]','檀溪翠霧曉輪囷，共慶皇華誕玉辰。',64,'全唐诗/poet.song.214000.json','["檀溪翠霧曉輪囷，共慶皇華誕玉辰。", "僂指明宵三五夜，從頭新歲八千春。", "且煩皎月清邊徼，行逐東風造禁宸。", "留取棠陰蔽南峴，爲陪羊杜壽蒼珉。"]'),
('bcd59e5c-a05a-485b-9d3d-a129198471b1','江陵和費察推九蘂瑞蓮韻','李曾伯','宋','宋诗','song-poetry','','[]','喜對荆人一笑嫣，吾邦今見此嘉蓮。',64,'全唐诗/poet.song.214000.json','["喜對荆人一笑嫣，吾邦今見此嘉蓮。", "脂容嫵媚目疑幻，玉貌參差骨是仙。", "試把萬葩千卉較，曾無一蒂九芳連。", "分明河洛中興象，要竭精忠答上天。"]'),
('2389b1ef-ab36-4670-bb9c-ec7a94d81c01','壬子夏偶成','李曾伯','宋','宋诗','song-poetry','','[]','心已灰如鬢已皤，迫人桑蔭疾於梭。',64,'全唐诗/poet.song.214000.json','["心已灰如鬢已皤，迫人桑蔭疾於梭。", "更嘗萬事不爲少，恍悟一身猶是多。", "田里乞身斯可矣，功名到手竟如何。", "公餘幸喜邊烽靜，且對樽前浩浩歌。"]'),
('22c18b32-02e9-425b-9f96-25e9146b6ab2','壬子江陵寄聞人松庵','李曾伯','宋','宋诗','song-poetry','','["\u897f\u6e56"]','不見松庵又幾年，書來云欲卜新椽。',64,'全唐诗/poet.song.214000.json','["不見松庵又幾年，書來云欲卜新椽。", "我方北寨愁供戍，君盍西湖喜結緣。", "多謝烹魚勤客遺，薄言騎鶴寓腰纏。", "惜無廣厦歡顔力，姑用長安作酒錢。"]'),
('ff76a504-f3de-4c87-8b0f-001e382300ae','秋霖喜霽適覩廟堂酬唱相去數千里而陰晴同之因用韻','李曾伯','宋','宋诗','song-poetry','','[]','明良相正體坤乾，感格時暘本致虔。',64,'全唐诗/poet.song.214000.json','["明良相正體坤乾，感格時暘本致虔。", "坐使群方皆見日，誰言千里不同天。", "只將精白承休德，豈在緇黄結善緣。", "更得北風無羽檄，不妨舉酒樂康年。"]'),
('0b3fa873-d7a1-45f4-a0fd-6b3d5b8c7dd0','宴四川余制置樂語口號','李曾伯','宋','宋诗','song-poetry','','[]','分弓輟自侍臣班，來擁貔貅設漢關。',64,'全唐诗/poet.song.214000.json','["分弓輟自侍臣班，來擁貔貅設漢關。", "膽落氈裘千里外，指呼羽扇一麾間。", "共期朴實工夫到，會見承平氣象還。", "荆益論盟如此酒，從今西顧釋天顔。"]'),
('b5c40148-3e64-44d5-a02c-acc83da9d96f','宴嘉興謝守樂語口號','李曾伯','宋','宋诗','song-poetry','','[]','輒從荀玉鎮扶風，政事龔黄一樣同。',64,'全唐诗/poet.song.214000.json','["輒從荀玉鎮扶風，政事龔黄一樣同。", "白髮歸田嗟我老，黑頭入相屬之公。", "蕭然舊菊荒蕪裏，欣在甘棠蔽芾中。", "詔下鴛湖天咫尺，好風行送畫船東。"]'),
('00caf6d2-9917-4518-bdbc-40e1f96c2147','宴湖南章漕樂語口號','李曾伯','宋','宋诗','song-poetry','','[]','使星一點壽星邊，惠我三湘兩閲年。',64,'全唐诗/poet.song.214000.json','["使星一點壽星邊，惠我三湘兩閲年。", "既付龜符還楚壘，便持犀節上堯天。", "何參接踵新規在，僑札論心舊識然。", "入對丹墀訪南事，細陳霜頰障蠻烟。"]'),
('32bcdcc2-2859-4a35-8f33-4b1686ef9c85','餞章漕樂語口號','李曾伯','宋','宋诗','song-poetry','','[]','來湘話浙倍綢繆，天路風高借莫留。',64,'全唐诗/poet.song.214000.json','["來湘話浙倍綢繆，天路風高借莫留。", "不俟駕行何憚暑，適逢圭覲恰當秋。", "登仙堪羨星辰履，歸老終尋雪夜舟。", "公到甘泉陳大計，毋忘膏雨澤南州。"]'),
('df52c417-5597-43fc-8769-c0422424d856','宴湖南洪漕樂語口號','李曾伯','宋','宋诗','song-poetry','','[]','仗節來從玉筍班，福星甫照舉歡顔。',64,'全唐诗/poet.song.214000.json','["仗節來從玉筍班，福星甫照舉歡顔。", "持荷自盍登堯陛，輓粟寧容久漢關。", "慶集正當萸菊際，交盟喜在芷蘭間。", "定王臺小難留住，祗恐天邊即予環。"]'),
('7086b31b-5635-43e0-a725-036611bc03a6','宴廣西豐憲樂語口號','李曾伯','宋','宋诗','song-poetry','','[]','帝遣星軺入桂州，雨餘凉嫩一天秋。',64,'全唐诗/poet.song.214000.json','["帝遣星軺入桂州，雨餘凉嫩一天秋。", "繡衣翠節皇華遠，碧玉青羅喜氣浮。", "猶昔孺文同此酒，喜今師德在吾舟。", "相期辦却平蠻事，公向三階我一丘。"]'),
('a823796a-4299-4cf1-a04d-86edc03368df','贈柯山道士鄭雲谷來住澧之洞晨  其一','李曾伯','宋','宋诗','song-poetry','','[]','本是住山人，來作開山計。',48,'全唐诗/poet.song.214000.json','["本是住山人，來作開山計。", "雲出元無心，有心爲雲累。", "執柯與紉蘭，如幻亦如寄。", "神游有崑蓬，御風歸歟是。"]'),
('3992ffac-724a-4c03-a928-eafc7d16d5ee','贈柯山道士鄭雲谷來住澧之洞晨  其二','李曾伯','宋','宋诗','song-poetry','','[]','道人本分事，不用達人詩。',48,'全唐诗/poet.song.214000.json','["道人本分事，不用達人詩。", "烟霞痼疾間，風月陶寫之。", "漆園直寓言，謫仙豈吾師。", "卷懷置心齋，焚薌比希夷。"]'),
('632bd866-0fef-46c6-8493-053d63b8cce0','題懷遠樓','李曾伯','宋','宋诗','song-poetry','','[]','心遠目難盡，境須詩與論。',48,'全唐诗/poet.song.214000.json','["心遠目難盡，境須詩與論。", "風檣誰客艇，烟樹某家村。", "野草春千古，江天月一痕。", "舊時方冊事，一笑付方樽。"]'),
('4091ef4e-7f91-4668-875a-6bdc3a3000b8','挽趙無垢  其一','李曾伯','宋','宋诗','song-poetry','','[]','早奏玉垣績，纔登金掌班。',48,'全唐诗/poet.song.214000.json','["早奏玉垣績，纔登金掌班。", "衆皆期兩地，誰謂老三山。", "江夏勳勞上，東平禮義間。", "壯猷慚弗克，孰與濟時艱。"]'),
('e721bb2b-c9d0-4e6a-9226-22315b96e3ee','挽趙無垢  其二','李曾伯','宋','宋诗','song-poetry','','[]','公未通閨日，相從入幕游。',48,'全唐诗/poet.song.214000.json','["公未通閨日，相從入幕游。", "瞠乎慚後乘，藉甚偉前籌。", "原隰曾并轡，江濤幾共舟。", "柯山回首處，老淚爲橫流。"]'),
('50cdecba-119b-42b0-a280-bcbcfd7a1220','挽曾侍郎  其一','李曾伯','宋','宋诗','song-poetry','','[]','名閥蜚聲遠，甘泉跬步登。',48,'全唐诗/poet.song.214000.json','["名閥蜚聲遠，甘泉跬步登。", "詞華八塼日，姓字一條冰。", "戀闕丹心在，臨朝清問曾。", "秀溪春夢杳，留得瓣香曾。"]'),
('7ab62af7-e865-4cfc-92e5-d7819006da54','挽曾侍郎  其二','李曾伯','宋','宋诗','song-poetry','','[]','江漢雲鴻遇，星霜電驥馳。',48,'全唐诗/poet.song.214000.json','["江漢雲鴻遇，星霜電驥馳。", "同朝更同幕，相好更相規。", "肯託賢郎我，追傷益友誰。", "哀辭千里寄，相者爲歌之。"]'),
('9478e3fb-b344-48a8-8a3c-3fc4f39ddb47','送石首傅宰','李曾伯','宋','宋诗','song-poetry','','[]','石首邑易治，難山政可師。',48,'全唐诗/poet.song.214000.json','["石首邑易治，難山政可師。", "弦歌聊戲耳，談笑以爲之。", "省德多餐飯，勤官少作詩。", "交情毋恃舊，公事定相規。"]'),
('ed3be1c1-1869-42f9-a16a-1ea2314c460f','題推篷梅軸  其一','李曾伯','宋','宋诗','song-poetry','','[]','玉奴梳洗罷，半面露新妝。',144,'全唐诗/poet.song.214000.json','["玉奴梳洗罷，半面露新妝。", "江岸數枝影，篷窗一罅香。", "橫披含曉色，卧對壓春芳。", "庾嶺幾多力，剡溪方寸長。", "蕭然臨水月，即之貫冰霜。", "老出墨池手，清入詩人腸。", "孤梢亞籬落，全樹嗤玉堂。", "故舊解后見，雋永約略嘗。", "熏羞篆鼎供，醉夢紙帳傍。", "頼君潤色工，著我懷袖藏。", "太繁厭易啟，所取廉毋傷。", "誰爲語逋遜，持此同相羊。"]'),
('172cb7bb-d225-49a2-8114-324044b8848b','題推篷梅軸  其二','李曾伯','宋','宋诗','song-poetry','','[]','片玉漏春色，恍逢江路傍。',144,'全唐诗/poet.song.214000.json','["片玉漏春色，恍逢江路傍。", "中山費巧思，壽陽矜輕妝。", "精神盈一握，標格壓衆芳。", "彷彿水邊影，有無風前香。", "卷舒適人意，推敲撓予腸。", "形狀僕草玄，譜系根花光。", "勿謂數枝隘，中寓千丈强。", "晏不滿幾尺，焉用張堂堂。", "桃李空滿園，媿死安敢當。", "太羹少爲貴，鼎鼐滋味長。", "只愁楮君弱，蠹魚食春陽。", "慎勿示肉眼，收付奚奴囊。"]'),
('360c3fe2-9e10-48d2-9a1d-a77c85a7a841','仲宣樓落成和吳深源制參韻  其一','李曾伯','宋','宋诗','song-poetry','','[]','巍樓聳立千仞壁，熊楚奇觀此其一。',208,'全唐诗/poet.song.214000.json','["巍樓聳立千仞壁，熊楚奇觀此其一。", "蒼龍夭矯出一頭，下瞰七澤乾坤浮。", "平遠獻狀呈几席，氣勢彈壓東西州。", "仲宣襟抱六合隘，生閲曹劉幾成敗。", "當時徙倚落日邊，豈計嘉名鎮長在。", "高談猶想四座驚，好語意得由天成。", "景升逝矣建安往，豈濁斯足清斯纓。", "今朝我與群賢集，風景還能類前日。", "賦斯樓者天台公，揚厲其誰會椽筆。", "嗟今視昔後視今，君子思遠而憂深。", "運方濟泰月在臨，有如此水舟同心。", "芳名起日炳若揭，老子婆娑衆賓悅。", "斯城斯樓天下無，王賦吳詩成四絕。"]'),
('1f159a05-f143-410e-b117-d5320a2d15fe','仲宣樓落成和吳深源制參韻  其二','李曾伯','宋','宋诗','song-poetry','','[]','東都一星下東壁，粲以文鳴斗南一。',208,'全唐诗/poet.song.214000.json','["東都一星下東壁，粲以文鳴斗南一。", "玄德髀肉瞞白頭，俯仰宇宙俱漚浮。", "主人景升帝王胄，風土更羨遠中州。", "安能不粟效夷隘，活著期扶弈枰敗。", "仲華解笑人寂寂，歷落山川舊圖在。", "夜深旅夢雞喚驚，崇樓百尺般手成。", "憑闌四顧萬慮起，鄉鄰寧不思冠纓。", "英雄海內方麕集，長憶永平太平日。", "在心爲志流爲詩，吾豈爭雄鸚鵡筆。", "風流好事傳到今，豈知漢澤入人深。", "暇日載酒清流臨，名篇雒啟誦吾心。", "偈言玩味猶諦揭，意趣充然芻豢悅。", "飛鴻盡處烟雨隔，姑嗅梅花共清絕。"]'),
('afea2476-cf80-49d8-84f1-c966155a9355','管順甫以湘竹爲青奴兒貺爲名湘夫人賦以謝之','李曾伯','宋','宋诗','song-poetry','','[]','妾家淇園北封君，厥祖慈事宗蒼篔。',258,'全唐诗/poet.song.214000.json','["妾家淇園北封君，厥祖慈事宗蒼篔。", "子孫異代貞節聞，枝分一派從南巡。", "千古流落湘江濱，幾番雨露敷新榮。", "斑斑不改啼紅痕，膏煎漆伐悔自矜。", "卒以取禍罹斧斤，工巧斲削資它人。", "管城夫子出意新，作俑取義何其云。", "致之千里充吾庭，命以湯沐虞嬪名。", "彷彿太伯之文身，虛中直外圓且明。", "不絲不穀不受塵，一笑不用捐千金。", "曲眉豐頰從雜陳，雖有多喙無一嗔。", "晨夕薦我眠風櫺，曲肱時復呼真真。", "骨雖非玉肌似冰，蝶夢不到巫山雲。", "白家蠻素卿自卿，老我祝爾毋忘盟。", "以便吾體全吾神，招魂共讀離騷經。", "推枕同作華胥民，只虞一夜秋氣清。", "猶筐中扇牆角檠，盍爲青奴亦作白頭吟。"]'),
('bdea665e-acd0-43f9-bbe7-b0ab5fa1e182','自和','李曾伯','宋','宋诗','song-poetry','','[]','北帝東皇競化工，六花吹滿鬢毛鬆。',64,'全唐诗/poet.song.214000.json','["北帝東皇競化工，六花吹滿鬢毛鬆。", "誰令霓衛鋪張曉，來與牛鞭斷送冬。", "寶歷明朝新紀鳳，珠宮昨夜起驪龍。", "驅寒乞取酒泉郡，何必荆州萬戶封。"]'),
('210dcd3f-4a0d-43ed-b16c-37c32ebe896c','登四望亭觀雪','李曾伯','宋','宋诗','song-poetry','','[]','踏雪一登城上亭，山川草木亦精神。',64,'全唐诗/poet.song.214000.json','["踏雪一登城上亭，山川草木亦精神。", "不知四面孰爲水，但見一般俱是春。", "此際全然許和氣，於中何處有纖塵。", "我來謾啜茶兒去，疑是神仙境界人。"]'),
('e1fc950f-655b-4bf8-8d08-fe2099f69d5f','自和','李曾伯','宋','宋诗','song-poetry','','[]','不夜城頭著此亭，東皇幻化一何神。',64,'全唐诗/poet.song.214000.json','["不夜城頭著此亭，東皇幻化一何神。", "相將蓮炬催芳夕，來俾梅花作好春。", "自臘月前尤可喜，覺西風外已無塵。", "銜枚曉奏鵝池捷，爲問和門有此人。"]'),
('33fea40a-cce1-4f6f-a3b6-ff1997a48748','和八窗叔雪中登樓韻','李曾伯','宋','宋诗','song-poetry','','[]','不夜城頭著此亭，山川幻化抑何神。',64,'全唐诗/poet.song.214000.json','["不夜城頭著此亭，山川幻化抑何神。", "高低地勢平於水，窮富人家等是春。", "一氣中間知有造，四方上下了無塵。", "烹茶讀易從古適，不羨梁園作賦人。"]'),
('e0347023-2631-4071-8180-ae96e89661d8','挽陳勉齋文昌  其一','李曾伯','宋','宋诗','song-poetry','','[]','幾年間氣一全才，天以經綸屬勉齋。',64,'全唐诗/poet.song.214000.json','["幾年間氣一全才，天以經綸屬勉齋。", "勳盛十年詞兩制，壽開九袠位三階。", "公於南國恩尤在，人惜東山望莫偕。", "歲晚倏聞梁木壞，君王應亦爲傷懷。"]'),
('e1bbc303-b179-4b6d-9f66-7d7aeb861096','挽陳勉齋文昌  其二','李曾伯','宋','宋诗','song-poetry','','[]','憶昨從軍辱己知，不圖二紀踵前規。',64,'全唐诗/poet.song.214000.json','["憶昨從軍辱己知，不圖二紀踵前規。", "人非城是黄粱夢，地老天荒白髮悲。", "墮淚忍看羊祜傳，傷心徒作魏公詩。", "勉旃衣鉢芝蘭事，傳取清風百世師。"]'),
('0426d28a-b1ff-48a3-8226-aaa62bbae3dc','壬子勸駕','李曾伯','宋','宋诗','song-poetry','','[]','人物從來盛楚南，新元詔士奉芝函。',64,'全唐诗/poet.song.214000.json','["人物從來盛楚南，新元詔士奉芝函。", "身逢熙運千之一，名占巍科十有三。", "好趁驛梅催騎策，歸來官柳映袍藍。", "池邊相祝趨聞喜，賸取宮花一朶簪。"]'),
('b18cb12e-74f0-4be9-bf02-9e05b94c9027','和劉舍人詠雪','李曾伯','宋','宋诗','song-poetry','','[]','怪見漫空萬蝶狂，須臾色界眩昏黄。',64,'全唐诗/poet.song.214000.json','["怪見漫空萬蝶狂，須臾色界眩昏黄。", "風姨知費幾番信，天女纔施半面妝。", "筆底詩徒和冰柱，酒邊舞已失霓裳。", "梁園甚恨孤佳約，一笑吟梅且擅場。"]'),
('71cff39a-2ed9-4af3-8e0b-a668e73f5830','立春日雪','李曾伯','宋','宋诗','song-poetry','','[]','剪綵寧如剪水工，瑞烟融出玉龍鬆。',64,'全唐诗/poet.song.214000.json','["剪綵寧如剪水工，瑞烟融出玉龍鬆。", "重看臘白不爲晚，未到昏黄猶見冬。", "多謝玉妃鞭白鳳，爲催青帝駕蒼龍。", "天心端報豐年喜，一稔相期樂可封。"]'),
('beadfffc-150a-4b6e-a39e-f4e26f51b609','挽別大參  其一','李曾伯','宋','宋诗','song-poetry','','[]','幾歷藩垣一節勤，歸來兩地會風雲。',64,'全唐诗/poet.song.214000.json','["幾歷藩垣一節勤，歸來兩地會風雲。", "調知白雪陽春別，香到黄花晚節聞。", "夷狄猶知問中立，朝廷惜竟老希文。", "台躔夜折空追歎，留得甘棠滿楚鄖。"]'),
('78c2013b-7bbe-4900-af11-64658ec09eb1','挽別大參  其二','李曾伯','宋','宋诗','song-poetry','','[]','早年公已阿戎知，幾與征西履屐隨。',64,'全唐诗/poet.song.214000.json','["早年公已阿戎知，幾與征西履屐隨。", "百六椽間無足紀，二三子側每相思。", "重來荆渚平生若，寧復苕溪一見之。", "哀此哲人今已矣，詩兮豈但哭吾私。"]'),
('2dcdfb60-ac40-4b26-9639-7785cb4a221c','登河山萬里樓','李曾伯','宋','宋诗','song-poetry','','[]','收攬河山入此樓，幾年蚡冒古荆州。',64,'全唐诗/poet.song.214000.json','["收攬河山入此樓，幾年蚡冒古荆州。", "目窮夕照西沉隊，心到寒江東盡頭。", "歷歷雄圖史南北，紛紛遺恨晉春秋。", "酒邊感慨憑闌久，衰柳行間數白鷗。"]'),
('6a580328-cff0-4b82-9361-54fbd269eda1','過西海隘即事','李曾伯','宋','宋诗','song-poetry','','[]','江带湖襟護一堤，人烟落落柳依依。',64,'全唐诗/poet.song.214000.json','["江带湖襟護一堤，人烟落落柳依依。", "白鷗世界秋容澹，紅蓼汀州水際肥。", "斷岸馬危遲弗驟，中流舟順疾於飛。", "歸來得自推敲了，更共登樓對夕暉。"]'),
('e31f2d5e-9364-4a48-bd79-a0865c81f69b','贈楊戶曹','李曾伯','宋','宋诗','song-poetry','','[]','壯年游戲寶峰傍，夢覺黄粱鬢盡霜。',64,'全唐诗/poet.song.214000.json','["壯年游戲寶峰傍，夢覺黄粱鬢盡霜。", "舊俗幾家罹變故，遠人千里歎清揚。", "酆南松檟煩君訪，劍北榛蕪動客傷。", "頼有柳州詩喚起，莫言安頓便思鄉。"]'),
('d8c16745-249e-4399-9793-4224cee93ac3','送戴書記','李曾伯','宋','宋诗','song-poetry','','[]','遠馭夷塗邁牧之，三霜道路飽驅馳。',64,'全唐诗/poet.song.214000.json','["遠馭夷塗邁牧之，三霜道路飽驅馳。", "和風俯趁春迎仗，落月回思夜入帷。", "自愧薦衡無好表，不妨道適有新詩。", "歲艱時棘邊臣老，向闕須陳黼扆知。"]'),
('0c8d16eb-e11d-4871-a4e7-6510b1316c57','和劉舍人咏鞦韆','李曾伯','宋','宋诗','song-poetry','','[]','院落陰陰捲晝簾，綵繩高掛矗青天。',64,'全唐诗/poet.song.214000.json','["院落陰陰捲晝簾，綵繩高掛矗青天。", "纖腰對蹴爭先起，香汗交流倦欲眠。", "花畔驚呼簪珥墜，柳梢時出綵羅鮮。", "可憐牆外行人惱，應費長安酒價千。"]'),
('91957ab7-ab52-4e9d-b36f-eccb5d0d9aba','襄捷和書院韻','李曾伯','宋','宋诗','song-poetry','','[]','我有芳樽與子同，老身却自悔從戎。',64,'全唐诗/poet.song.214000.json','["我有芳樽與子同，老身却自悔從戎。", "休言晉事懷元凱，尚欠唐兵縛世充。", "往跡悠悠寧有極，短才咄咄歎無功。", "賦詩釃酒聊行樂，到底誰爲一世雄。"]'),
('2bd5964a-78bc-4e0b-a762-425c834b584c','伏讀靖康宸札有感','李曾伯','宋','宋诗','song-poetry','','[]','盟尋城下事方危，尚爾衰民益虜資。',64,'全唐诗/poet.song.214000.json','["盟尋城下事方危，尚爾衰民益虜資。", "紿楚時曾無紀信，交秦計卒墮張儀。", "抗言玉鉉吁何及，捐積瓊林惜已遲。", "劫火既灰遺墨在，小臣唯有淚沾頤。"]'),
('b3e42068-54eb-495a-873c-0ff19535a24b','和制幹陳循道惠鶴韻','李曾伯','宋','宋诗','song-poetry','','[]','怪得中宵夢羽衣，詩來恍見九臯飛。',64,'全唐诗/poet.song.214000.json','["怪得中宵夢羽衣，詩來恍見九臯飛。", "期君與共淮淝捷，舍我曷爲緱嶺歸。", "愧乏纏腰娛綵服，喜將聞唳到柴扉。", "凌雲豈是籠中物，要學當年老令威。"]'),
('a27d4b6d-1e27-4f99-afa4-2dc58f2bda0b','和劉舍人夏雨喜霽','李曾伯','宋','宋诗','song-poetry','','[]','古戍春歸歎寂寥，老槐陰下鬢蕭蕭。',64,'全唐诗/poet.song.214000.json','["古戍春歸歎寂寥，老槐陰下鬢蕭蕭。", "正愁雨久人情厭，且喜天晴物意饒。", "歌吹遏雲傳白苧，旌旗拂日翳紅蕉。", "月邊休聽啼鵑恨，只把詩篇與酒銷。"]'),
('bd7fd86d-2870-494b-a250-d8644f4196d5','五月聞蛩有感','李曾伯','宋','宋诗','song-poetry','','[]','南風先自作秋聲，蛩爾何知亦早吟。',64,'全唐诗/poet.song.214000.json','["南風先自作秋聲，蛩爾何知亦早吟。", "慵婦機邊重到耳，征人塞上頓驚心。", "索裘應解寒將晚，徹土須乘天未陰。", "聞此休將兒戲看，盍圖遠略備當今。"]'),
('80576560-0fbb-46c4-bf5e-68e35cf21abc','自和','李曾伯','宋','宋诗','song-poetry','','[]','纔聽鳴蜩葉底聲，倏聞振羽草根吟。',64,'全唐诗/poet.song.214000.json','["纔聽鳴蜩葉底聲，倏聞振羽草根吟。", "物情感我千絲鬢，時事縈人一片心。", "讀易牀頭新課業，回文機上舊光陰。", "客懷休用嗟疇昔，更老那知得似今。"]'),
('1d5015e4-73f0-476b-b340-ec30af5d9b25','累日脾疾自歌','李曾伯','宋','宋诗','song-poetry','','[]','壯年筋力慣驅馳，堪歎新來數問醫。',64,'全唐诗/poet.song.214000.json','["壯年筋力慣驅馳，堪歎新來數問醫。", "生老病催無怪者，寸關亦可自知之。", "養痾抗疏吾謀是，論證投方某劑宜。", "識破幻軀天賦命，兒曹昵昵復何疑。"]'),
('9503a153-2d0e-420c-8b16-68f0fc7d3683','題宣公祠','李曾伯','宋','宋诗','song-poetry','','[]','凜凜清規百世師，功名僅見奉天時。',64,'全唐诗/poet.song.214000.json','["凜凜清規百世師，功名僅見奉天時。", "忠謀任起姦諛忌，感涕寧無士卒思。", "落日桑榆存舊蹟，西風蘆葦護荒祠。", "忠南流落何遺恨，留得良方遺後醫。"]'),
('70cc0d58-0993-49eb-95d4-5a813e780f94','和袁提刑咏雪  其一','李曾伯','宋','宋诗','song-poetry','','[]','羽衛鬖髿萬玉然，元從繡斧下青天。',32,'全唐诗/poet.song.214000.json','["羽衛鬖髿萬玉然，元從繡斧下青天。", "分明要與荆人看，蒼檜擎枝一節堅。"]'),
('f4a59bd8-f351-4827-a1ed-39070435bb7e','和袁提刑咏雪  其二','李曾伯','宋','宋诗','song-poetry','','[]','剪出瑶英頃刻飛，欠加天女錦雲機。',32,'全唐诗/poet.song.214000.json','["剪出瑶英頃刻飛，欠加天女錦雲機。", "虛皇瑞報調羹信，添得梅花略似肥。"]'),
('29eb20a1-a8c7-49c0-9e1f-a117755eb886','和劉制參遺梅  其一','李曾伯','宋','宋诗','song-poetry','','[]','群玉峰頭慣見春，此花常寓雪霜仁。',32,'全唐诗/poet.song.214000.json','["群玉峰頭慣見春，此花常寓雪霜仁。", "東風又促孤山去，應向香邊念故人。"]'),
('dbcf0845-5ec3-4430-82a7-deced141b3f4','和劉制參遺梅  其二','李曾伯','宋','宋诗','song-poetry','','[]','感君寄我一枝春，雨虐風饕苦不仁。',32,'全唐诗/poet.song.214000.json','["感君寄我一枝春，雨虐風饕苦不仁。", "羞得玉奴渾不放，含香猶待浣溪人。"]'),
('9cda4add-4dd2-4f38-8ba1-b55c77248097','又用韻  其一','李曾伯','宋','宋诗','song-poetry','','[]','雪凝霜降不肯春，花神豈類婦人仁。',32,'全唐诗/poet.song.214000.json','["雪凝霜降不肯春，花神豈類婦人仁。", "肯留年後供清思，分付東風與主人。"]'),
('f8104598-8c6e-4a18-b926-4ceece7c7c27','又用韻  其二','李曾伯','宋','宋诗','song-poetry','','[]','妝點銅瓶分外春，惜花尤見主翁仁。',32,'全唐诗/poet.song.214000.json','["妝點銅瓶分外春，惜花尤見主翁仁。", "自憐白髮衰如許，空對花前憶故人。"]'),
('ae8e71ba-c7a3-4454-a4e6-3ae9fd566d7b','題覃懷呂充隠和陶詩卷','李曾伯','宋','宋诗','song-poetry','','[]','數詩盤谷友人欽，一片柴桑處士心。',32,'全唐诗/poet.song.214000.json','["數詩盤谷友人欽，一片柴桑處士心。", "幾十年間南北事，祗令三歎有遺音。"]'),
('902b02a3-7869-4589-b2b6-68aeaf9df698','月峽城樓偶作','李曾伯','宋','宋诗','song-poetry','','[]','雲羃前溪洞，烟荒隔岸城。',48,'全唐诗/poet.song.214000.json','["雲羃前溪洞，烟荒隔岸城。", "秋旗雜山色，曉角带江聲。", "駐騎須邊靜，維舟待峽平。", "掀髯聊徙倚，一雁楚天橫。"]'),
('10262b06-0f0f-4169-af0b-639bd1d3cc4f','月峽重九感懷','李曾伯','宋','宋诗','song-poetry','','[]','落帽尋盟鬢久皤，今朝於此上嵯峨。',64,'全唐诗/poet.song.214000.json','["落帽尋盟鬢久皤，今朝於此上嵯峨。", "雲收谷浄山新霽，風定沙平水不波。", "對菊使人懷古爾，思蓴如我感時何。", "明年把酒知何處，歸到東籬更莫它。"]'),
('37d56b43-3a5d-4db7-b644-379a0e78e7db','登塵表','李曾伯','宋','宋诗','song-poetry','','[]','領略東風一倚闌，凭高便覺小塵寰。',64,'全唐诗/poet.song.214000.json','["領略東風一倚闌，凭高便覺小塵寰。", "目窮千古關河外，身在半空烟靄間。", "二水護城青映带，四山連野翠回環。", "英雄易老愁無極，境是人非鶴自還。"]'),
('848e7b46-29f9-4d88-a442-f0900ddc0bca','自和  其一','李曾伯','宋','宋诗','song-poetry','','[]','百尺城頭著畫闌，當年氣欲壓人寰。',64,'全唐诗/poet.song.214000.json','["百尺城頭著畫闌，當年氣欲壓人寰。", "天機野馬浮游外，世事沙鷗浩蕩間。", "俗靡風頹疇底柱，功成身退盍循環。", "君看方冊中前鑒，辦取輕帆及早還。"]'),
('7db0e232-a5a6-4feb-9dd1-9f44bbfc5e21','自和  其二','李曾伯','宋','宋诗','song-poetry','','[]','最高樓上又層闌，目短元龍空海寰。',64,'全唐诗/poet.song.214000.json','["最高樓上又層闌，目短元龍空海寰。", "棟宇地雄千嶂表，金湯天設兩江間。", "西風障面曾籌檄，夜月胡牀憶佩環。", "老去憑虛心輒悸，蜀城雖好不如還。"]'),
('6f1e9274-65f5-49c4-b872-886eda96a810','首夏而有秋意','李曾伯','宋','宋诗','song-poetry','','[]','纔過清和候，凄然感旅懷。',48,'全唐诗/poet.song.214000.json','["纔過清和候，凄然感旅懷。", "新蛩吟古砌，落葉滿前階。", "榴火春仍駐，槐屯午自佳。", "憑詩記風土，歸以語朋儕。"]'),
('eb62c527-6722-466e-b34b-6c123c3048dc','秋日登樓眺望','李曾伯','宋','宋诗','song-poetry','','[]','徙倚上危梯，雲空望眼迷。',48,'全唐诗/poet.song.214000.json','["徙倚上危梯，雲空望眼迷。", "雁聲秋信北，鴉背夕陽西。", "岸遠舟逾小，水高山陡低。", "家鄉天際是，何日賦歸兮。"]'),
('a2fbeb4b-85ad-49fc-aefb-aca9918481d8','送管季衡赴省','李曾伯','宋','宋诗','song-poetry','','[]','酌君以江南臘釀之酒，祝君以古戎秋芳之蘭。',330,'全唐诗/poet.song.214000.json','["酌君以江南臘釀之酒，祝君以古戎秋芳之蘭。", "餞君以慈恩千佛之筆，贈君以洪鑪九轉之丹。", "酒呼美祿壯行色，蘭取賸馥香人寰。", "筆將披腹寫今古，丹可換骨超仙凡。", "霜晴水瘦過灧澦，春和花發登長安。", "妙齡翰墨富摛藻，肯堂源委從巍冠。", "珊瑚文采世所貴，玉樹瀟灑人爭看。", "出門西笑著鞭去，郄林許我高枝攀。", "湘靈詩成看神助，論秦賦漢從容間。", "大對堯階丹地前，細陳蜀道青天難。", "已然遄往證屢惡，方來未艾憂多端。", "當思頭目我吳楚，罔忽腹背皆夷蠻。", "粒珠束桂楮爛賤，魚頳難赭嗟維艱。", "馬老伏櫪筋力盡，劍新出匣鋒鋩寒。", "維國大寶一箇信，維民司命一分寬。", "挽回線脈冀天鑒，生意庶可岷峨還。", "直須建策邁晁董，無愧名第聯歐韓。", "臚傳可卜慶雲見，會見喜色盈天顔。", "宮袍新賜鶡弁棄，晝錦歸博庭闈歡。", "鄉閭相賀寶坊又一瑞，益使天下欽湘山。"]'),
('48e0178d-b2b4-44ea-b814-18f8a6637136','重慶閫治十詠 華明堂','李曾伯','宋','宋诗','song-poetry','','[]','要識披圖際，還同枉駕時。',24,'全唐诗/poet.song.214000.json','["要識披圖際，還同枉駕時。", "未應成否論，漢德有興衰。"]'),
('fdd98656-d9d6-49e5-8056-f712358273d3','重慶閫治十詠 尊安堂','李曾伯','宋','宋诗','song-poetry','','[]','堯舜君民學，吾儒共講磨。',24,'全唐诗/poet.song.214000.json','["堯舜君民學，吾儒共講磨。", "一毫如有愧，其若此堂何。"]'),
('24321477-33d9-459d-b763-3ded7c996752','重慶閫治十詠 一廉堂','李曾伯','宋','宋诗','song-poetry','','[]','九重懷井絡，一字侈奎章。',24,'全唐诗/poet.song.214000.json','["九重懷井絡，一字侈奎章。", "來者思冰檗，其毋頃刻忘。"]'),
('72756d24-e7dd-428e-8fb1-9b72d76ad050','重慶閫治十詠 集思堂','李曾伯','宋','宋诗','song-poetry','','[]','先以一誠格，斯能衆正招。',24,'全唐诗/poet.song.214000.json','["先以一誠格，斯能衆正招。", "要來堂下蔑，勿狥帳中超。"]'),
('f8cb6e91-2dd2-4a79-9a2b-fd48ab26e167','重慶閫治十詠 生意堂','李曾伯','宋','宋诗','song-poetry','','[]','碩果食難盡，其機運不停。',24,'全唐诗/poet.song.214000.json','["碩果食難盡，其機運不停。", "岷峨幾霜雪，依舊草青青。"]'),
('c6c61c93-07d2-40c7-81ff-aeaa3db3a319','重慶閫治十詠 龍虎屏','李曾伯','宋','宋诗','song-poetry','','[]','不逐風雲去，盍求山澤安。',24,'全唐诗/poet.song.214000.json','["不逐風雲去，盍求山澤安。", "祗憐當筆者，空作畫屏看。"]'),
('fca35fea-24cf-43d7-9919-3fc10a61561f','重慶閫治十詠 友石','李曾伯','宋','宋诗','song-poetry','','[]','卓爾有所立，儼然即之溫。',24,'全唐诗/poet.song.214000.json','["卓爾有所立，儼然即之溫。", "他疑攻玉異，交誼斷金存。"]'),
('21787bcb-e567-4166-a244-3e9c6f0c81ca','重慶閫治十詠 吟嘯','李曾伯','宋','宋诗','song-poetry','','[]','坐却并州騎，行思楚澤漁。',24,'全唐诗/poet.song.214000.json','["坐却并州騎，行思楚澤漁。", "斯亭著斯客，斯意竟何如。"]'),
('a4292c3f-ae66-48ff-962a-6c966118cac6','重慶閫治十詠 橫舟','李曾伯','宋','宋诗','song-poetry','','[]','不早浮槎去，焉能罔水行。',24,'全唐诗/poet.song.214000.json','["不早浮槎去，焉能罔水行。", "叩舷誰共語，載不盡高情。"]'),
('e00afd52-afb8-47aa-b9c4-ca8ba081af90','重慶閫治十詠 六角亭','李曾伯','宋','宋诗','song-poetry','','[]','四維風折勢，一片雪同規。',24,'全唐诗/poet.song.214000.json','["四維風折勢，一片雪同規。", "花竹叢間著，開樽瀹茗宜。"]'),
('542968e8-8b55-4e9a-9a4f-efa4a2052c05','枕上偶成','李曾伯','宋','宋诗','song-poetry','','[]','官轍驅馳遍四郊，老來於此尚投膠。',64,'全唐诗/poet.song.214000.json','["官轍驅馳遍四郊，老來於此尚投膠。", "綢繆先事心爲碎，展轉中宵睫不交。", "貪鼠驅無容出穴，驚烏疑恐弗安巢。", "燈殘衾薄新寒力，聽徹更籌五五敲。"]'),
('abd10647-ddc5-4690-b06a-77ce95af55cf','思歸偶成  其一','李曾伯','宋','宋诗','song-poetry','','[]','春來便擬問歸津，轉眼江流若許深。',64,'全唐诗/poet.song.214000.json','["春來便擬問歸津，轉眼江流若許深。", "六十歲翁窮塞客，八千里路故鄉心。", "鵑啼月樹添征思，鵲語風簷悞好音。", "只有雲山遮不斷，夢隨栩蝶過家林。"]'),
('8c0bea2b-77f7-4864-b18a-736b166e5682','思歸偶成  其二','李曾伯','宋','宋诗','song-poetry','','[]','杜鵑一自聽天津，南北紛紛患轉深。',64,'全唐诗/poet.song.214000.json','["杜鵑一自聽天津，南北紛紛患轉深。", "備謹徹桑征戍事，憂形恤緯老臣心。", "驚聞邊信多蠻語，喜動鄉情带楚音。", "若得君王放歸去，便陪蓮社訪東林。"]'),
('47fa7892-219e-499e-ac17-61f06af6e77d','題宜興庵壁  其一','李曾伯','宋','宋诗','song-poetry','','[]','禪榻一覺睡，冬宵五更長。',24,'全唐诗/poet.song.214000.json','["禪榻一覺睡，冬宵五更長。", "窗遞清風入，枕邊松柏香。"]'),
('2ef13002-4877-47a4-ba8f-856399505f11','題宜興庵壁  其二','李曾伯','宋','宋诗','song-poetry','','[]','秋盡菊都荒，蜂猶採蜜忙。',24,'全唐诗/poet.song.214000.json','["秋盡菊都荒，蜂猶採蜜忙。", "何如龜縮殻，此際已深藏。"]'),
('a6ea4f2d-caea-4890-bb4c-c97b7d0dfe7b','題宜興庵壁  其三','李曾伯','宋','宋诗','song-poetry','','[]','拂石坐小橋，臨流俯清泚。',24,'全唐诗/poet.song.214000.json','["拂石坐小橋，臨流俯清泚。", "松聲與禽聲，可以醒吾耳。"]'),
('b8722cb0-6919-4e15-a27f-ea6914d97399','自湘赴廣道間雜詠 永州曉行','李曾伯','宋','宋诗','song-poetry','','[]','推枕月微明，登車纔五更。',24,'全唐诗/poet.song.214000.json','["推枕月微明，登車纔五更。", "啼破千山暝，枝禽三兩聲。"]'),
('77341a81-75b1-4c5a-9b6d-e2ad47f803c1','自湘赴廣道間雜詠 李花','李曾伯','宋','宋诗','song-poetry','','[]','昨夜孤村宿，春深人寂寥。',24,'全唐诗/poet.song.214000.json','["昨夜孤村宿，春深人寂寥。", "庭前一株李，爲我縞中宵。"]'),
('84faa03d-ded6-499c-a766-f30537fee698','自湘赴廣道間雜詠 飛燕','李曾伯','宋','宋诗','song-poetry','','[]','瞥見誰家燕，纔驚社日臨。',24,'全唐诗/poet.song.214000.json','["瞥見誰家燕，纔驚社日臨。", "洛花移種否，喚起故園心。"]'),
('274d0db5-96b7-4c6a-b3a5-3b4226d7f6c4','自湘赴廣道間雜詠 蘭花','李曾伯','宋','宋诗','song-poetry','','[]','行盡離騷國，春深未見蘭。',24,'全唐诗/poet.song.214000.json','["行盡離騷國，春深未見蘭。", "容非隠君子，甘老蕨薇間。"]'),
('f1357d62-8b13-4203-95ca-c478fa8b1385','自湘赴廣道間雜詠 山樊','李曾伯','宋','宋诗','song-poetry','','[]','不見花開處，香浮七里村。',24,'全唐诗/poet.song.214000.json','["不見花開處，香浮七里村。", "試從風外覓，端是有山樊。"]'),
('c204d9af-2ca8-4f57-9749-e81ab5f342ef','自湘赴廣道間雜詠 古木','李曾伯','宋','宋诗','song-poetry','','[]','古木列官道，春風老幹柯。',24,'全唐诗/poet.song.214000.json','["古木列官道，春風老幹柯。", "炎涼知幾變，來往閲人多。"]'),
('40260162-25eb-40a7-ad8e-4582644b382a','自湘赴廣道間雜詠 湘竹','李曾伯','宋','宋诗','song-poetry','','[]','紋竹起嬪虞，因懷二女居。',24,'全唐诗/poet.song.214000.json','["紋竹起嬪虞，因懷二女居。", "君淚夫人淚，思歟抑怨歟。"]'),
('aa137411-9eec-4354-8cc0-ff009866a345','自湘赴廣道間雜詠 蟠松','李曾伯','宋','宋诗','song-poetry','','[]','紅紫競芳叢，中蟠一古松。',24,'全唐诗/poet.song.214000.json','["紅紫競芳叢，中蟠一古松。", "春風自來去，吹不動蒼龍。"]'),
('e3044896-981b-45d4-93d8-b4a0f144eb35','自湘赴廣道間雜詠 桃李','李曾伯','宋','宋诗','song-poetry','','[]','仙李明炫夜，夭桃艷當春。',24,'全唐诗/poet.song.214000.json','["仙李明炫夜，夭桃艷當春。", "便將花作主，聘與玉爲人。"]'),
('90e64257-8def-4c99-998a-b3f20d0071ba','全州道間  其一','李曾伯','宋','宋诗','song-poetry','','[]','竹裏幾椽茅屋，門前一樹桃花。',28,'全唐诗/poet.song.214000.json','["竹裏幾椽茅屋，門前一樹桃花。", "布袖蒿簪笑語，鷄豚社酒山家。"]'),
('1c794334-4f0c-4e45-af95-31d29f3ec38c','全州道間  其二','李曾伯','宋','宋诗','song-poetry','','[]','巷陌高題儀鳳，橋梁橫卧長虹。',28,'全唐诗/poet.song.214000.json','["巷陌高題儀鳳，橋梁橫卧長虹。", "十里江山福地，滿城桃李春風。"]'),
('f3321a43-f99f-4112-9528-6dd714084e62','全州道間  其三','李曾伯','宋','宋诗','song-poetry','','[]','林塢禽鳴高樹，溪橋人立危欄。',28,'全唐诗/poet.song.214000.json','["林塢禽鳴高樹，溪橋人立危欄。", "芳草鋪平綠野，白雲界破青山。"]'),
('85c70308-f3cf-46c7-ad8b-f91c4ee76ac3','過黄州和共山高寒韻','李曾伯','宋','宋诗','song-poetry','','[]','千古江山一覽間，老瞞於此膽曾寒。',32,'全唐诗/poet.song.214000.json','["千古江山一覽間，老瞞於此膽曾寒。", "凭高要起乘風志，肯把閑情作鴨欄。"]'),
('e3747dfb-5bd9-41df-8a8c-54f925aafd2d','登壽沙樓和抑齋韻  其一','李曾伯','宋','宋诗','song-poetry','','[]','黄葉滿林霜尚輕，蓼花披岸水猶生。',32,'全唐诗/poet.song.214000.json','["黄葉滿林霜尚輕，蓼花披岸水猶生。", "坐邀一段瀟湘勝，元出鈞陶手作成。"]'),
('28104299-4915-4c25-9cdf-d06c54617e8e','登壽沙樓和抑齋韻  其二','李曾伯','宋','宋诗','song-poetry','','[]','白鷺洲邊多古寺，翠微陰裏盡人烟。',32,'全唐诗/poet.song.214000.json','["白鷺洲邊多古寺，翠微陰裏盡人烟。", "當時曾對掀髯笑，今問老龍何處眠。"]'),
('9d5a4472-2300-4e6d-b6cb-0c47cf8bf1b2','登壽沙樓和抑齋韻  其三','李曾伯','宋','宋诗','song-poetry','','[]','江湖已老猶爲吏，心境俱清即是仙。',32,'全唐诗/poet.song.214000.json','["江湖已老猶爲吏，心境俱清即是仙。", "聊挹層巒薦湘菊，一時人在小壺天。"]'),
('be2b2d44-f15a-467c-9cfb-be34e41a432e','雪夜不寐偶成  其一','李曾伯','宋','宋诗','song-poetry','','[]','底事陽和尚未回，書雲已久未逢梅。',32,'全唐诗/poet.song.214000.json','["底事陽和尚未回，書雲已久未逢梅。", "忽然風遞清香至，花在誰家園裏開。"]'),
('2a1c8eb0-cbd2-4fa4-b1c4-afbeabaf00a1','雪夜不寐偶成  其二','李曾伯','宋','宋诗','song-poetry','','[]','窗外風聲又雪聲，初更展轉到三更。',32,'全唐诗/poet.song.214000.json','["窗外風聲又雪聲，初更展轉到三更。", "枕邊自作推敲態，吟得詩成夢亦成。"]'),
('71ca035b-917a-4b5b-8573-ad80d511386a','洪雲巖有和謝之  其一','李曾伯','宋','宋诗','song-poetry','','[]','春近衡峰雁又回，老懷休憶故山梅。',32,'全唐诗/poet.song.214000.json','["春近衡峰雁又回，老懷休憶故山梅。", "花期自是江南早，早晚湘南也解開。"]'),
('83a1cb96-31fe-4511-8941-fa38ef867b6d','洪雲巖有和謝之  其二','李曾伯','宋','宋诗','song-poetry','','[]','聽徹虛簷䔩䔩聲，鐵衣冰骨記身更。',32,'全唐诗/poet.song.214000.json','["聽徹虛簷䔩䔩聲，鐵衣冰骨記身更。", "如今休憶鵝池路，縱竭龍鍾做不成。"]');
